import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting, high resolution.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

export const speakWord = (word: string, lang: string = 'en-US') => {
  const utterance = new SpeechSynthesisUtterance(word);
  utterance.lang = lang;
  utterance.rate = 0.8; // Slightly slower for children
  window.speechSynthesis.speak(utterance);
};

import { WordList, Word } from './types';

const STORAGE_KEY = 'echofy_data';

export const saveLists = (lists: WordList[]) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(lists));
};

export const loadLists = (): WordList[] => {
  const data = localStorage.getItem(STORAGE_KEY);
  return data ? JSON.parse(data) : [];
};

export const extractWords = (text: string): Word[] => {
  // Regex to extract words, ignoring numbers and symbols
  const matches = text.match(/[a-zA-ZáéíóúÁÉÍÓÚñÑ]+/g) || [];
  return matches.map(w => ({
    original: w.toLowerCase(),
    id: Math.random().toString(36).substr(2, 9),
    errors: 0,
    completed: false
  }));
};

