import React, { useState, useEffect, useMemo } from 'react';
import { WordList, Word } from '../types';
import { speakWord } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  const initWord = () => {
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    // Aleatorizar letras asegurando que no formen la palabra original
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    while(shuffled.map(s => s.char).join('') === currentWord.original) {
      shuffled = [...chars].sort(() => Math.random() - 0.5);
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setShowRevelation(false);
    setIsTransitioning(false);

    // Auto-pronunciar al iniciar
    setTimeout(() => speakWord(currentWord.original), 500);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = (letterObj: {char: string, id: string}, index: number) => {
    if (showRevelation) return;

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      // Feedback auditivo (fonema)
      speakWord(letterObj.char);

      // Verificar si completó
      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = (constructed: string) => {
    const isCorrect = constructed === currentWord.original;

    if (!isCorrect) {
      // Registrar error silencioso
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        listToUpdate.words[currentIndex].errors += 1;
        saveLists(allLists);
      }
    }

    setTimeout(() => {
      setShowRevelation(true);
      speakWord(currentWord.original);
    }, 300);
  };

  const nextWord = () => {
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit(); // Fin de la lista
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col items-center p-6 select-none transition-all duration-700 ${isTransitioning ? 'opacity-0 -translate-y-20' : 'opacity-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      {/* Overlay de Fantasía */}
      <div className="absolute inset-0 bg-white/20 backdrop-blur-md pointer-events-none"></div>

      {/* 1. Logo ECHOFY */}
      <div className="relative z-10 mt-4 mb-2 opacity-30">
        <h1 className="text-2xl font-elegant tracking-[0.2em] font-light text-slate-800">ECHOFY</h1>
      </div>

      {/* 2. La Bocina */}
      <button 
        onClick={() => speakWord(currentWord.original)}
        className="relative z-10 w-24 h-24 bg-white/40 rounded-full flex items-center justify-center shadow-lg hover:scale-105 active:scale-95 transition-transform mb-8"
      >
        <span className="text-4xl">🔊</span>
      </button>

      {/* 3. Espacio de Eco (Revelación) */}
      <div className="relative z-10 h-32 flex flex-col items-center justify-center mb-6">
        {showRevelation && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 text-center">
            <h2 className="text-4xl font-elegant font-semibold text-slate-800 mb-2 uppercase tracking-widest">
              {currentWord.original}
            </h2>
            <p className="text-xl italic text-slate-600 font-elegant">
              "{getMeaning(currentWord.original)}"
            </p>
          </div>
        )}
      </div>

      {/* 4. Cuadros Vacíos (Construcción) */}
      <div className="relative z-10 flex gap-3 mb-12 flex-wrap justify-center">
        {slots.map((char, i) => (
          <div 
            key={i}
            onClick={() => handleSlotClick(i)}
            className={`w-14 h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all
              ${char ? 'bg-white border-slate-300 shadow-md text-slate-700' : 'bg-slate-200/30 border-dashed border-slate-400/50'}
              ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-12' : 'animate-in fade-in'}
            `}
          >
            {char}
          </div>
        ))}
      </div>

      {/* 5. Letras (Selección) */}
      <div className="relative z-10 flex gap-4 flex-wrap justify-center max-w-lg mt-auto mb-10">
        {availableLetters.map((letterObj, i) => (
          <button
            key={letterObj.id}
            onClick={() => handleLetterClick(letterObj, i)}
            className={`w-16 h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 hover:bg-slate-50 active:scale-90 transition-all
              ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-20' : 'animate-in fade-in'}
            `}
            style={{ animationDelay: `${i * 0.05}s` }}
          >
            {letterObj.char}
          </button>
        ))}
      </div>

      {/* Botón Siguiente */}
      {showRevelation && (
        <button 
          onClick={nextWord}
          className="fixed bottom-10 right-10 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-bounce hover:bg-emerald-600 transition-colors"
        >
          <span className="text-3xl">➡️</span>
        </button>
      )}

      {/* Botón Salir */}
      <button 
        onClick={onExit}
        className="fixed top-6 right-6 p-2 opacity-50 hover:opacity-100"
      >
        <span className="text-2xl">✕</span>
      </button>
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect } from 'react';
import { WordList } from '../types';
import { loadLists, saveLists, extractWords } from '../store';
import { generateBackgroundImage } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
}

const ParentDashboard: React.FC<Props> = ({ onStartGame }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);

  useEffect(() => {
    setLists(loadLists());
  }, []);

  const handleCreateList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    const bg = theme ? await generateBackgroundImage(theme) : undefined;

    const newList: WordList = {
      id: Math.random().toString(36).substr(2, 9),
      name: newListName,
      words: extractWords(inputText),
      backgroundImage: bg || undefined,
      lastPlayed: Date.now(),
      settings: {
        rainEnabled: true
      }
    };

    const updated = [...lists, newList];
    setLists(updated);
    saveLists(updated);

    setNewListName('');
    setInputText('');
    setTheme('');
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string) => {
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string) => {
    if (confirm('¿Borrar esta lista?')) {
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-8 animate-in fade-in duration-500 pb-20">
      <header className="flex flex-col items-center mb-12">
        <h1 className="text-5xl font-elegant tracking-widest font-light text-slate-800 mb-2">ECHOFY</h1>
        <p className="text-slate-500 italic">Panel de Control para Padres</p>
      </header>

      {isAdding ? (
        <div className="bg-white p-8 rounded-3xl shadow-xl border border-slate-100 mb-8 space-y-6">
          <h2 className="text-2xl font-elegant text-slate-700">Nueva Lista</h2>
          <input 
            className="w-full p-4 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-300"
            placeholder="Nombre de la lista (ej. Animales)"
            value={newListName}
            onChange={e => setNewListName(e.target.value)}
          />
          <textarea 
            className="w-full p-4 h-32 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-300"
            placeholder="Pega tus palabras aquí (una por línea, o texto libre)"
            value={inputText}
            onChange={e => setInputText(e.target.value)}
          />
          <input 
            className="w-full p-4 rounded-xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-300"
            placeholder="Tema visual (ej. Espacio, Selva, Sueños)"
            value={theme}
            onChange={e => setTheme(e.target.value)}
          />
          <div className="flex gap-4">
            <button 
              disabled={isLoadingImage}
              onClick={handleCreateList}
              className="flex-1 bg-slate-800 text-white p-4 rounded-xl font-semibold hover:bg-slate-700 disabled:opacity-50"
            >
              {isLoadingImage ? 'Creando magia...' : 'Guardar Lista'}
            </button>
            <button 
              onClick={() => setIsAdding(false)}
              className="px-6 py-4 rounded-xl border border-slate-200 text-slate-500"
            >
              Cancelar
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsAdding(true)}
          className="w-full p-6 border-2 border-dashed border-slate-300 rounded-3xl text-slate-400 hover:border-slate-400 hover:text-slate-500 transition-all mb-8 flex items-center justify-center gap-2"
        >
          <span className="text-2xl">+</span> Crear nueva lista de palabras
        </button>
      )}

      <div className="grid gap-6">
        {lists.map(list => (
          <div key={list.id} className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center justify-between group">
            <div className="flex items-center gap-4">
              <div className="w-12 h-12 rounded-2xl bg-slate-100 flex items-center justify-center text-xl">
                📚
              </div>
              <div>
                <h3 className="text-xl font-semibold text-slate-800">{list.name}</h3>
                <p className="text-sm text-slate-400">{list.words.length} palabras • {new Date(list.lastPlayed || 0).toLocaleDateString()}</p>
              </div>
            </div>

            <div className="flex items-center gap-4">
              <button 
                onClick={() => toggleRain(list.id)}
                className={`p-2 rounded-lg text-xs font-bold transition-colors ${list.settings.rainEnabled ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400'}`}
              >
                {list.settings.rainEnabled ? 'LLUVIA ON' : 'CALMA ON'}
              </button>
              <button 
                onClick={() => onStartGame(list.id)}
                className="bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold hover:bg-emerald-600 shadow-md shadow-emerald-100"
              >
                Jugar
              </button>
              <button 
                onClick={() => deleteList(list.id)}
                className="p-2 text-slate-300 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"
              >
                ✕
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ParentDashboard;

import React, { useState } from 'react';
import ParentDashboard from './components/ParentDashboard';
import GameScreen from './components/GameScreen';
import { loadLists } from './store';
import { WordList } from './types';

const App: React.FC = () => {
  const [role, setRole] = useState<'parent' | 'child'>('parent');
  const [activeListId, setActiveListId] = useState<string | null>(null);

  const activeList = activeListId ? loadLists().find(l => l.id === activeListId) : null;

  if (role === 'child' && activeList) {
    return <GameScreen list={activeList} onExit={() => {
      setRole('parent');
      setActiveListId(null);
    }} />;
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans">
      <ParentDashboard 
        onStartGame={(id) => {
          setActiveListId(id);
          setRole('child');
        }} 
      />

      {/* Botón flotante para cambiar de rol rápidamente (debugging/demo) */}
      <div className="fixed bottom-6 left-1/2 -translate-x-1/2 z-50">
        <div className="bg-white/80 backdrop-blur-md px-4 py-2 rounded-full shadow-lg border border-slate-200 flex gap-4 text-xs font-bold text-slate-400">
          <span>PADRE</span>
          <div className="w-10 h-5 bg-slate-200 rounded-full relative">
            <div className={`absolute top-1 w-3 h-3 rounded-full bg-slate-500 transition-all ${role === 'child' ? 'left-6' : 'left-1'}`} />
          </div>
          <span>NIÑO</span>
        </div>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { WordList, Word } from '../types';
import { speakWord } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  const initWord = () => {
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    while(shuffled.map(s => s.char).join('') === currentWord.original && chars.length > 1) {
      shuffled = [...chars].sort(() => Math.random() - 0.5);
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setShowRevelation(false);
    setIsTransitioning(false);

    // Auto-pronunciar al iniciar (con un pequeño delay para que cargue la vista)
    setTimeout(() => speakWord(currentWord.original), 800);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = (letterObj: {char: string, id: string}, index: number) => {
    if (showRevelation) return;

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      speakWord(letterObj.char);

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = (constructed: string) => {
    const isCorrect = constructed === currentWord.original;

    if (!isCorrect) {
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
    }

    setTimeout(() => {
      setShowRevelation(true);
      speakWord(currentWord.original);
    }, 400);
  };

  const nextWord = () => {
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col items-center select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 -translate-y-full' : 'opacity-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      {/* Overlay Fantasía - Mobile Friendly */}
      <div className="absolute inset-0 bg-white/10 backdrop-blur-2xl pointer-events-none"></div>
      <div className="absolute inset-0 bg-gradient-to-b from-white/30 to-transparent pointer-events-none"></div>

      {/* 1. Logo ECHOFY (Sutil) */}
      <div className="relative z-10 pt-10 pb-2 opacity-25">
        <h1 className="text-xl font-elegant tracking-[0.4em] font-light text-slate-900">ECHOFY</h1>
      </div>

      {/* 2. La Bocina (Debajo del Logo) */}
      <div className="relative z-10 py-4">
        <button 
          onClick={() => speakWord(currentWord.original)}
          className="w-20 h-20 bg-white/50 backdrop-blur-md rounded-full flex items-center justify-center shadow-[0_8px_30px_rgb(0,0,0,0.04)] active:scale-90 transition-transform"
          aria-label="Escuchar palabra"
        >
          <span className="text-4xl">🔊</span>
        </button>
      </div>

      {/* 3. Espacio de Revelación (Eco) */}
      <div className="relative z-10 w-full h-36 flex flex-col items-center justify-center px-6">
        {showRevelation ? (
          <div className="animate-in fade-in zoom-in-95 duration-1000 text-center">
            <h2 className="text-3xl font-elegant font-bold text-slate-800 mb-1 uppercase tracking-[0.2em]">
              {currentWord.original}
            </h2>
            <div className="bg-white/60 backdrop-blur-sm px-4 py-2 rounded-2xl">
              <p className="text-lg italic text-slate-600 font-elegant">
                {getMeaning(currentWord.original)}
              </p>
            </div>
          </div>
        ) : (
          <div className="w-1 h-1 bg-transparent"></div>
        )}
      </div>

      {/* 4. Cuadros Vacíos (Construcción) */}
      <div className="relative z-10 flex gap-2 mb-8 flex-wrap justify-center px-4 max-w-full">
        {slots.map((char, i) => (
          <div 
            key={i}
            onClick={() => handleSlotClick(i)}
            className={`w-12 h-14 rounded-2xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-500
              ${char ? 'bg-white border-slate-200 shadow-xl text-slate-800 scale-105' : 'bg-slate-900/5 border-dashed border-slate-400/30'}
              ${list.settings.rainEnabled && !char ? 'animate-in slide-in-from-top-8' : 'animate-in fade-in'}
            `}
          >
            {char}
          </div>
        ))}
      </div>

      {/* 5. Letras (Selección) - Zona de pulgares */}
      <div className="relative z-10 w-full px-6 flex gap-3 flex-wrap justify-center items-end flex-grow pb-16">
        {availableLetters.map((letterObj, i) => (
          <button
            key={letterObj.id}
            onClick={() => handleLetterClick(letterObj, i)}
            className={`w-16 h-16 bg-white/90 backdrop-blur-md rounded-2xl shadow-[0_10px_20px_rgba(0,0,0,0.05)] flex items-center justify-center text-3xl font-bold text-slate-800 active:scale-95 active:bg-slate-100 transition-all
              ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-16' : 'animate-in fade-in'}
