            style={{ 
              animationDelay: list.settings.rainEnabled ? `${i * 0.08}s` : '0s',
              minWidth: '64px', minHeight: '64px' // Touch target WCAG
            }}
          >
            {letterObj.char}
          </button>
        ))}
      </div>

      {/* Botón Siguiente (Flotante lateral) */}
      {showRevelation && (
