import React, { useState, useEffect, useMemo } from 'react';
import { WordList, Word } from '../types';
import { speakWord } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  const initWord = () => {
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    while(shuffled.map(s => s.char).join('') === currentWord.original && chars.length > 1) {
      shuffled = [...chars].sort(() => Math.random() - 0.5);
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setShowRevelation(false);
    setIsTransitioning(false);
    setIsCorrect(null);

    setTimeout(() => speakWord(currentWord.original), 800);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = (letterObj: {char: string, id: string}, index: number) => {
    if (showRevelation) return;

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      speakWord(letterObj.char);

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = (constructed: string) => {
    const checkResult = constructed === currentWord.original.toLowerCase();
    setIsCorrect(checkResult);

    if (!checkResult) {
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
    }

    setTimeout(() => {
      setShowRevelation(true);
      speakWord(currentWord.original);
    }, 400);
  };

  const nextWord = () => {
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col items-center select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 -translate-y-full' : 'opacity-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      <div className="absolute inset-0 bg-white/10 backdrop-blur-3xl pointer-events-none"></div>
      <div className="absolute inset-0 bg-gradient-to-b from-white/40 via-white/10 to-transparent pointer-events-none"></div>

      <div className="relative z-10 pt-12 pb-2 opacity-30">
        <h1 className="text-xl font-elegant tracking-[0.4em] font-light text-slate-900">ECHOFY</h1>
      </div>

      <div className="relative z-10 py-4">
        <button 
          onClick={() => speakWord(currentWord.original)}
          className="w-24 h-24 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl shadow-slate-200/50 active:scale-90 transition-transform"
        >
          <span className="text-4xl">🔊</span>
        </button>
      </div>

      <div className="relative z-10 w-full h-40 flex flex-col items-center justify-center px-8">
        {showRevelation ? (
          <div className="animate-in fade-in zoom-in-95 duration-1000 text-center">
            {/* Siempre muestra la palabra original correctamente escrita en inglés */}
            <h2 className="text-4xl font-elegant font-bold text-slate-800 mb-2 uppercase tracking-[0.2em]">
              {currentWord.original}
            </h2>
            {/* Significado en español */}
            <div className="bg-white/80 backdrop-blur-lg px-6 py-2 rounded-[2rem] shadow-sm border border-white/50">
              <p className="text-xl italic text-slate-600 font-elegant font-medium">
                {getMeaning(currentWord.original)}
              </p>
            </div>
          </div>
        ) : (
          <div className="opacity-0">—</div>
        )}
      </div>

      <div className="relative z-10 flex gap-2 mb-10 flex-wrap justify-center px-4 max-w-full">
        {slots.map((char, i) => (
          <div 
            key={i}
            onClick={() => handleSlotClick(i)}
            className={`w-14 h-16 rounded-2xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-500
              ${char ? (showRevelation && !isCorrect ? 'bg-rose-50 border-rose-200 text-rose-500 scale-105 shadow-rose-100/50 shadow-lg' : 'bg-white border-slate-100 shadow-xl text-slate-800 scale-105') : 'bg-slate-900/5 border-dashed border-slate-300/40'}
              ${list.settings.rainEnabled && !char ? 'animate-in slide-in-from-top-12' : 'animate-in fade-in'}
            `}
          >
            {char}
          </div>
        ))}
      </div>

      <div className="relative z-10 w-full px-6 flex gap-3 flex-wrap justify-center items-end flex-grow pb-20">
        {!showRevelation && availableLetters.map((letterObj, i) => (
          <button
            key={letterObj.id}
            onClick={() => handleLetterClick(letterObj, i)}
            className={`w-16 h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 active:scale-95 active:bg-slate-50 transition-all
              ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-20' : 'animate-in fade-in'}
            `}
            style={{ 
              animationDelay: list.settings.rainEnabled ? `${i * 0.08}s` : '0s',
              minWidth: '64px', minHeight: '64px'
            }}
          >
            {letterObj.char}
          </button>
        ))}
      </div>

      {showRevelation && (
        <button 
          onClick={nextWord}
          className="fixed bottom-12 right-8 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200 flex items-center justify-center animate-in slide-in-from-right-10 duration-500 active:scale-90"
          style={{ width: '76px', height: '76px' }}
        >
          <span className="text-3xl">➡️</span>
        </button>
      )}

      <button 
        onClick={onExit}
        className="fixed top-14 right-6 w-10 h-10 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-400 active:bg-white/40"
      >
        <span className="text-xl">✕</span>
      </button>
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect } from 'react';
import { WordList } from '../types';
import { loadLists, saveLists, extractWords } from '../store';
import { generateBackgroundImage } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
}

const ParentDashboard: React.FC<Props> = ({ onStartGame }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);

  useEffect(() => {
    setLists(loadLists());
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    // Solo regenerar imagen si hay un tema nuevo
    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      const updated = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText),
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updated);
      saveLists(updated);
    } else {
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setIsAdding(false);
    setEditingListId(null);
    setIsLoadingImage(false);
  };

  const startEditing = (list: WordList, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme(''); // El tema se usa para regenerar el fondo
    setIsAdding(true);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-6 animate-in fade-in duration-700 pb-32">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-2"></div>
        <p className="text-slate-400 text-sm font-elegant uppercase tracking-wider">Gestión de Eco</p>
      </header>

      {isAdding ? (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4">
          <h2 className="text-xl font-elegant font-semibold text-slate-700 px-2">
            {editingListId ? 'Editar lista' : 'Crear nueva lista'}
          </h2>
          <input 
            className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
            placeholder="Título (ej. Los Colores)"
            value={newListName}
            onChange={e => setNewListName(e.target.value)}
          />
          <textarea 
            className="w-full p-4 h-28 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
            placeholder="Palabras a aprender..."
            value={inputText}
            onChange={e => setInputText(e.target.value)}
          />
          <input 
            className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
            placeholder={editingListId ? "Tema nuevo para el fondo (opcional)" : "Tema del fondo (ej. Selva)"}
            value={theme}
            onChange={e => setTheme(e.target.value)}
          />
          <div className="flex gap-3 pt-2">
            <button 
              disabled={isLoadingImage}
              onClick={handleSaveList}
              className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold shadow-lg shadow-slate-200 disabled:opacity-50 active:scale-95 transition-transform"
            >
              {isLoadingImage ? 'Procesando...' : (editingListId ? 'Guardar Cambios' : 'Crear')}
            </button>
            <button 
              onClick={resetForm}
              className="px-6 p-4 rounded-2xl bg-slate-100 text-slate-500 font-bold active:scale-95"
            >
              ×
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsAdding(true)}
          className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 hover:text-slate-500 transition-all mb-8 flex items-center justify-center gap-2 bg-white/50 active:scale-98"
        >
          <span className="text-2xl font-light">+</span> Nueva Lista
        </button>
      )}

      <div className="space-y-4">
        {lists.length === 0 && !isAdding && (
          <div className="text-center py-20 opacity-30">
            <span className="text-5xl block mb-4">📖</span>
            <p className="font-elegant">No hay listas aún</p>
          </div>
        )}
        {lists.map(list => (
          <div 
            key={list.id} 
            onClick={() => onStartGame(list.id)}
            className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer group"
          >
            <div className="flex items-center gap-4">
              <div className="w-14 h-14 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl shadow-inner overflow-hidden">
                {list.backgroundImage ? (
                  <img src={list.backgroundImage} className="w-full h-full object-cover" alt="" />
                ) : (
                  '📝'
                )}
              </div>
              <div>
                <h3 className="text-lg font-bold text-slate-800 leading-tight">{list.name}</h3>
                <p className="text-xs text-slate-400 font-elegant uppercase tracking-tighter">
                  {list.words.length} palabras
                </p>
              </div>
            </div>

            <div className="flex items-center gap-1">
              <button 
                onClick={(e) => startEditing(list, e)}
                className="w-9 h-9 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center hover:bg-slate-100 active:scale-90 transition-all"
                title="Editar"
              >
                <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.828 2.828 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5L17 3z"></path></svg>
              </button>
              <button 
                onClick={(e) => toggleRain(list.id, e)}
                className={`w-9 h-9 rounded-full flex items-center justify-center transition-all active:scale-90 ${list.settings.rainEnabled ? 'bg-blue-50 text-blue-500' : 'bg-orange-50 text-orange-400'}`}
                title={list.settings.rainEnabled ? 'Modo Lluvia' : 'Modo Calma'}
              >
                {list.settings.rainEnabled ? '🌧️' : '☁️'}
              </button>
              <button 
                onClick={(e) => deleteList(list.id, e)}
                className="w-9 h-9 rounded-full bg-slate-50 text-slate-300 flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 active:scale-90 transition-all"
                title="Borrar"
              >
                ✕
              </button>
            </div>
          </div>
        ))}
      </div>

      <footer className="mt-12 text-center opacity-20 px-8">
        <p className="text-[10px] font-elegant tracking-widest uppercase">Echofy v2.0 • Aprendizaje Silencioso</p>
      </footer>
    </div>
  );
};

export default ParentDashboard;

