              ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-20' : 'animate-in fade-in'}
            `}
            style={{ 
              animationDelay: list.settings.rainEnabled ? `${i * 0.08}s` : '0s',
              minWidth: '64px', minHeight: '64px'
            }}
          >
            {letterObj.char}
          </button>
        ))}
      </div>

      {showRevelation && (
        <button 
          onClick={nextWord}
          className="fixed bottom-12 right-8 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200 flex items-center justify-center animate-in slide-in-from-right-10 duration-500 active:scale-90"
        >
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}

      <button 
        onClick={onExit}
        className="fixed top-14 right-6 w-10 h-10 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-400 active:bg-white/40 active:scale-90 transition-all"
      >
        <span className="text-xl">✕</span>
      </button>
    </div>
  );
};

