import React, { useState, useEffect, useMemo } from 'react';
import { WordList, Word } from '../types';
import { speakWord } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  const initWord = () => {
    // Generar letras desordenadas
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    // Evitar que aparezca ya resuelta por azar
    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setShowRevelation(false);
    setIsTransitioning(false);
    setIsCorrect(null);

    // Pequeño delay para que el usuario se asiente antes de escuchar
    setTimeout(() => speakWord(currentWord.original), 500);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = (letterObj: {char: string, id: string}, index: number) => {
    if (showRevelation) return;

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      speakWord(letterObj.char);

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      }
    }
  };

  const handleSlotClick = (index: number) => {
    if (showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = (constructed: string) => {
    const checkResult = constructed === currentWord.original.toLowerCase();
    setIsCorrect(checkResult);

    if (!checkResult) {
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
    }

    setTimeout(() => {
      setShowRevelation(true);
      speakWord(currentWord.original);
    }, 400);
  };

  const nextWord = () => {
    // Iniciamos la transición visual de salida
    setIsTransitioning(true);

    // Esperamos a que termine la animación CSS (600ms) antes de cambiar los datos
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      {/* Capas de Fondo y Efectos */}
      <div className="absolute inset-0 bg-white/10 backdrop-blur-3xl pointer-events-none"></div>
      <div className="absolute inset-0 bg-gradient-to-b from-white/30 via-transparent to-white/20 pointer-events-none"></div>

      {/* Botón Salir (Esquina superior derecha segura) */}
      <button 
        onClick={onExit}
        className="fixed top-4 right-4 z-50 w-12 h-12 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-500 shadow-sm active:bg-white/40 active:scale-90 transition-all mt-[env(safe-area-inset-top)]"
      >
        <span className="text-xl font-bold">✕</span>
      </button>

      {/* Contenido Principal: Distribuido verticalmente */}
      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">

        {/* Zona Superior: Audio y Feedback Visual */}
        <div className="flex flex-col items-center justify-center pt-8 w-full">
            <button 
              onClick={() => speakWord(currentWord.original)}
              className="w-20 h-20 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl shadow-slate-200/50 active:scale-90 transition-transform mb-6"
            >
              <span className="text-4xl">🔊</span>
            </button>

            {/* Zona de Revelación (Significado) */}
            <div className="h-24 w-full flex items-center justify-center px-4">
              {showRevelation ? (
                <div className="animate-in fade-in zoom-in-95 duration-700 text-center w-full max-w-sm">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 mb-1 uppercase tracking-[0.1em] drop-shadow-sm">
                    {currentWord.original}
                  </h2>
                  <div className="bg-white/70 backdrop-blur-md px-4 py-2 rounded-2xl shadow-sm border border-white/40 inline-block">
                    <p className="text-lg italic text-slate-700 font-elegant font-medium leading-tight">
                      {getMeaning(currentWord.original)}
                    </p>
                  </div>
                </div>
              ) : (
                <div className="opacity-0">.</div>
              )}
            </div>
        </div>

        {/* Zona Central: Slots de Letras */}
        <div className="flex gap-2 flex-wrap justify-center px-2 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div 
              key={i}
              onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (showRevelation && !isCorrect ? 'bg-rose-50 border-rose-200 text-rose-500' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}
                ${list.settings.rainEnabled && !char ? 'animate-in slide-in-from-top-4' : 'animate-in fade-in'}
              `}
            >
              {char}
            </div>
          ))}
        </div>

        {/* Zona Inferior: Banco de Letras */}
        <div className="w-full px-4 pb-8 sm:pb-12 flex gap-2 sm:gap-3 flex-wrap justify-center items-end min-h-[100px]">
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button
              key={letterObj.id}
              onClick={() => handleLetterClick(letterObj, i)}
              className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center text-3xl font-bold text-slate-800 active:scale-90 active:bg-slate-100 transition-all border-b-4 border-slate-100
                ${list.settings.rainEnabled ? 'animate-in slide-in-from-top-10 fade-in' : 'animate-in zoom-in-50'}
              `}
              style={{ 
                animationDelay: list.settings.rainEnabled ? `${i * 0.05}s` : '0s',
                animationFillMode: 'both'
              }}
            >
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {/* Botón Siguiente (Flotante y Alta Jerarquía) */}
      {showRevelation && (
        <button 
          onClick={(e) => {
            e.stopPropagation(); // Evitar clics fantasmas
            nextWord();
          }}
          className="fixed bottom-8 right-6 z-50 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200/50 flex items-center justify-center animate-in slide-in-from-right-20 zoom-in duration-500 active:scale-90 active:bg-emerald-600 transition-all border-4 border-white/20 mb-[env(safe-area-inset-bottom)]"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}

    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect } from 'react';
import { WordList } from '../types';
import { loadLists, saveLists, extractWords } from '../store';
import { generateBackgroundImage } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');

  // UI State
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  useEffect(() => {
    setLists(loadLists());
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      // MODO EDICIÓN
      const updatedLists = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText), 
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updatedLists);
      saveLists(updatedLists);
    } else {
      // MODO CREACIÓN
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const startEditing = (list: WordList) => {
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme('');
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setEditingListId(null);
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      if (editingListId === id) resetForm();
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  const handleListClick = (list: WordList) => {
    if (role === 'parent') {
      startEditing(list);
    } else {
      onStartGame(list.id);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-6 animate-in fade-in duration-700 pb-48">
      <header className="flex flex-col items-center mb-8 mt-6">
        <h1 className="text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-2"></div>
        <p className="text-slate-400 text-sm font-elegant uppercase tracking-wider">Gestión de Eco</p>
      </header>

      {/* Formulario */}
      {role === 'parent' && (
        isAdding ? (
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4 pb-10">
            <h2 className="text-xl font-elegant font-semibold text-slate-700 px-2 flex justify-between items-center">
              <span>{editingListId ? 'Editar Lista' : 'Crear nueva lista'}</span>
              {editingListId && <span className="text-xs text-slate-400 font-normal uppercase tracking-wider">Modo Edición</span>}
            </h2>
            <input 
              className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder="Título (ej. Los Colores)"
              value={newListName}
              onChange={e => setNewListName(e.target.value)}
            />
            <textarea 
              className="w-full p-4 h-32 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder="Palabras a aprender..."
              value={inputText}
              onChange={e => setInputText(e.target.value)}
            />
            <input 
              className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder={editingListId ? "Nuevo tema para fondo (Opcional)" : "Tema del fondo (ej. Selva)"}
              value={theme}
              onChange={e => setTheme(e.target.value)}
            />
            <div className="flex gap-3 pt-2">
              <button 
                disabled={isLoadingImage}
                onClick={handleSaveList}
                className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold shadow-lg shadow-slate-200 disabled:opacity-50 active:scale-95 transition-transform h-14"
              >
                {isLoadingImage ? 'Procesando...' : (editingListId ? 'Guardar Cambios' : 'Crear')}
              </button>
              <button 
                onClick={resetForm}
                className="px-6 p-4 rounded-2xl bg-slate-100 text-slate-500 font-bold active:scale-95 h-14 w-16 flex items-center justify-center text-xl"
              >
                ×
              </button>
            </div>
          </div>
        ) : (
          <button 
            onClick={() => {
              setEditingListId(null);
              setNewListName('');
              setInputText('');
              setTheme('');
              setIsAdding(true);
            }}
            className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 hover:text-slate-500 transition-all mb-8 flex items-center justify-center gap-2 bg-white/50 active:scale-98"
          >
            <span className="text-2xl font-light">+</span> Nueva Lista
          </button>
        )
      )}

      <div className="space-y-4">
        {lists.length === 0 && !isAdding && (
          <div className="text-center py-20 opacity-30">
            <span className="text-5xl block mb-4">📖</span>
            <p className="font-elegant">No hay listas aún</p>
          </div>
        )}
        {lists.map(list => (
          <div 
            key={list.id} 
            onClick={() => handleListClick(list)}
            className={`bg-white p-4 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer group min-h-[5.5rem]
              ${editingListId === list.id ? 'ring-2 ring-slate-900 shadow-xl scale-[1.02]' : ''}`}
          >
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl shadow-inner overflow-hidden shrink-0">
                {list.backgroundImage ? (
                  <img src={list.backgroundImage} className="w-full h-full object-cover" alt="" />
                ) : (
                  '📝'
                )}
              </div>
              <div>
                <h3 className="text-lg font-bold text-slate-800 leading-tight">{list.name}</h3>
                <p className="text-xs text-slate-400 font-elegant uppercase tracking-tighter">
                  {list.words.length} palabras
                </p>
              </div>
            </div>

            {role === 'parent' && (
              <div className="flex items-center gap-2">
                <button 
                  onClick={(e) => toggleRain(list.id, e)}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-all active:scale-90 shadow-sm border border-slate-50 ${list.settings.rainEnabled ? 'bg-blue-50 text-blue-500' : 'bg-orange-50 text-orange-400'}`}
                  title={list.settings.rainEnabled ? 'Modo Lluvia' : 'Modo Calma'}
                >
                  <span className="text-xl">{list.settings.rainEnabled ? '🌧️' : '☁️'}</span>
                </button>
                <button 
                  onClick={(e) => deleteList(list.id, e)}
                  className="w-12 h-12 rounded-full bg-slate-50 text-slate-300 flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 active:scale-90 transition-all shadow-sm border border-slate-100"
                  title="Borrar"
                >
                  <span className="text-lg font-bold">✕</span>
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      <footer className="mt-12 text-center opacity-20 px-8">
        <p className="text-[10px] font-elegant tracking-widest uppercase">Echofy v2.0</p>
      </footer>
    </div>
  );
};

