export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting. Blurred and fantasy effects.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

// --- VOICE & AUDIO LOGIC ---

let englishVoice: SpeechSynthesisVoice | null = null;
let hasInitializedVoices = false;

// Mapa fonético para simular inglés usando voz en español (Plan de Respaldo)
const PHONETIC_MAP_FALLBACK: Record<string, string> = {
  "a": "ei", "b": "bi", "c": "si", "d": "di", "e": "ii", 
  "f": "ef", "g": "yi", "h": "eich", "i": "ai", "j": "yei",
  "k": "kei", "l": "el", "m": "em", "n": "en", "o": "ou",
  "p": "pi", "q": "kiu", "r": "ar", "s": "es", "t": "ti",
  "u": "iu", "v": "vi", "w": "doboliu", "x": "ex", "y": "uai", "z": "zi"
};

const loadEnglishVoice = () => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;

  const voices = window.speechSynthesis.getVoices();
  if (voices.length > 0) {
    // Prioridad 1: Inglés de EEUU
    // Prioridad 2: Cualquier Inglés
    englishVoice = voices.find(v => v.lang === 'en-US' || v.lang.startsWith('en-US')) || 
                   voices.find(v => v.lang.startsWith('en')) || null;
    hasInitializedVoices = true;
  }
};

// Intentar cargar voces al inicio
if (typeof window !== 'undefined' && window.speechSynthesis) {
  loadEnglishVoice();
  if (window.speechSynthesis.onvoiceschanged !== undefined) {
    window.speechSynthesis.onvoiceschanged = loadEnglishVoice;
  }
}

export const speakWord = (word: string, lang: string = 'en-US', interrupt: boolean = true) => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;

  // Asegurar que intentamos cargar las voces si aún no están listas
  if (!hasInitializedVoices) {
    loadEnglishVoice();
  }

  if (interrupt) {
    window.speechSynthesis.cancel();
  }

  let textToSpeak = word;
  const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);

  const utterance = new SpeechSynthesisUtterance();

  if (englishVoice) {
    // Escenario Ideal: Tenemos voz nativa en inglés
    utterance.voice = englishVoice;
    utterance.lang = englishVoice.lang;
    utterance.text = textToSpeak;
  } else {
    // Escenario Fallback: No hay voz inglés detectada
    if (isSingleLetter) {
      // Si es una letra, usamos el mapa fonético para que la voz en español diga "Ei", "Bi", etc.
      const lowerChar = word.toLowerCase();
      if (PHONETIC_MAP_FALLBACK[lowerChar]) {
        textToSpeak = PHONETIC_MAP_FALLBACK[lowerChar];
        // Forzamos español para que lea la fonética tal cual está escrita (ej. "Ei" suena como A en inglés)
        utterance.lang = 'es-ES'; 
      } else {
         utterance.lang = lang; 
      }
    } else {
      // Palabra completa: Confiamos en que el tag 'en-US' haga su mejor esfuerzo
      utterance.lang = lang;
    }
    utterance.text = textToSpeak;
  }

  // Ajustes de entonación para niños
  utterance.rate = isSingleLetter ? 0.65 : 0.75; // Letras un poco más lentas
  utterance.pitch = 1.1; 

  window.speechSynthesis.speak(utterance);
};

