// --- VOICE & AUDIO LOGIC ---

// Mapa fonético para simular inglés usando voz en español (Solo si falla todo lo demás)
const PHONETIC_MAP_FALLBACK: Record<string, string> = {
  "a": "ei", "b": "bi", "c": "si", "d": "di", "e": "ii", 
  "f": "ef", "g": "yi", "h": "eich", "i": "ai", "j": "yei",
  "k": "kei", "l": "el", "m": "em", "n": "en", "o": "ou",
  "p": "pi", "q": "kiu", "r": "ar", "s": "es", "t": "ti",
  "u": "iu", "v": "vi", "w": "doboliu", "x": "ex", "y": "uai", "z": "zi"
};

export const getEnglishVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const voices = window.speechSynthesis.getVoices();
  // Filtrar voces en inglés
  return voices.filter(v => v.lang.startsWith('en'));
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || 
         name.includes('premium') || 
         name.includes('enhanced') || 
         name.includes('siri') || 
         name.includes('natural');
};

export const speakWord = (word: string, lang: string = 'en-US', interrupt: boolean = true) => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return;

  if (interrupt) {
    window.speechSynthesis.cancel();
  }

  // 1. Cargar Configuración Global
  const settings = loadVoiceSettings();

  // 2. Buscar voces disponibles
  const voices = window.speechSynthesis.getVoices();
  let selectedVoice: SpeechSynthesisVoice | null = null;

  // 3. Determinar voz a usar
  if (settings.voiceURI) {
    // Si el usuario eligió una, intentamos encontrarla
    selectedVoice = voices.find(v => v.voiceURI === settings.voiceURI) || null;
  }

  // Si no hay voz seleccionada (o ya no existe), buscamos la mejor automática en inglés
  if (!selectedVoice) {
    selectedVoice = voices.find(v => v.lang === 'en-US' && isPremiumVoice(v)) || // Google US / Siri
                    voices.find(v => v.lang.startsWith('en') && isPremiumVoice(v)) || // Otras Premium
                    voices.find(v => v.lang === 'en-US') || // Default US
                    voices.find(v => v.lang.startsWith('en')) || null; // Cualquier inglés
  }

  const utterance = new SpeechSynthesisUtterance();
  const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);
  let textToSpeak = word;

  if (selectedVoice) {
    // Escenario Ideal: Tenemos voz nativa en inglés (seleccionada o auto-detectada)
    utterance.voice = selectedVoice;
    utterance.lang = selectedVoice.lang;

    // Aplicar configuración personalizada (Rate y Pitch)
    // Nota: Las letras sueltas siempre van un poco más lento por claridad
    const baseRate = settings.rate;
    utterance.rate = isSingleLetter ? Math.max(0.5, baseRate - 0.2) : baseRate; 
    utterance.pitch = settings.pitch;

  } else {
    // Escenario Catástrofe: No hay NINGUNA voz en inglés en el sistema
    // Usamos el fallback fonético con la voz por defecto del sistema (probablemente español)
    if (isSingleLetter) {
      const lowerChar = word.toLowerCase();
      if (PHONETIC_MAP_FALLBACK[lowerChar]) {
        textToSpeak = PHONETIC_MAP_FALLBACK[lowerChar];
        utterance.lang = 'es-ES'; // Forzamos español para leer la fonética
      }
    } else {
      utterance.lang = lang; // Intentamos lo que pida la función
    }
    // Valores "Hardcoded" si no hay voz inglés para intentar suavizar lo robótico
    utterance.rate = 0.8;
    utterance.pitch = 1.1;
  }

  utterance.text = textToSpeak;
  window.speechSynthesis.speak(utterance);
};

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, speakWord, getEnglishVoices, isPremiumVoice } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');

  // UI State
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // --- VOICE STUDIO STATE ---
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());

    // Cargar voces iniciales
    const loadVoices = () => {
      const voices = getEnglishVoices();
      setAvailableVoices(voices);
      // Validar si la voz guardada aún existe, si no, resetear a null (auto)
      if (voiceSettings.voiceURI && !voices.find(v => v.voiceURI === voiceSettings.voiceURI)) {
        updateVoiceSettings({ ...voiceSettings, voiceURI: null });
      }
    };

    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
         window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, []);

  const updateVoiceSettings = (newSettings: VoiceSettings) => {
    setVoiceSettings(newSettings);
    saveVoiceSettings(newSettings);
  };

  const handleTestVoice = () => {
    speakWord("Hello friend! Learning is fun.", 'en-US', true);
  };

  const getVoiceDisplayName = () => {
    if (!voiceSettings.voiceURI) return "Automática (Mejor disponible)";
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    return v ? v.name.replace(/Microsoft|Google|English|United States/g, '').trim() : "Desconocida";
  };

  // --- LIST MANAGEMENT ---

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      // MODO EDICIÓN
      const updatedLists = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText), 
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updatedLists);
      saveLists(updatedLists);
    } else {
      // MODO CREACIÓN
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const startEditing = (list: WordList) => {
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme('');
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setEditingListId(null);
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      if (editingListId === id) resetForm();
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  const handleListClick = (list: WordList) => {
    if (role === 'parent') {
      startEditing(list);
    } else {
      onStartGame(list.id);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-6 animate-in fade-in duration-700 pb-48 relative">
      <header className="flex flex-col items-center mb-6 mt-6">
        <h1 className="text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-4"></div>

        {/* VOICE STATUS PILL (Solo visible en modo Padre) */}
        {role === 'parent' && (
          <button 
            onClick={() => setIsVoiceStudioOpen(true)}
            className="flex items-center gap-2 px-4 py-2 bg-white rounded-full shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 hover:shadow-md transition-all active:scale-95 group"
          >
            <span className="text-lg group-hover:text-emerald-500 transition-colors">🔊</span>
            <div className="flex flex-col items-start">
               <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300 leading-none">Voz Actual</span>
               <span className="text-xs font-semibold font-elegant truncate max-w-[150px]">{getVoiceDisplayName()}</span>
            </div>
            <span className="text-xs text-slate-300 ml-1">›</span>
          </button>
        )}
        {role === 'child' && (
           <p className="text-slate-400 text-sm font-elegant uppercase tracking-wider">Gestión de Eco</p>
        )}
      </header>

      {/* Formulario */}
      {role === 'parent' && (
        isAdding ? (
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4 pb-10">
            <h2 className="text-xl font-elegant font-semibold text-slate-700 px-2 flex justify-between items-center">
              <span>{editingListId ? 'Editar Lista' : 'Crear nueva lista'}</span>
              {editingListId && <span className="text-xs text-slate-400 font-normal uppercase tracking-wider">Modo Edición</span>}
            </h2>
            <input 
              className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder="Título (ej. Los Colores)"
              value={newListName}
              onChange={e => setNewListName(e.target.value)}
            />
            <textarea 
