                         <div className="flex flex-col">
                            <span className="font-bold text-sm">Automática</span>
                            <span className={`text-[10px] uppercase ${!voiceSettings.voiceURI ? 'text-slate-400' : 'text-slate-300'}`}>La mejor detectada</span>
                         </div>
                      </div>
                      {!voiceSettings.voiceURI && <span className="text-emerald-400">●</span>}
