import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, speakWord, getEnglishVoices, isPremiumVoice } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');

  // UI State
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // --- VOICE STUDIO STATE ---
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());

    // Cargar voces iniciales
    const loadVoices = () => {
      const voices = getEnglishVoices();
      setAvailableVoices(voices);
      // Validar si la voz guardada aún existe, si no, resetear a null (auto)
      if (voiceSettings.voiceURI && !voices.find(v => v.voiceURI === voiceSettings.voiceURI)) {
        updateVoiceSettings({ ...voiceSettings, voiceURI: null });
      }
    };

    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
         window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, []);

  const updateVoiceSettings = (newSettings: VoiceSettings) => {
    setVoiceSettings(newSettings);
    saveVoiceSettings(newSettings);
  };

  const handleTestVoice = () => {
    speakWord("Hello friend! Learning is fun.", 'en-US', true);
  };

  const getVoiceDisplayName = () => {
    if (!voiceSettings.voiceURI) return "Automática";
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    // Limpieza agresiva de nombres para móvil
    return v ? v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine/gi, '').trim() : "Desconocida";
