                          className="w-full accent-slate-800"
                        />
                        <div className="flex justify-between w-full text-xs mt-2 px-1 text-slate-400 font-bold">
                           <span>Grave</span><span>Agudo</span>
                        </div>
                    </div>
                </div>

                {/* Voice List */}
                <div className="flex-1 overflow-y-auto min-h-0 space-y-2 mb-4 pr-1">
                   <div 
                      onClick={() => updateVoiceSettings({...voiceSettings, voiceURI: null})}
                      className={`p-4 rounded-2xl border transition-all cursor-pointer flex items-center justify-between
                        ${!voiceSettings.voiceURI ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}`}
                   >
                      <div className="flex items-center gap-3">
                         <span className="text-xl">✨</span>
                         <div className="flex flex-col">
                            <span className="font-bold text-sm">Automática</span>
                            <span className={`text-[10px] uppercase ${!voiceSettings.voiceURI ? 'text-slate-400' : 'text-slate-300'}`}>La mejor detectada</span>
                         </div>
                      </div>
                      {!voiceSettings.voiceURI && <span className="text-emerald-400">●</span>}
                   </div>

                   {availableVoices.map(voice => {
                     const isPremium = isPremiumVoice(voice);
                     const isActive = voiceSettings.voiceURI === voice.voiceURI;
                     return (
                        <div 
                           key={voice.voiceURI}
                           onClick={() => updateVoiceSettings({...voiceSettings, voiceURI: voice.voiceURI})}
                           className={`p-3 rounded-2xl border transition-all cursor-pointer flex items-center justify-between
                             ${isActive ? 'bg-slate-900 text-white border-slate-900 shadow-lg' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}
                             ${isPremium && !isActive ? 'border-amber-100 bg-amber-50/30' : ''}
                           `}
                        >
                           <div className="flex items-center gap-3 overflow-hidden">
                              <span className="text-xl shrink-0">{isPremium ? '🌟' : '🗣️'}</span>
                              <div className="flex flex-col min-w-0">
                                 <span className="font-bold text-sm truncate pr-2">{voice.name.replace(/Microsoft|Google|English|United States/g, '')}</span>
                                 <span className={`text-[10px] truncate ${isActive ? 'text-slate-400' : 'text-slate-300'}`}>{voice.lang}</span>
                              </div>
                           </div>
                           {isActive && <span className="text-emerald-400 shrink-0">●</span>}
                        </div>
                     );
                   })}

                   {availableVoices.length === 0 && (
                      <div className="text-center p-4 text-slate-400 text-sm italic">
                         No se encontraron voces en Inglés.
                      </div>
                   )}
                </div>

                {/* Actions & Education */}
                <div className="shrink-0 space-y-3">
                    <button 
                       onClick={handleTestVoice}
                       className="w-full bg-emerald-50 text-emerald-600 font-bold py-3 rounded-xl hover:bg-emerald-100 active:scale-95 transition-all flex items-center justify-center gap-2"
                    >
                       <span>▶️</span> Probar Audio
                    </button>

                    <div className="bg-slate-50 p-3 rounded-xl">
                       <p className="text-[10px] text-slate-400 leading-relaxed text-center">
                          <strong className="text-slate-600 block mb-1">¿Suena robótico?</strong>
                          Ve a los Ajustes de tu dispositivo &gt; Accesibilidad &gt; Voz y descarga las versiones "Mejoradas" o "Premium" para Inglés (EE.UU).
                       </p>
                    </div>

                    <button 
                       onClick={() => setIsVoiceStudioOpen(false)}
                       className="w-full py-3 text-slate-400 font-bold hover:text-slate-600 transition-colors"
                    >
                       Cerrar
                    </button>
                </div>
            </div>
        </div>
      )}

    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, speakWord, getEnglishVoices, isPremiumVoice } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');

  // UI State
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // --- VOICE STUDIO STATE ---
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings'); // Nuevo estado para navegar dentro del modal
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());

    // Cargar voces iniciales
    const loadVoices = () => {
      const voices = getEnglishVoices();
      setAvailableVoices(voices);
      // Validar si la voz guardada aún existe, si no, resetear a null (auto)
      if (voiceSettings.voiceURI && !voices.find(v => v.voiceURI === voiceSettings.voiceURI)) {
        updateVoiceSettings({ ...voiceSettings, voiceURI: null });
      }
    };

    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
         window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, []);

  const updateVoiceSettings = (newSettings: VoiceSettings) => {
    setVoiceSettings(newSettings);
    saveVoiceSettings(newSettings);
  };

  const handleTestVoice = () => {
    speakWord("Hello friend! Learning is fun.", 'en-US', true);
  };

  const getVoiceDisplayName = () => {
    if (!voiceSettings.voiceURI) return "Automática";
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    // Limpieza agresiva de nombres para móvil
    return v ? v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine/gi, '').trim() : "Desconocida";
  };

  const openVoiceStudio = () => {
      setVoiceViewMode('settings'); // Siempre abrir en ajustes
      setIsVoiceStudioOpen(true);
  };

  // --- LIST MANAGEMENT ---

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      // MODO EDICIÓN
      const updatedLists = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText), 
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updatedLists);
      saveLists(updatedLists);
    } else {
      // MODO CREACIÓN
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const startEditing = (list: WordList) => {
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme('');
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setEditingListId(null);
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      if (editingListId === id) resetForm();
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  const handleListClick = (list: WordList) => {
    if (role === 'parent') {
      startEditing(list);
    } else {
      onStartGame(list.id);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 animate-in fade-in duration-700 pb-48 relative">
      <header className="flex flex-col items-center mb-6 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-6"></div>

        {/* VOICE STATUS PILL (Solo visible en modo Padre) - RESPONSIVE FIX */}
        {role === 'parent' && (
          <button 
            onClick={openVoiceStudio}
            className="flex items-center gap-3 px-4 py-2 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 hover:shadow-md transition-all active:scale-95 group max-w-full"
          >
            <span className="text-lg group-hover:text-emerald-500 transition-colors shrink-0">🔊</span>
            <div className="flex flex-col items-start min-w-0 overflow-hidden">
               <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300 leading-none mb-0.5">Voz</span>
               <span className="text-sm font-semibold font-elegant truncate w-full text-left block max-w-[180px] sm:max-w-xs">{getVoiceDisplayName()}</span>
            </div>
            <span className="text-xs text-slate-300 shrink-0 ml-1">›</span>
          </button>
        )}
        {role === 'child' && (
           <p className="text-slate-400 text-sm font-elegant uppercase tracking-wider">Gestión de Eco</p>
        )}
      </header>

      {/* Formulario */}
      {role === 'parent' && (
        isAdding ? (
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4 pb-10">
            <h2 className="text-xl font-elegant font-semibold text-slate-700 px-2 flex justify-between items-center">
              <span>{editingListId ? 'Editar Lista' : 'Crear nueva lista'}</span>
              {editingListId && <span className="text-xs text-slate-400 font-normal uppercase tracking-wider">Modo Edición</span>}
            </h2>
            <input 
              className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder="Título (ej. Los Colores)"
              value={newListName}
              onChange={e => setNewListName(e.target.value)}
            />
            <textarea 
              className="w-full p-4 h-32 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder="Palabras a aprender..."
              value={inputText}
              onChange={e => setInputText(e.target.value)}
            />
            <input 
              className="w-full p-4 rounded-2xl bg-slate-50 border-none focus:ring-2 focus:ring-slate-200 text-lg"
              placeholder={editingListId ? "Nuevo tema para fondo (Opcional)" : "Tema del fondo (ej. Selva)"}
              value={theme}
              onChange={e => setTheme(e.target.value)}
            />
            <div className="flex gap-3 pt-2">
              <button 
                disabled={isLoadingImage}
                onClick={handleSaveList}
                className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold shadow-lg shadow-slate-200 disabled:opacity-50 active:scale-95 transition-transform h-14"
              >
                {isLoadingImage ? 'Procesando...' : (editingListId ? 'Guardar Cambios' : 'Crear')}
              </button>
              <button 
                onClick={resetForm}
                className="px-6 p-4 rounded-2xl bg-slate-100 text-slate-500 font-bold active:scale-95 h-14 w-16 flex items-center justify-center text-xl"
              >
                ×
              </button>
            </div>
          </div>
        ) : (
          <button 
            onClick={() => {
              setEditingListId(null);
              setNewListName('');
              setInputText('');
              setTheme('');
              setIsAdding(true);
            }}
            className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 hover:text-slate-500 transition-all mb-8 flex items-center justify-center gap-2 bg-white/50 active:scale-98"
          >
            <span className="text-2xl font-light">+</span> Nueva Lista
          </button>
        )
      )}

      <div className="space-y-4">
        {lists.length === 0 && !isAdding && (
          <div className="text-center py-20 opacity-30">
            <span className="text-5xl block mb-4">📖</span>
            <p className="font-elegant">No hay listas aún</p>
          </div>
        )}
        {lists.map(list => (
          <div 
            key={list.id} 
            onClick={() => handleListClick(list)}
            className={`bg-white p-4 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer group min-h-[5.5rem]
              ${editingListId === list.id ? 'ring-2 ring-slate-900 shadow-xl scale-[1.02]' : ''}`}
          >
            <div className="flex items-center gap-4 min-w-0">
              <div className="w-16 h-16 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl shadow-inner overflow-hidden shrink-0">
                {list.backgroundImage ? (
                  <img src={list.backgroundImage} className="w-full h-full object-cover" alt="" />
                ) : (
                  '📝'
                )}
              </div>
              <div className="min-w-0">
                <h3 className="text-lg font-bold text-slate-800 leading-tight truncate">{list.name}</h3>
                <p className="text-xs text-slate-400 font-elegant uppercase tracking-tighter">
                  {list.words.length} palabras
                </p>
              </div>
            </div>

            {role === 'parent' && (
              <div className="flex items-center gap-2 shrink-0">
                <button 
                  onClick={(e) => toggleRain(list.id, e)}
                  className={`w-12 h-12 rounded-full flex items-center justify-center transition-all active:scale-90 shadow-sm border border-slate-50 ${list.settings.rainEnabled ? 'bg-blue-50 text-blue-500' : 'bg-orange-50 text-orange-400'}`}
                  title={list.settings.rainEnabled ? 'Modo Lluvia' : 'Modo Calma'}
                >
                  <span className="text-xl">{list.settings.rainEnabled ? '🌧️' : '☁️'}</span>
                </button>
                <button 
                  onClick={(e) => deleteList(list.id, e)}
                  className="w-12 h-12 rounded-full bg-slate-50 text-slate-300 flex items-center justify-center hover:bg-rose-50 hover:text-rose-400 active:scale-90 transition-all shadow-sm border border-slate-100"
                  title="Borrar"
                >
                  <span className="text-lg font-bold">✕</span>
                </button>
              </div>
            )}
          </div>
        ))}
      </div>

      <footer className="mt-12 text-center opacity-20 px-8">
        <p className="text-[10px] font-elegant tracking-widest uppercase">Echofy v2.0</p>
      </footer>

      {/* --- VOICE STUDIO MODAL --- */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[100] flex items-end justify-center sm:items-center">
            {/* Backdrop */}
            <div 
              className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm animate-in fade-in duration-300"
              onClick={() => setIsVoiceStudioOpen(false)}
            ></div>

            {/* Modal Content */}
            <div className="bg-white w-full max-w-sm mx-auto sm:rounded-[2.5rem] rounded-t-[2.5rem] p-6 shadow-2xl animate-in slide-in-from-bottom-4 duration-500 relative z-10 max-h-[85vh] flex flex-col">
                <div className="w-12 h-1 bg-slate-200 rounded-full mx-auto mb-6 shrink-0"></div>

                {voiceViewMode === 'settings' ? (
                  /* --- VISTA 1: AJUSTES PRINCIPALES --- */
                  <>
                    <h2 className="text-2xl font-elegant font-bold text-slate-800 text-center mb-1">Estudio de Voz</h2>
                    <p className="text-center text-slate-400 text-sm mb-6">Ajusta cómo suena tu eco</p>

                    {/* Botón Grande de Selección de Voz */}
                    <button 
                       onClick={() => setVoiceViewMode('list')}
                       className="w-full mb-6 p-4 rounded-2xl border border-slate-100 bg-white hover:bg-slate-50 active:bg-slate-100 active:scale-98 transition-all flex items-center justify-between shadow-sm group"
                    >
                       <div className="flex items-center gap-3 overflow-hidden">
                          <div className="w-10 h-10 rounded-full bg-indigo-50 text-indigo-500 flex items-center justify-center text-xl shrink-0">
                            🗣️
                          </div>
                          <div className="flex flex-col items-start min-w-0">
                             <span className="text-[10px] uppercase font-bold text-slate-400 tracking-widest">Voz Seleccionada</span>
                             <span className="text-lg font-bold text-slate-800 truncate w-full text-left">{getVoiceDisplayName()}</span>
                          </div>
                       </div>
                       <span className="text-slate-300 text-xl group-hover:translate-x-1 transition-transform">›</span>
                    </button>

                    {/* Controles de Velocidad y Tono */}
                    <div className="flex gap-4 mb-6 shrink-0">
                        <div className="flex-1 bg-slate-50 rounded-2xl p-4 flex flex-col items-center">
                            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Velocidad</span>
                            <input 
                              type="range" min="0.5" max="1.5" step="0.1" 
                              value={voiceSettings.rate}
                              onChange={(e) => updateVoiceSettings({...voiceSettings, rate: parseFloat(e.target.value)})}
                              className="w-full accent-slate-800"
                            />
                            <div className="flex justify-between w-full text-lg mt-1 px-1 text-slate-300">
                              <span>🐢</span><span>🐇</span>
                            </div>
                        </div>
                        <div className="flex-1 bg-slate-50 rounded-2xl p-4 flex flex-col items-center">
                            <span className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-3">Tono</span>
                            <input 
                              type="range" min="0.5" max="1.5" step="0.1"
                              value={voiceSettings.pitch}
                              onChange={(e) => updateVoiceSettings({...voiceSettings, pitch: parseFloat(e.target.value)})}
                              className="w-full accent-slate-800"
                            />
                            <div className="flex justify-between w-full text-xs mt-2 px-1 text-slate-400 font-bold">
                              <span>Grave</span><span>Agudo</span>
                            </div>
                        </div>
                    </div>

                    {/* Botones de Acción */}
                    <div className="space-y-3 mt-auto">
                        <button 
                          onClick={handleTestVoice}
                          className="w-full bg-emerald-50 text-emerald-600 font-bold py-3 rounded-xl hover:bg-emerald-100 active:scale-95 transition-all flex items-center justify-center gap-2"
                        >
                          <span>▶️</span> Probar Audio
                        </button>

                        <button 
                          onClick={() => setIsVoiceStudioOpen(false)}
                          className="w-full py-3 text-slate-400 font-bold hover:text-slate-600 transition-colors"
                        >
                          Cerrar
                        </button>
                    </div>
                  </>
                ) : (
                  /* --- VISTA 2: LISTA DE VOCES --- */
                  <>
                    <div className="flex items-center gap-3 mb-4">
                      <button 
                        onClick={() => setVoiceViewMode('settings')}
                        className="w-10 h-10 rounded-full bg-slate-100 text-slate-500 flex items-center justify-center hover:bg-slate-200 active:scale-90 transition-all"
                      >
                        ←
                      </button>
                      <h2 className="text-xl font-elegant font-bold text-slate-800">Seleccionar Voz</h2>
                    </div>

                    <div className="flex-1 overflow-y-auto min-h-[300px] space-y-2 pr-1 mb-4">
                       {/* Opción Automática */}
                       <div 
                          onClick={() => {
                            updateVoiceSettings({...voiceSettings, voiceURI: null});
                            setVoiceViewMode('settings');
                          }}
                          className={`p-4 rounded-2xl border transition-all cursor-pointer flex items-center justify-between
                            ${!voiceSettings.voiceURI ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}`}
                       >
                          <div className="flex items-center gap-3">
                             <span className="text-xl">✨</span>
                             <div className="flex flex-col">
                                <span className="font-bold text-sm">Automática</span>
                                <span className={`text-[10px] uppercase ${!voiceSettings.voiceURI ? 'text-slate-400' : 'text-slate-300'}`}>La mejor detectada</span>
                             </div>
                          </div>
                          {!voiceSettings.voiceURI && <span className="text-emerald-400">●</span>}
                       </div>

                       {/* Lista Real de Voces */}
                       {availableVoices.map(voice => {
                         const isPremium = isPremiumVoice(voice);
                         const isActive = voiceSettings.voiceURI === voice.voiceURI;
                         return (
                            <div 
                               key={voice.voiceURI}
                               onClick={() => {
                                 updateVoiceSettings({...voiceSettings, voiceURI: voice.voiceURI});
                                 setVoiceViewMode('settings'); // Volver a ajustes al seleccionar
                               }}
                               className={`p-3 rounded-2xl border transition-all cursor-pointer flex items-center justify-between
                                 ${isActive ? 'bg-slate-900 text-white border-slate-900 shadow-lg' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}
                                 ${isPremium && !isActive ? 'border-amber-100 bg-amber-50/30' : ''}
                               `}
                            >
                               <div className="flex items-center gap-3 overflow-hidden">
                                  <span className="text-xl shrink-0">{isPremium ? '🌟' : '🗣️'}</span>
                                  <div className="flex flex-col min-w-0">
                                     <span className="font-bold text-sm truncate pr-2">{voice.name.replace(/Microsoft|Google|English|United States/g, '')}</span>
                                     <span className={`text-[10px] truncate ${isActive ? 'text-slate-400' : 'text-slate-300'}`}>{voice.lang}</span>
                                  </div>
                               </div>
                               {isActive && <span className="text-emerald-400 shrink-0">●</span>}
                            </div>
                         );
                       })}

                       {availableVoices.length === 0 && (
                          <div className="text-center p-4 text-slate-400 text-sm italic">
                             No se encontraron voces en Inglés.
                          </div>
                       )}
                    </div>

                    <div className="bg-slate-50 p-3 rounded-xl shrink-0">
                       <p className="text-[10px] text-slate-400 leading-relaxed text-center">
                          <strong className="text-slate-600 block mb-1">Tip de Calidad</strong>
                          Descarga voces "Premium" o "Mejoradas" en los ajustes de Accesibilidad de tu dispositivo.
                       </p>
                    </div>
                  </>
                )}
            </div>
        </div>
      )}

    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, speakWord, getEnglishVoices, isPremiumVoice } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
