    return v ? v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine/gi, '').trim() : "Desconocida";
  };

  const openVoiceStudio = () => {
      setVoiceViewMode('settings'); // Siempre abrir en ajustes
      setIsVoiceStudioOpen(true);
  };

  // --- LIST MANAGEMENT ---

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      // MODO EDICIÓN
      const updatedLists = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText), 
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updatedLists);
      saveLists(updatedLists);
    } else {
      // MODO CREACIÓN
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const startEditing = (list: WordList) => {
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme('');
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setEditingListId(null);
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      if (editingListId === id) resetForm();
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  const handleListClick = (list: WordList) => {
    if (role === 'parent') {
      startEditing(list);
    } else {
      onStartGame(list.id);
    }
