export default ParentDashboard;

import { GoogleGenAI } from "@google/genai";
import { loadVoiceSettings } from "./store";

export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting. Blurred and fantasy effects.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

// --- VOICE & AUDIO LOGIC ---

// Mapa fonético para simular inglés usando voz en español (Solo si falla todo lo demás)
const PHONETIC_MAP_FALLBACK: Record<string, string> = {
  "a": "ei", "b": "bi", "c": "si", "d": "di", "e": "ii", 
  "f": "ef", "g": "yi", "h": "eich", "i": "ai", "j": "yei",
  "k": "kei", "l": "el", "m": "em", "n": "en", "o": "ou",
  "p": "pi", "q": "kiu", "r": "ar", "s": "es", "t": "ti",
  "u": "iu", "v": "vi", "w": "doboliu", "x": "ex", "y": "uai", "z": "zi"
};

export const getEnglishVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const voices = window.speechSynthesis.getVoices();
  // Filtrar voces en inglés
  return voices.filter(v => v.lang.startsWith('en'));
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || 
         name.includes('premium') || 
         name.includes('enhanced') || 
         name.includes('siri') || 
         name.includes('natural');
};

const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null, lang: string } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null, lang: 'en-US' };

  const voices = window.speechSynthesis.getVoices();

  // 1. Voz seleccionada por usuario
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice, lang: userVoice.lang };
  }

  // 2. Automática: Premium English
  const premium = voices.find(v => v.lang.startsWith('en') && isPremiumVoice(v));
  if (premium) return { voice: premium, lang: premium.lang };

  // 3. Automática: Standard English US
  const us = voices.find(v => v.lang === 'en-US');
  if (us) return { voice: us, lang: 'en-US' };

  // 4. Automática: Any English
  const anyEn = voices.find(v => v.lang.startsWith('en'));
  if (anyEn) return { voice: anyEn, lang: anyEn.lang };

  return { voice: null, lang: 'es-ES' }; // Fallback total
};

export const speakWord = (word: string, lang: string = 'en-US', interrupt: boolean = true) => {
  // Versión simple para compatibilidad ("Disparar y olvidar")
  speakWordPromise(word, lang, interrupt).catch(console.error);
};

// NUEVA FUNCIÓN: Retorna una Promesa que se resuelve cuando termina el audio
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise((resolve) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const settings = loadVoiceSettings();
    const { voice, lang: voiceLang } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance();

    // Configuración de texto y voz
    const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);
    let textToSpeak = word;

    if (voice) {
      utterance.voice = voice;
      utterance.lang = voiceLang;
      const baseRate = settings.rate;
      // Letras sueltas un poco más lento para claridad
      utterance.rate = isSingleLetter ? Math.max(0.5, baseRate - 0.2) : baseRate;
      utterance.pitch = settings.pitch;
    } else {
      // Fallback fonético
      if (isSingleLetter) {
        const lowerChar = word.toLowerCase();
        if (PHONETIC_MAP_FALLBACK[lowerChar]) {
          textToSpeak = PHONETIC_MAP_FALLBACK[lowerChar];
          utterance.lang = 'es-ES';
        }
      } else {
        utterance.lang = lang;
      }
      utterance.rate = 0.8; 
    }

    utterance.text = textToSpeak;

    // Eventos de la Promesa
    utterance.onend = () => {
      resolve();
    };

    utterance.onerror = (e) => {
      console.warn("Speech synthesis error", e);
      resolve(); // Resolvemos igual para no bloquear la app
    };

    // Safety timeout: si por alguna razón onend no dispara en 5 segundos, liberamos
    const safetyTimeout = setTimeout(() => {
        resolve();
    }, 5000);

    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WordList, Word } from '../types';
import { speakWordPromise } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isCorrect, setIsCorrect] = useState<boolean | null>(null);

  // ESTADO DE BLOQUEO: Si es true, el niño no puede tocar nada
  const [isAudioLocked, setIsAudioLocked] = useState(true);

  // Refs para control de montaje
  const isMounted = useRef(true);

  // Generamos un "seed" aleatorio para el jitter de la animación
  const [randomJitters, setRandomJitters] = useState<number[]>([]);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  const initWord = async () => {
    // 1. Bloqueo inicial inmediato
    setIsAudioLocked(true);
    setShowRevelation(false);
    setIsTransitioning(false);
    setIsCorrect(null);

    // 2. Preparar letras
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setRandomJitters(shuffled.map(() => Math.random() * 0.1));

    // 3. Calcular TIEMPO EXACTO de caída
    // Fórmula: Delay Inicial (0.6s) + Cascada (N * 0.06s) + Duración Animación (0.8s) + Margen Seguridad (0.2s)
    const numLetters = shuffled.length;
    const cascadeDuration = numLetters * 0.06;
    const animationDuration = 0.8; 
    const initialDelay = 0.6;
    const totalDropTime = (initialDelay + cascadeDuration + animationDuration + 0.2) * 1000;

    // 4. Esperar a que caigan las letras visualmente
    await new Promise(resolve => setTimeout(resolve, totalDropTime));

    if (!isMounted.current) return;

    // 5. Pronunciar la palabra completa (Solo cuando ya aterrizaron)
    await speakWordPromise(currentWord.original, 'en-US', true);

    // 6. Desbloquear interacción
    if (isMounted.current) setIsAudioLocked(false);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    // Si está bloqueado (porque está hablando o cayendo), ignoramos el clic
    if (isAudioLocked || showRevelation) return;

    // BLOQUEAR INTERFAZ
    setIsAudioLocked(true);

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      // Actualizar UI
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      const newJitters = [...randomJitters];
      newJitters.splice(index, 1);
      setRandomJitters(newJitters);

      // HABLAR (Esperar a que termine)
      await speakWordPromise(letterObj.char, 'en-US', true);

      // Verificar si completó
      if (newSlots.indexOf(null) === -1) {
        // Si completó, NO desbloqueamos, pasamos directo a la secuencia final
        handleCompletion(newSlots.join(''));
      } else {
        // Si no completó, desbloqueamos para la siguiente letra
        setIsAudioLocked(false);
      }
    } else {
        // Por seguridad, si no había espacio
        setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    // También bloqueamos devolver letras si está hablando
    if (isAudioLocked || showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
    setRandomJitters([...randomJitters, Math.random() * 0.1]);
  };

  const handleCompletion = async (constructed: string) => {
    const checkResult = constructed === currentWord.original.toLowerCase();
    setIsCorrect(checkResult);

    // Guardar errores si falló
    if (!checkResult) {
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
      // Si falló, desbloqueamos para que corrija
      setIsAudioLocked(false);
      return; 
    }

    // --- SECUENCIA DE ÉXITO COREOGRAFIADA ---
    // El bloqueo (isAudioLocked) sigue en TRUE desde la última letra

    // 1. Pausa dramática post-última letra (500ms)
    await new Promise(resolve => setTimeout(resolve, 500));

    if (!isMounted.current) return;

    // 2. Mostrar Revelación Visual
    setShowRevelation(true); 

    // 3. Pronunciar Palabra Completa (Inglés)
    await speakWordPromise(currentWord.original, 'en-US', true);

    // 4. Pausa Breve
    await new Promise(resolve => setTimeout(resolve, 300));

    // 5. Deletreo Lento (Spelling)
    const letters = currentWord.original.split('');
    for (const char of letters) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
        // Pequeñísima pausa entre letras del deletreo
        await new Promise(resolve => setTimeout(resolve, 100));
    }

    // 6. Pausa Breve
    await new Promise(resolve => setTimeout(resolve, 400));

    // 7. Pronunciar Palabra Completa Final (Cierre)
    await speakWordPromise(currentWord.original, 'en-US', false);

    // Fin de la secuencia: Aparece botón siguiente (controlado por showRevelation)
    // El bloqueo de audio ya no importa porque showRevelation deshabilita clics en letras
  };

  const nextWord = () => {
    // Cancelar cualquier audio pendiente
    window.speechSynthesis.cancel();

    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      {/* Capas de Fondo */}
      <div className="absolute inset-0 bg-white/10 backdrop-blur-3xl pointer-events-none"></div>
      <div className="absolute inset-0 bg-gradient-to-b from-white/30 via-transparent to-white/20 pointer-events-none"></div>

      {/* Botón Salir */}
      <button 
        onClick={() => {
            window.speechSynthesis.cancel();
            onExit();
        }}
        className="fixed top-4 right-4 z-50 w-12 h-12 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-500 shadow-sm active:bg-white/40 active:scale-90 transition-all mt-[env(safe-area-inset-top)]"
      >
        <span className="text-xl font-bold">✕</span>
      </button>

      {/* Contenido Principal */}
      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">

        {/* Zona Superior */}
        <div className="flex flex-col items-center justify-center pt-8 w-full">
            <button 
              // Permitimos repetir el audio principal incluso si está bloqueado, pero con cuidado
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl shadow-slate-200/50 transition-all mb-6
                ${isAudioLocked ? 'opacity-50 scale-95 cursor-not-allowed' : 'active:scale-90'}
              `}
            >
              <span className="text-4xl">🔊</span>
            </button>

            {/* Revelación */}
            <div className="h-24 w-full flex items-center justify-center px-4">
              {showRevelation ? (
                <div className="animate-in fade-in zoom-in-95 duration-700 text-center w-full max-w-sm">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 mb-1 uppercase tracking-[0.1em] drop-shadow-sm">
                    {currentWord.original}
                  </h2>
                  <div className="bg-white/70 backdrop-blur-md px-4 py-2 rounded-2xl shadow-sm border border-white/40 inline-block">
                    <p className="text-lg italic text-slate-700 font-elegant font-medium leading-tight">
                      {getMeaning(currentWord.original)}
                    </p>
                  </div>
                </div>
              ) : (
                <div className="opacity-0">.</div>
              )}
            </div>
        </div>

        {/* Zona Slots */}
        <div className="flex gap-2 flex-wrap justify-center px-2 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div 
              key={i}
              onClick={() => handleSlotClick(i)}
              style={{ 
                animationDelay: list.settings.rainEnabled && !char ? `${i * 0.08}s` : '0s' 
              }}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (showRevelation && !isCorrect ? 'bg-rose-50 border-rose-200 text-rose-500' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}
                ${list.settings.rainEnabled && !char ? 'animate-bounce-drop' : 'animate-in fade-in'}
                ${isAudioLocked && char && !showRevelation ? 'opacity-60' : 'opacity-100'} 
              `}
            >
              {char}
            </div>
          ))}
        </div>

        {/* Zona Banco de Letras */}
        <div className={`w-full px-4 pb-8 sm:pb-12 flex gap-2 sm:gap-3 flex-wrap justify-center items-end min-h-[100px] transition-opacity duration-300 ${isAudioLocked && !showRevelation ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => {
            const delayTime = 0.6 + (i * 0.06) + (randomJitters[i] || 0);

            return (
              <button
                key={letterObj.id}
                onClick={() => handleLetterClick(letterObj, i)}
                disabled={isAudioLocked}
                style={{ 
                  animationDelay: list.settings.rainEnabled ? `${delayTime.toFixed(2)}s` : '0s',
                }}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-100
                  ${list.settings.rainEnabled ? 'animate-bounce-drop' : 'animate-in zoom-in-50'}
                  ${!isAudioLocked ? 'active:scale-90 active:bg-slate-100' : ''}
                `}
              >
                {letterObj.char}
              </button>
            );
          })}
        </div>
      </div>

      {/* Botón Siguiente */}
      {showRevelation && (
        <button 
          onClick={(e) => {
            e.stopPropagation();
            nextWord();
          }}
          className="fixed bottom-8 right-6 z-50 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200/50 flex items-center justify-center animate-in slide-in-from-right-20 zoom-in duration-500 active:scale-90 active:bg-emerald-600 transition-all border-4 border-white/20 mb-[env(safe-area-inset-bottom)]"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}

    </div>
  );
};

