import { GoogleGenAI } from "@google/genai";
import { loadVoiceSettings } from "./store";

export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting. Blurred and fantasy effects.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

// --- VOICE & AUDIO LOGIC ---

// Mapa fonético para simular inglés usando voz en español (Solo si falla todo lo demás)
const PHONETIC_MAP_FALLBACK: Record<string, string> = {
  "a": "ei", "b": "bi", "c": "si", "d": "di", "e": "ii", 
  "f": "ef", "g": "yi", "h": "eich", "i": "ai", "j": "yei",
  "k": "kei", "l": "el", "m": "em", "n": "en", "o": "ou",
  "p": "pi", "q": "kiu", "r": "ar", "s": "es", "t": "ti",
  "u": "iu", "v": "vi", "w": "doboliu", "x": "ex", "y": "uai", "z": "zi"
};

export const getEnglishVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const voices = window.speechSynthesis.getVoices();
  // Filtrar estrictamente voces en inglés (case insensitive)
  return voices.filter(v => v.lang && v.lang.toLowerCase().startsWith('en'));
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || 
         name.includes('premium') || 
         name.includes('enhanced') || 
         name.includes('siri') || 
         name.includes('natural');
};

const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null, lang: string } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null, lang: 'en-US' };

  const voices = window.speechSynthesis.getVoices();

  // 1. Voz seleccionada por usuario (Validar que siga existiendo)
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice, lang: userVoice.lang };
  }

  // 2. Automática: Buscar Premium English
  const premium = voices.find(v => v.lang.toLowerCase().startsWith('en') && isPremiumVoice(v));
  if (premium) return { voice: premium, lang: premium.lang };

  // 3. Automática: Standard English US
  const us = voices.find(v => v.lang === 'en-US' || v.lang === 'en_US');
  if (us) return { voice: us, lang: 'en-US' };

  // 4. Automática: Cualquier English
  const anyEn = voices.find(v => v.lang.toLowerCase().startsWith('en'));
  if (anyEn) return { voice: anyEn, lang: anyEn.lang };

  // 5. Fallback: No retornamos español. Si no hay inglés, dejamos null para que el navegador use su default.
  return { voice: null, lang: 'en-US' }; 
};

export const speakWord = (word: string, lang: string = 'en-US', interrupt: boolean = true) => {
  // Versión simple para compatibilidad ("Disparar y olvidar")
  speakWordPromise(word, lang, interrupt).catch(console.error);
};

// NUEVA FUNCIÓN: Retorna una Promesa que se resuelve cuando termina el audio
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise((resolve) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const settings = loadVoiceSettings();
    const { voice, lang: voiceLang } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance();

    // Configuración de texto y voz
    const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);
    let textToSpeak = word;

    if (voice) {
      utterance.voice = voice;
      utterance.lang = voiceLang;
      const baseRate = settings.rate;
      // Letras sueltas un poco más lento para claridad
      utterance.rate = isSingleLetter ? Math.max(0.5, baseRate - 0.2) : baseRate;
      utterance.pitch = settings.pitch;
    } else {
      // Fallback si no hay voz detectada
      utterance.lang = 'en-US';
      utterance.rate = 0.8; 
    }

    utterance.text = textToSpeak;

    // Eventos de la Promesa
    utterance.onend = () => {
      resolve();
    };

    utterance.onerror = (e) => {
      console.warn("Speech synthesis error", e);
      resolve(); // Resolvemos igual para no bloquear la app
    };

    // Safety timeout: si por alguna razón onend no dispara en 5 segundos, liberamos
    const safetyTimeout = setTimeout(() => {
        resolve();
    }, 5000);

    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, speakWord, getEnglishVoices, isPremiumVoice } from '../geminiService';

interface Props {
  onStartGame: (listId: string) => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);

  // Form State
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');

  // UI State
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // --- VOICE STUDIO STATE ---
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings'); // Nuevo estado para navegar dentro del modal
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());

    // Cargar voces iniciales
    const loadVoices = () => {
      const voices = getEnglishVoices();
      setAvailableVoices(voices);
      // Validar si la voz guardada aún existe, si no, resetear a null (auto)
      if (voiceSettings.voiceURI && !voices.find(v => v.voiceURI === voiceSettings.voiceURI)) {
        updateVoiceSettings({ ...voiceSettings, voiceURI: null });
      }
    };

    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }

    return () => {
      if (typeof window !== 'undefined' && window.speechSynthesis) {
         window.speechSynthesis.onvoiceschanged = null;
      }
    };
  }, []);

  const updateVoiceSettings = (newSettings: VoiceSettings) => {
    setVoiceSettings(newSettings);
    saveVoiceSettings(newSettings);
  };

  const handleTestVoice = () => {
    speakWord("Hello friend! Learning is fun.", 'en-US', true);
  };

  const getVoiceDisplayName = () => {
    if (!voiceSettings.voiceURI) return "Automática";
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    // Limpieza agresiva de nombres para móvil
    return v ? v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine/gi, '').trim() : "Desconocida";
  };

  const openVoiceStudio = () => {
      setVoiceViewMode('settings'); // Siempre abrir en ajustes
      setIsVoiceStudioOpen(true);
  };

  // --- LIST MANAGEMENT ---

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;

    setIsLoadingImage(true);
    let bg = undefined;

    if (theme) {
      bg = await generateBackgroundImage(theme);
    }

    if (editingListId) {
      // MODO EDICIÓN
      const updatedLists = lists.map(l => {
        if (l.id === editingListId) {
          return {
            ...l,
            name: newListName,
            words: extractWords(inputText), 
            backgroundImage: bg || l.backgroundImage,
            lastPlayed: Date.now()
          };
        }
        return l;
      });
      setLists(updatedLists);
      saveLists(updatedLists);
    } else {
      // MODO CREACIÓN
      const newList: WordList = {
        id: Math.random().toString(36).substr(2, 9),
        name: newListName,
        words: extractWords(inputText),
        backgroundImage: bg || undefined,
        lastPlayed: Date.now(),
        settings: {
          rainEnabled: true
        }
      };
      const updated = [...lists, newList];
      setLists(updated);
      saveLists(updated);
    }

    resetForm();
  };

  const startEditing = (list: WordList) => {
    setEditingListId(list.id);
    setNewListName(list.name);
    setInputText(list.words.map(w => w.original).join(' '));
    setTheme('');
    setIsAdding(true);
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const resetForm = () => {
    setNewListName('');
    setInputText('');
    setTheme('');
    setEditingListId(null);
    setIsAdding(false);
    setIsLoadingImage(false);
  };

  const toggleRain = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    const updated = lists.map(l => {
      if (l.id === id) return { ...l, settings: { ...l.settings, rainEnabled: !l.settings.rainEnabled } };
      return l;
    });
    setLists(updated);
    saveLists(updated);
  };

  const deleteList = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (confirm('¿Quieres borrar esta lista definitivamente?')) {
      if (editingListId === id) resetForm();
      const updated = lists.filter(l => l.id !== id);
      setLists(updated);
      saveLists(updated);
    }
  };

  const handleListClick = (list: WordList) => {
    if (role === 'parent') {
      startEditing(list);
    } else {
      onStartGame(list.id);
    }
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 animate-in fade-in duration-700 pb-48 relative">
