// Mapa fonético para simular inglés usando voz en español (Solo si falla todo lo demás)
const PHONETIC_MAP_FALLBACK: Record<string, string> = {
  "a": "ei", "b": "bi", "c": "si", "d": "di", "e": "ii", 
  "f": "ef", "g": "yi", "h": "eich", "i": "ai", "j": "yei",
  "k": "kei", "l": "el", "m": "em", "n": "en", "o": "ou",
  "p": "pi", "q": "kiu", "r": "ar", "s": "es", "t": "ti",
  "u": "iu", "v": "vi", "w": "doboliu", "x": "ex", "y": "uai", "z": "zi"
};

export const getEnglishVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const voices = window.speechSynthesis.getVoices();
  // Filtrar estrictamente voces en inglés (case insensitive)
  return voices.filter(v => v.lang && v.lang.toLowerCase().startsWith('en'));
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || 
         name.includes('premium') || 
         name.includes('enhanced') || 
         name.includes('siri') || 
         name.includes('natural');
};

const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null, lang: string } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null, lang: 'en-US' };

  const voices = window.speechSynthesis.getVoices();

  // 1. Voz seleccionada por usuario (Validar que siga existiendo)
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice, lang: userVoice.lang };
  }

  // 2. Automática: Buscar Premium English
  const premium = voices.find(v => v.lang.toLowerCase().startsWith('en') && isPremiumVoice(v));
  if (premium) return { voice: premium, lang: premium.lang };

  // 3. Automática: Standard English US
  const us = voices.find(v => v.lang === 'en-US' || v.lang === 'en_US');
  if (us) return { voice: us, lang: 'en-US' };

  // 4. Automática: Cualquier English
  const anyEn = voices.find(v => v.lang.toLowerCase().startsWith('en'));
  if (anyEn) return { voice: anyEn, lang: anyEn.lang };

  // 5. Fallback: No retornamos español. Si no hay inglés, dejamos null para que el navegador use su default.
  return { voice: null, lang: 'en-US' }; 
};

export const speakWord = (word: string, lang: string = 'en-US', interrupt: boolean = true) => {
  // Versión simple para compatibilidad ("Disparar y olvidar")
  speakWordPromise(word, lang, interrupt).catch(console.error);
};

// NUEVA FUNCIÓN: Retorna una Promesa que se resuelve cuando termina el audio
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise((resolve) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const settings = loadVoiceSettings();
    const { voice, lang: voiceLang } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance();

    // Configuración de texto y voz
    const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);
    let textToSpeak = word;

    if (voice) {
      utterance.voice = voice;
      utterance.lang = voiceLang;
      const baseRate = settings.rate;

      if (isSingleLetter) {
        // Lógica para letras sueltas: Claras y concisas
        utterance.rate = Math.max(0.5, baseRate - 0.1);
        utterance.pitch = settings.pitch;
      } else {
        // Lógica para PALABRAS COMPLETAS: Efecto "Prolongado" (Legato)

        // 1. Velocidad: Un poco más lento que la base para "estirar" las vocales
        utterance.rate = Math.max(0.65, baseRate * 0.9); 

        // 2. Tono: Ligeramente más grave para dar cuerpo a la voz lenta y evitar que suene artificial
        utterance.pitch = Math.max(0.8, settings.pitch * 0.95);

        // 3. El Truco de la Puntuación:
        // Añadir "..." al final fuerza al motor TTS a usar una entonación no-final (suspensiva).
        // Esto evita el corte abrupto del audio (clipping) y deja un "aire" natural al final.
        textToSpeak = `${word}...`;
      }

    } else {
      // Fallback si no hay voz detectada
      utterance.lang = 'en-US';
      utterance.rate = 0.75; 
      if (!isSingleLetter) {
        textToSpeak = `${word}...`;
      }
    }

    utterance.text = textToSpeak;

    // Eventos de la Promesa
    utterance.onend = () => {
      resolve();
    };

    utterance.onerror = (e) => {
      console.warn("Speech synthesis error", e);
      resolve(); // Resolvemos igual para no bloquear la app
    };

    // Safety timeout: si por alguna razón onend no dispara en 5 segundos, liberamos
    const safetyTimeout = setTimeout(() => {
        resolve();
    }, 5000);

    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

