import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WordList, Word } from '../types';
import { speakWordPromise } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  // ESTADOS DE FASE
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); // Para el efecto Glow

  // Refs para control de montaje
  const isMounted = useRef(true);

  // Generamos un "seed" aleatorio para el jitter de la animación
  const [randomJitters, setRandomJitters] = useState<number[]>([]);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  // Lógica de "Rojo Suave"
  const isCorrectSoFar = useMemo(() => {
    const filled = slots.filter(s => s !== null).join('');
    return currentWord.original.toLowerCase().startsWith(filled.toLowerCase());
  }, [slots, currentWord]);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  const initWord = async () => {
    // 1. Bloqueo inicial inmediato (Fase 1: El Estímulo)
    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setIsTransitioning(false);

    // 2. Preparar letras
    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setAvailableLetters(shuffled);
    setSlots(new Array(currentWord.original.length).fill(null));
    setRandomJitters(shuffled.map(() => Math.random() * 0.1));

    // 3. Calcular TIEMPO DE CAÍDA (aprox 1.5s total)
    const numLetters = shuffled.length;
    const cascadeDuration = numLetters * 0.06;
    const animationDuration = 0.8; 
    const initialDelay = 0.6;
    const totalDropTime = (initialDelay + cascadeDuration + animationDuration) * 1000;

    // 4. A la vez que aterrizan, pronunciar (Fase 1: Modelo Sonoro)
    const landingWait = setTimeout(async () => {
       if (!isMounted.current) return;
       // Pronunciar Legato al aterrizar
       await speakWordPromise(currentWord.original, 'en-US', true);

       // 5. Liberación (Fase 1: Liberación)
       if (isMounted.current) {
          setIsReadyToPlay(true);
          setIsAudioLocked(false);
       }
    }, totalDropTime);

    return () => clearTimeout(landingWait);
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    // Fase 2: La Construcción
    if (isAudioLocked || showRevelation) return;

    setIsAudioLocked(true); // Bloquear mientras vuela y habla la letra

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      const newJitters = [...randomJitters];
      newJitters.splice(index, 1);
      setRandomJitters(newJitters);

      // Feedback Fonémico Instantáneo
      await speakWordPromise(letterObj.char, 'en-US', true);

      // Si completó la palabra
      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
        setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || showRevelation || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
    setRandomJitters([...randomJitters, Math.random() * 0.1]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();

    if (!isActuallyCorrect) {
      // Guardar error en store de forma silenciosa
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
      // Permitir que el niño corrija
      setIsAudioLocked(false);
      return; 
    }

    // --- FASE 3: REVELACIÓN Y ECO ---
    setIsAudioLocked(true); // Mantener bloqueado para la coreografía

    // 1. Pausa dramática (500ms)
    await new Promise(resolve => setTimeout(resolve, 500));

    if (!isMounted.current) return;

    // 2. Revelación Visual
    setShowRevelation(true); 

    // 3. Ciclo de Audio Triple
    // 3.1 Pronuncia palabra completa
    await speakWordPromise(currentWord.original, 'en-US', true);
    await new Promise(resolve => setTimeout(resolve, 300));

    // 3.2 Deletreo rítmico
    const letters = currentWord.original.split('');
    for (const char of letters) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
        await new Promise(resolve => setTimeout(resolve, 150));
    }
    await new Promise(resolve => setTimeout(resolve, 400));

    // 3.3 Palabra completa final (Cierre)
    await speakWordPromise(currentWord.original, 'en-US', false);

    // Al terminar la secuencia, el botón Siguiente ya está visible por showRevelation
  };

  const nextWord = () => {
    window.speechSynthesis.cancel();
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      {/* Capas de Fondo */}
      <div className="absolute inset-0 bg-white/10 backdrop-blur-3xl pointer-events-none"></div>

      {/* Botón Salir */}
      <button 
        onClick={() => {
            window.speechSynthesis.cancel();
            onExit();
        }}
        className="fixed top-4 right-4 z-50 w-12 h-12 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-500 shadow-sm active:bg-white/40 active:scale-90 transition-all mt-[env(safe-area-inset-top)]"
      >
        <span className="text-xl font-bold">✕</span>
      </button>

      {/* Contenido Principal */}
      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">

        {/* Zona Superior */}
        <div className="flex flex-col items-center justify-center pt-8 w-full">
            <button 
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl shadow-slate-200/50 transition-all mb-6
                ${isAudioLocked ? 'opacity-50 scale-95 cursor-not-allowed' : 'active:scale-90'}
              `}
            >
              <span className="text-4xl">🔊</span>
            </button>

            {/* Revelación */}
            <div className="h-24 w-full flex items-center justify-center px-4">
              {showRevelation ? (
                <div className="animate-in fade-in zoom-in-95 duration-700 text-center w-full max-w-sm">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 mb-1 uppercase tracking-[0.1em] drop-shadow-sm">
                    {currentWord.original}
                  </h2>
                  <div className="bg-white/70 backdrop-blur-md px-4 py-2 rounded-2xl shadow-sm border border-white/40 inline-block">
                    <p className="text-lg italic text-slate-700 font-elegant font-medium leading-tight">
                      {getMeaning(currentWord.original)}
                    </p>
                  </div>
                </div>
              ) : (
                <div className="opacity-0">.</div>
              )}
            </div>
        </div>

        {/* Zona Slots (Fase 2: Validación Silenciosa) */}
        <div className="flex gap-2 flex-wrap justify-center px-2 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div 
              key={i}
              onClick={() => handleSlotClick(i)}
              style={{ 
                animationDelay: !char ? `${i * 0.08}s` : '0s' 
              }}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (
                  !isCorrectSoFar 
                    ? 'bg-rose-50 border-rose-200 text-rose-500' // Rojo Suave
                    : 'bg-white border-slate-100 shadow-lg text-slate-800'
                ) : 'bg-slate-900/5 border-dashed border-slate-300/50'}
                ${!char ? 'animate-bounce-drop' : 'animate-in fade-in'}
              `}
            >
              {char}
            </div>
          ))}
        </div>

        {/* Zona Banco (Fase 1: Liberación / Glow) */}
        <div className={`w-full px-4 pb-8 sm:pb-12 flex gap-2 sm:gap-3 flex-wrap justify-center items-end min-h-[100px] transition-opacity duration-300 ${isAudioLocked && !showRevelation ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => {
            const delayTime = 0.6 + (i * 0.06) + (randomJitters[i] || 0);
            return (
              <button
                key={letterObj.id}
                onClick={() => handleLetterClick(letterObj, i)}
                disabled={isAudioLocked}
                style={{ 
                  animationDelay: `${delayTime.toFixed(2)}s`,
                }}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-100
                  animate-bounce-drop
                  ${isReadyToPlay ? 'animate-glow-signal border-emerald-100' : ''}
                  ${!isAudioLocked ? 'active:scale-90 active:bg-slate-100' : ''}
                `}
              >
                {letterObj.char}
              </button>
            );
          })}
        </div>
      </div>

      {/* Fase 4: Transición de Agencia */}
      {showRevelation && (
        <button 
          onClick={(e) => {
            e.stopPropagation();
            nextWord();
          }}
          className="fixed bottom-8 right-6 z-50 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200/50 flex items-center justify-center animate-in slide-in-from-right-20 zoom-in duration-500 active:scale-90 active:bg-emerald-600 transition-all border-4 border-white/20 mb-[env(safe-area-inset-bottom)]"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}

    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { WordList, Word } from '../types';
import { speakWordPromise } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  list: WordList;
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ list, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);

  // ESTADOS DE FASE Y VALIDACIÓN
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [attempts, setAttempts] = useState(0);

  // Refs para control de montaje
  const isMounted = useRef(true);
  const [randomJitters, setRandomJitters] = useState<number[]>([]);

  const currentWord = useMemo(() => {
    return list.words[currentIndex];
  }, [list, currentIndex]);

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  const initWord = async () => {
    // FASE 1: EL ESTÍMULO
    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setIsTransitioning(false);
    setValidationStatus('none');
    setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    // Asegurar que no salga la palabra armada por azar
    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    // Preparar slots vacíos
    setSlots(new Array(currentWord.original.length).fill(null));
    setRandomJitters(shuffled.map(() => Math.random() * 0.1));

    // --- SECUENCIA DE CAÍDA Y DELETREO ---
    // Dejamos un pequeño delay inicial para que el niño vea la pantalla limpia
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;

    // Seteamos las letras para que empiecen sus animaciones de caída
    setAvailableLetters(shuffled);

    // Deletreo rítmico durante la caída
    for (const charObj of shuffled) {
      if (!isMounted.current) return;
      await speakWordPromise(charObj.char, 'en-US', false);
      await new Promise(resolve => setTimeout(resolve, 200)); 
    }

    // Pausa tras la última letra
    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    // Palabra completa al aterrizar (Legato)
    await speakWordPromise(currentWord.original, 'en-US', true);

    // LIBERACIÓN
    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;

    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      const newJitters = [...randomJitters];
      newJitters.splice(index, 1);
      setRandomJitters(newJitters);

      // Feedback fonémico instantáneo
      await speakWordPromise(letterObj.char, 'en-US', true);

      // Comprobar si se llenaron todos los huecos
      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;

    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); // Resetear estado de error si quita una letra

    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
    setRandomJitters([...randomJitters, Math.random() * 0.1]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();

    if (isActuallyCorrect) {
      // FASE 3: ÉXITO
      setValidationStatus('correct');
      setIsAudioLocked(true);

      await new Promise(resolve => setTimeout(resolve, 500));
      if (!isMounted.current) return;

      setShowRevelation(true);

      // Ciclo Triple: Palabra -> Deletreo -> Palabra
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));

      const letters = currentWord.original.split('');
      for (const char of letters) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
        await new Promise(resolve => setTimeout(resolve, 150));
      }
      await new Promise(resolve => setTimeout(resolve, 500));

      await speakWordPromise(currentWord.original, 'en-US', false);
      setIsAudioLocked(false); // Desbloquear para permitir avanzar

    } else {
      // B: INCORRECTO
      setValidationStatus('incorrect');
      setAttempts(prev => prev + 1);
      setIsAudioLocked(false);

      // Guardar error en store (silencioso)
      const allLists = loadLists();
      const listToUpdate = allLists.find(l => l.id === list.id);
      if (listToUpdate) {
        const wordInStore = listToUpdate.words.find(w => w.id === currentWord.id);
        if (wordInStore) wordInStore.errors += 1;
        saveLists(allLists);
      }
    }
  };

  const nextWord = () => {
    window.speechSynthesis.cancel();
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < list.words.length - 1) {
        setCurrentIndex(currentIndex + 1);
      } else {
        onExit();
      }
    }, 600);
  };

  // Determinar si debemos mostrar el botón de escape (flecha verde)
  const showNextButton = validationStatus === 'correct' || (validationStatus === 'incorrect' && attempts >= 2);

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden touch-none transition-all duration-700 ease-in-out ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}
         style={{ 
           backgroundImage: list.backgroundImage ? `url(${list.backgroundImage})` : 'none',
           backgroundSize: 'cover',
           backgroundPosition: 'center'
         }}>

      <div className="absolute inset-0 bg-white/10 backdrop-blur-3xl pointer-events-none"></div>

      <button 
        onClick={() => { window.speechSynthesis.cancel(); onExit(); }}
        className="fixed top-4 right-4 z-50 w-12 h-12 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-500 shadow-sm active:bg-white/40 active:scale-90 transition-all mt-[env(safe-area-inset-top)]"
      >
        <span className="text-xl font-bold">✕</span>
      </button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">

        {/* Zona Superior */}
        <div className="flex flex-col items-center justify-center pt-8 w-full">
            <button 
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl shadow-slate-200/50 transition-all mb-6
                ${isAudioLocked ? 'opacity-50 scale-95 cursor-not-allowed' : 'active:scale-90'}
              `}
            >
              <span className="text-4xl">🔊</span>
            </button>

            {/* Revelación Visual */}
            <div className="h-24 w-full flex items-center justify-center px-4 text-center">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 w-full max-w-sm">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 mb-1 uppercase tracking-[0.1em]">
                    {currentWord.original}
                  </h2>
                  <div className="bg-white/70 backdrop-blur-md px-4 py-2 rounded-2xl shadow-sm border border-white/40 inline-block">
                    <p className="text-lg italic text-slate-700 font-elegant font-medium leading-tight">
                      {getMeaning(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 duration-300">
                  <div className="bg-rose-100/80 backdrop-blur-md px-6 py-2 rounded-full border border-rose-200 shadow-sm">
                    <p className="text-rose-600 font-bold tracking-wide">Intenta de nuevo</p>
                  </div>
                </div>
              )}
            </div>
        </div>

        {/* Zona Slots */}
        <div className="flex gap-2 flex-wrap justify-center px-2 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div 
              key={i}
              onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (
                  validationStatus === 'incorrect'
                    ? 'bg-rose-50 border-rose-200 text-rose-500' // Rojo suave
                    : validationStatus === 'correct'
                    ? 'bg-emerald-50 border-emerald-200 text-emerald-600' // Verde suave
                    : 'bg-white border-slate-100 shadow-lg text-slate-800'
                ) : 'bg-slate-900/5 border-dashed border-slate-300/50'}
                ${!char ? 'animate-bounce-drop' : 'animate-in fade-in'}
              `}
            >
              {char}
            </div>
          ))}
        </div>

        {/* Zona Banco */}
        <div className={`w-full px-4 pb-12 sm:pb-16 flex gap-2 sm:gap-3 flex-wrap justify-center items-end min-h-[100px] transition-opacity duration-300 ${isAudioLocked && !showNextButton && validationStatus !== 'incorrect' ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {validationStatus !== 'correct' && availableLetters.map((letterObj, i) => {
            return (
              <button
                key={letterObj.id}
                onClick={() => handleLetterClick(letterObj, i)}
                disabled={isAudioLocked}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-[0_8px_30px_rgb(0,0,0,0.12)] flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-100
                  animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'animate-glow-signal border-emerald-100' : ''}
                  ${!isAudioLocked ? 'active:scale-90 active:bg-slate-100' : ''}
                `}
              >
                {letterObj.char}
              </button>
            );
          })}
        </div>
      </div>

      {/* Botón de Avance (Fase 4: Transición de Agencia) */}
      {showNextButton && (
        <button 
          onClick={(e) => { e.stopPropagation(); nextWord(); }}
          className="fixed bottom-10 right-8 z-[60] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl shadow-emerald-200/50 flex items-center justify-center animate-in slide-in-from-right-20 zoom-in duration-500 active:scale-90 active:bg-emerald-600 transition-all border-4 border-white/20 mb-[env(safe-area-inset-bottom)]"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}

    </div>
  );
};

