                    <span className="text-[10px] font-bold text-slate-400 uppercase mb-3">Velocidad</span>
                    <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => updateVoiceSettings({...voiceSettings, rate: parseFloat(e.target.value)})} className="w-full accent-slate-800" />
                    <div className="flex justify-between w-full text-sm mt-1 px-1"><span>🐢</span><span>🐇</span></div>
                  </div>
                  <div className="flex-1 bg-slate-50 rounded-2xl p-4 flex flex-col items-center">
                    <span className="text-[10px] font-bold text-slate-400 uppercase mb-3">Tono</span>
                    <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => updateVoiceSettings({...voiceSettings, pitch: parseFloat(e.target.value)})} className="w-full accent-slate-800" />
                    <div className="flex justify-between w-full text-[10px] mt-2 px-1 text-slate-400 font-bold uppercase"><span>Grave</span><span>Agudo</span></div>
                  </div>
                </div>
                <div className="space-y-3 mt-auto">
                  <button onClick={handleTestVoice} className="w-full bg-emerald-50 text-emerald-600 font-bold py-3 rounded-xl flex items-center justify-center gap-2"><span>▶️</span> Probar Audio</button>
                  <button onClick={() => setIsVoiceStudioOpen(false)} className="w-full py-3 text-slate-400 font-bold">Listo</button>
                </div>
              </>
            ) : (
              <>
                <div className="flex items-center gap-3 mb-4">
                  <button onClick={() => setVoiceViewMode('settings')} className="w-10 h-10 rounded-full bg-slate-100 text-slate-500 flex items-center justify-center transition-all">←</button>
                  <h2 className="text-xl font-elegant font-bold text-slate-800">Top 10 Voces USA</h2>
                </div>
                <div className="flex-1 overflow-y-auto space-y-2 pr-1 mb-4">
                   {availableVoices.map(voice => {
                     const isPremium = isPremiumVoice(voice);
                     const isActive = voiceSettings.voiceURI === voice.voiceURI;
                     return (
                        <div key={voice.voiceURI} onClick={() => { updateVoiceSettings({...voiceSettings, voiceURI: voice.voiceURI}); setVoiceViewMode('settings'); }}
                           className={`p-4 rounded-2xl border transition-all cursor-pointer flex items-center justify-between ${isActive ? 'bg-slate-900 text-white border-slate-900 shadow-lg' : 'bg-white border-slate-100 text-slate-600 hover:bg-slate-50'}`}>
                           <div className="flex items-center gap-3 overflow-hidden">
                              <span className="text-xl">{isPremium ? '🌟' : '🗣️'}</span>
                              <div className="flex flex-col min-w-0">
                                 <span className="font-bold text-sm truncate">{voice.name.replace(/Microsoft|Google|English|United States|en-US/g, '').trim()}</span>
                                 <span className={`text-[10px] ${isActive ? 'text-slate-400' : 'text-slate-300'}`}>Natural English (USA)</span>
                              </div>
                           </div>
                           {isActive && <span className="text-emerald-400">●</span>}
                        </div>
                     );
                   })}
                </div>
                <div className="bg-slate-50 p-3 rounded-xl text-center"><p className="text-[10px] text-slate-400 leading-relaxed font-bold uppercase tracking-widest">Exclusivo Spelling Bee Edition</p></div>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

