import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  backgroundImage?: string;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, backgroundImage, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; };
  }, []);

  const initWord = async () => {
    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setIsTransitioning(false);
    setValidationStatus('none');
    setShowNextButton(false);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);
    await speakWordPromise(currentWord.original, 'en-US', true);

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      await speakWordPromise(letterObj.char, 'en-US', true);
      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true);

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      await new Promise(resolve => setTimeout(resolve, 500));
      if (!isMounted.current) return;
      setShowRevelation(true);
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 300));
      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }
      await speakWordPromise(currentWord.original, 'en-US', false);
      if (isMounted.current) { setShowNextButton(true); setIsAudioLocked(false); }
    } else {
      setValidationStatus('incorrect');
      const allLists = loadLists();
      const targetList = allLists.find(l => l.id === listId);
      if (targetList) {
        const wordInMain = targetList.words.find(w => w.original === currentWord.original);
        if (wordInMain) wordInMain.errors += 1;
        saveLists(allLists);
      }
      await speakWordPromise(currentWord.original, 'en-US', true);
      if (isMounted.current) { setShowNextButton(true); setIsAudioLocked(false); }
    }
  };

  const nextWord = () => {
    window.speechSynthesis.cancel();
    setIsTransitioning(true);
    setTimeout(() => {
      if (currentIndex < words.length - 1) setCurrentIndex(currentIndex + 1);
      else onExit();
    }, 600);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-700 ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>
      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/10' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { window.speechSynthesis.cancel(); onExit(); }} className="fixed top-4 right-4 z-50 w-12 h-12 flex items-center justify-center bg-white/20 backdrop-blur-md rounded-full text-slate-500 shadow-sm mt-[env(safe-area-inset-top)]">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8">
            <button onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/60 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-50 scale-95' : 'active:scale-90'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-24 px-4 text-center flex flex-col items-center">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 uppercase tracking-widest">{currentWord.original}</h2>
                  <p className="text-sm italic text-slate-500 font-elegant mt-1">{getMeaning(currentWord.original)}</p>
                </div>
              )}
              {validationStatus === 'incorrect' && <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100 rounded-full border border-rose-200 text-rose-600 font-bold">Try again</div>}
              {mode === 'repaso' && !showRevelation && <span className="text-[10px] font-bold text-indigo-400 uppercase tracking-[0.3em] mt-2">Repaso de Maestría</span>}
            </div>
        </div>

        <div className="flex gap-2 flex-wrap justify-center px-4 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char}
            </div>
          ))}
        </div>

        <div className={`w-full px-4 pb-16 flex gap-2 flex-wrap justify-center items-end min-h-[100px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {validationStatus !== 'correct' && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-100 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'animate-glow-signal border-emerald-100' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button onClick={nextWord} className="fixed bottom-10 right-8 w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)]">
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4"><line x1="5" y1="12" x2="19" y2="12"></line><polyline points="12 5 19 12 12 19"></polyline></svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect } from 'react';
import ParentDashboard from './components/ParentDashboard';
import GameScreen from './components/GameScreen';
import { loadLists, prepareSession } from './store';
import { Word, GameSession } from './types';

const App: React.FC = () => {
  const [role, setRole] = useState<'parent' | 'child'>('parent');
  const [activeSession, setActiveSession] = useState<GameSession | null>(null);

  useEffect(() => {
    document.body.style.overflow = 'hidden';
    document.body.style.position = 'fixed';
    document.body.style.width = '100%';
    document.body.style.height = '100%';
    const handleContextMenu = (e: MouseEvent) => e.preventDefault();
    if (role === 'child') window.addEventListener('contextmenu', handleContextMenu);
    return () => { window.removeEventListener('contextmenu', handleContextMenu); };
  }, [role]);

  const handleStartGame = (listId: string, mode: 'normal' | 'repaso') => {
    const list = loadLists().find(l => l.id === listId);
    if (list) {
      const wordsForSession = prepareSession(list, mode);
      setActiveSession({
        listId,
        words: wordsForSession,
        mode
      });
      setRole('child');
    }
  };

  const activeList = activeSession ? loadLists().find(l => l.id === activeSession.listId) : null;

  if (role === 'child' && activeSession && activeList) {
    return (
      <GameScreen 
        listId={activeSession.listId}
        words={activeSession.words}
        backgroundImage={activeList.backgroundImage}
        mode={activeSession.mode}
        onExit={() => setActiveSession(null)} 
      />
    );
  }

  return (
    <div className="min-h-screen bg-[#fdfdfe] text-slate-900 font-sans overflow-y-auto pb-32">
      <ParentDashboard 
        role={role}
        onStartGame={handleStartGame} 
      />
      <div className="fixed bottom-10 left-1/2 -translate-x-1/2 z-50 flex items-center gap-5">
        <span className={`text-xs font-elegant font-bold tracking-[0.2em] w-32 text-right transition-colors duration-300 ${role === 'child' ? 'text-emerald-600' : 'text-slate-400'}`}>
          {role === 'parent' ? 'MODO PADRE' : 'MODO NIÑO'}
        </span>
        <button onClick={() => setRole(role === 'parent' ? 'child' : 'parent')}
          className={`w-14 h-8 rounded-full relative transition-colors duration-300 shadow-sm active:scale-95 ${role === 'child' ? 'bg-emerald-500' : 'bg-slate-300'}`}>
          <div className={`absolute top-1 left-1 w-6 h-6 rounded-full bg-white shadow-md transform transition-transform duration-300 ease-out ${role === 'child' ? 'translate-x-6' : 'translate-x-0'}`} />
        </button>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise } from '../geminiService';
import { getMeaning, saveLists, loadLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  backgroundImage?: string;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, backgroundImage, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      window.speechSynthesis.cancel();
    };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;

    // Reset inmediato de estados críticos
    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setValidationStatus('none');
    setShowNextButton(false);
    setIsTransitioning(false);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    // Evitar que salga ya armada por azar
    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));

    // Pequeña pausa para que la transición de entrada respire
    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);

    // Pronunciar palabra con fallback
    try {
      await Promise.race([
        speakWordPromise(currentWord.original, 'en-US', true),
        new Promise(resolve => setTimeout(resolve, 3500)) // Fallback 3.5s
      ]);
    } catch (e) {
      console.warn("Speech synthesis timeout or error");
    }

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex, listId]); // Dependencia de listId por si cambia la sesión

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      try {
        await Promise.race([
          speakWordPromise(letterObj.char, 'en-US', true),
          new Promise(resolve => setTimeout(resolve, 1000))
        ]);
      } catch(e) {}

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true);

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      await new Promise(resolve => setTimeout(resolve, 500));
      if (!isMounted.current) return;

      setShowRevelation(true);

      // Secuencia de éxito: Palabra -> Deletreo -> Palabra
      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
        await new Promise(resolve => setTimeout(resolve, 300));
        for (const char of currentWord.original.split('')) {
          if (!isMounted.current) return;
          await speakWordPromise(char, 'en-US', false);
        }
        await speakWordPromise(currentWord.original, 'en-US', false);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    } else {
      setValidationStatus('incorrect');

      // Registrar error en la lista persistente
      const allLists = loadLists();
      const targetList = allLists.find(l => l.id === listId);
      if (targetList) {
        const wordInMain = targetList.words.find(w => w.original === currentWord.original);
        if (wordInMain) wordInMain.errors += 1;
        saveLists(allLists);
      }

      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    window.speechSynthesis.cancel();
    setIsTransitioning(true);

    // Esperar a que la animación de fade-out termine
    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { window.speechSynthesis.cancel(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8">
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/70 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/50'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-24 px-4 text-center flex flex-col items-center justify-center">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700">
                  <h2 className="text-3xl font-elegant font-bold text-slate-800 uppercase tracking-widest">{currentWord.original}</h2>
                  <p className="text-sm italic text-slate-500 font-elegant mt-1">{getMeaning(currentWord.original)}</p>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100/80 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold shadow-sm">
                  Try again
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.3em] mt-2 animate-pulse">Modo Repaso</span>
              )}
            </div>
        </div>

        <div className="flex gap-2 flex-wrap justify-center px-4 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char}
            </div>
          ))}
        </div>

        <div className={`w-full px-4 pb-20 flex gap-2 flex-wrap justify-center items-end min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {validationStatus !== 'correct' && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import { GoogleGenAI, Modality } from "@google/genai";
import { loadVoiceSettings } from "./store";

// Caché para almacenar audio (base64) y evitar llamadas repetitivas a la API
const audioCache: Record<string, string> = {};

export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting. Blurred and fantasy effects.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

// --- VOICE & AUDIO LOGIC ---

/**
 * Decodifica y reproduce audio en Base64 usando Web Audio API.
 * Esto es necesario para iOS donde el autoplay es estricto.
 */
const playBase64Audio = async (base64String: string): Promise<void> => {
  return new Promise((resolve, reject) => {
    try {
      const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
      const audioData = atob(base64String);
      const arrayBuffer = new ArrayBuffer(audioData.length);
      const view = new Uint8Array(arrayBuffer);

      for (let i = 0; i < audioData.length; i++) {
        view[i] = audioData.charCodeAt(i);
      }

      audioContext.decodeAudioData(arrayBuffer, (buffer) => {
        const source = audioContext.createBufferSource();
        source.buffer = buffer;
        source.connect(audioContext.destination);
        source.onended = () => {
           audioContext.close();
           resolve();
        };
        source.start(0);
      }, (err) => {
        console.error("Error decoding audio", err);
        reject(err);
      });
    } catch (e) {
      console.error("Audio playback error", e);
      reject(e);
    }
  });
};

/**
 * Genera voz usando Gemini TTS para calidad humana.
 */
const playGeminiTTS = async (text: string): Promise<boolean> => {
  // 1. Revisar Caché
  const cacheKey = text.toLowerCase().trim();
  if (audioCache[cacheKey]) {
    await playBase64Audio(audioCache[cacheKey]);
    return true;
  }

  // 2. Llamar API
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              // 'Kore' es una voz femenina clara y amable, buena para niños
              prebuiltVoiceConfig: { voiceName: 'Kore' },
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      audioCache[cacheKey] = base64Audio; // Guardar en caché
      await playBase64Audio(base64Audio);
      return true;
    }
    return false;
  } catch (error) {
    console.warn("Gemini TTS failed, falling back to browser voice:", error);
    return false;
  }
};


/**
 * Filtra y devuelve el Top 10 de voces más naturales exclusivamente de USA (en-US).
 */
export const getTopUSAVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];

  const allVoices = window.speechSynthesis.getVoices();
  const usVoices = allVoices.filter(v => v.lang.toLowerCase().replace('_', '-') === 'en-us');

  const sortedVoices = [...usVoices].sort((a, b) => {
    const aIsPremium = isPremiumVoice(a) ? 1 : 0;
    const bIsPremium = isPremiumVoice(b) ? 1 : 0;
    return bIsPremium - aIsPremium; 
  });

  return sortedVoices.slice(0, 10);
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || 
         name.includes('premium') || 
         name.includes('enhanced') || 
         name.includes('siri') || 
         name.includes('natural') ||
         name.includes('neural');
};

const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null, lang: string } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null, lang: 'en-US' };

  const voices = window.speechSynthesis.getVoices();

  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice, lang: userVoice.lang };
  }

  const usPremium = voices.find(v => v.lang.toLowerCase().replace('_', '-') === 'en-us' && isPremiumVoice(v));
  if (usPremium) return { voice: usPremium, lang: usPremium.lang };

  const us = voices.find(v => v.lang.toLowerCase().replace('_', '-') === 'en-us');
  if (us) return { voice: us, lang: 'en-US' };

  return { voice: null, lang: 'en-US' }; 
};

/**
 * Función principal para hablar.
 * 1. Intenta Gemini TTS (Calidad Humana)
 * 2. Si falla o es solo una letra suelta (deletreo), usa Web Speech API (Fallback)
 */
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise(async (resolve) => {
    if (typeof window === 'undefined') {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);

    // ESTRATEGIA: Usar Gemini SOLO para palabras completas (no deletreo) para ahorrar latencia y costos.
    // El deletreo funciona bien con la voz robótica, pero la palabra completa necesita calidad.
    if (!isSingleLetter) {
        const success = await playGeminiTTS(word);
        if (success) {
            resolve();
            return;
        }
    }

    // --- FALLBACK: BROWSER SPEECH SYNTHESIS ---

    if (!window.speechSynthesis) {
        resolve();
        return;
    }

    const settings = loadVoiceSettings();
    const { voice, lang: voiceLang } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance();

    let textToSpeak = word;

    if (voice) {
      utterance.voice = voice;
      utterance.lang = voiceLang;
      const baseRate = settings.rate;

      if (isSingleLetter) {
        utterance.rate = Math.max(0.5, baseRate - 0.1);
        utterance.pitch = settings.pitch;
      } else {
        utterance.rate = Math.max(0.65, baseRate * 0.9); 
        utterance.pitch = Math.max(0.8, settings.pitch * 0.95);
        textToSpeak = `${word}...`;
      }
    } else {
      utterance.lang = 'en-US';
      utterance.rate = 0.75; 
      if (!isSingleLetter) {
        textToSpeak = `${word}...`;
      }
    }

    utterance.text = textToSpeak;

    utterance.onend = () => resolve();
    utterance.onerror = () => resolve();

    const safetyTimeout = setTimeout(() => resolve(), 5000);
    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

