        await Promise.race([
          speakWordPromise(letterObj.char, 'en-US', true),
          new Promise(resolve => setTimeout(resolve, 1000))
        ]);
      } catch(e) {}

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true);

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      await new Promise(resolve => setTimeout(resolve, 500));
      if (!isMounted.current) return;

      setShowRevelation(true);

      // Secuencia de éxito: Palabra -> Deletreo -> Palabra
      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
        await new Promise(resolve => setTimeout(resolve, 300));
        for (const char of currentWord.original.split('')) {
          if (!isMounted.current) return;
          await speakWordPromise(char, 'en-US', false);
        }
        await speakWordPromise(currentWord.original, 'en-US', false);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    } else {
      setValidationStatus('incorrect');

      // Registrar error en la lista persistente
      const allLists = loadLists();
      const targetList = allLists.find(l => l.id === listId);
      if (targetList) {
        const wordInMain = targetList.words.find(w => w.original === currentWord.original);
        if (wordInMain) wordInMain.errors += 1;
        saveLists(allLists);
      }

      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    window.speechSynthesis.cancel();
    setIsTransitioning(true);

    // Esperar a que la animación de fade-out termine
    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { window.speechSynthesis.cancel(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8">
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/70 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/50'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-32 px-4 text-center flex flex-col items-center justify-start w-full max-w-lg">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center">
                  <h2 className="text-3xl sm:text-4xl font-elegant font-bold text-slate-800 uppercase tracking-widest mb-2">{currentWord.original}</h2>
                  <div className="bg-white/40 backdrop-blur-sm rounded-xl p-3 border border-white/50 shadow-sm">
                    <p className="text-base font-semibold text-slate-700 leading-snug">{getMeaning(currentWord.original)}</p>
                    <p className="text-xs text-slate-500 mt-1 flex items-center justify-center gap-1">
                      <span className="opacity-50">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100/80 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold shadow-sm">
                  Try again
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.3em] mt-2 animate-pulse">Modo Repaso</span>
              )}
            </div>
        </div>

        <div className="flex gap-2 flex-wrap justify-center px-4 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char}
            </div>
          ))}
        </div>

        <div className={`w-full px-4 pb-20 flex gap-2 flex-wrap justify-center items-end min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {validationStatus !== 'correct' && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

