import { GoogleGenAI, Modality } from "@google/genai";
import { loadVoiceSettings } from "./store";

// Caché para almacenar audio (Float32Array) y evitar llamadas repetitivas
const audioCache: Record<string, Float32Array> = {};

// Singleton AudioContext para iOS
let globalAudioContext: AudioContext | null = null;
let currentSource: AudioBufferSourceNode | null = null;

// Inicializar AudioContext (Debe llamarse tras una interacción de usuario)
export const initAudioContext = () => {
  if (!globalAudioContext) {
    const AudioCtor = window.AudioContext || (window as any).webkitAudioContext;
    globalAudioContext = new AudioCtor();
  }
  if (globalAudioContext.state === 'suspended') {
    globalAudioContext.resume().catch(console.error);
  }
};

export const generateBackgroundImage = async (theme: string): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            text: `A minimalist, dreamy, and high-quality artistic background for a children's educational app. Theme: ${theme}. Style: Soft watercolor, pastel colors, elegant, non-distracting. Blurred and fantasy effects.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "16:9"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

// --- AUDIO DECODING UTILS (RAW PCM) ---

const decodeBase64ToPCM = (base64: string): Float32Array => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  // Gemini devuelve PCM 16-bit Little Endian
  const int16 = new Int16Array(bytes.buffer);
  const float32 = new Float32Array(int16.length);

  // Normalizar a rango -1.0 a 1.0 para Web Audio API
  for (let i = 0; i < int16.length; i++) {
    float32[i] = int16[i] / 32768.0;
  }
  return float32;
};

const playPCMData = async (pcmData: Float32Array): Promise<void> => {
  initAudioContext();
  if (!globalAudioContext) return;

  // Detener audio anterior si existe
  if (currentSource) {
    try { currentSource.stop(); } catch(e) {}
  }

  // Gemini TTS output es 24000Hz Mono
  const sampleRate = 24000;
  const buffer = globalAudioContext.createBuffer(1, pcmData.length, sampleRate);
  buffer.getChannelData(0).set(pcmData);

  const source = globalAudioContext.createBufferSource();
  source.buffer = buffer;
  source.connect(globalAudioContext.destination);
  currentSource = source;

  return new Promise((resolve) => {
    source.onended = () => {
      currentSource = null;
      resolve();
    };
    source.start(0);
  });
};

export const stopAudio = () => {
  if (typeof window !== 'undefined' && window.speechSynthesis) {
    window.speechSynthesis.cancel();
  }
  if (currentSource) {
    try { currentSource.stop(); } catch(e) {}
    currentSource = null;
  }
};

/**
 * Genera voz usando Gemini TTS para calidad humana.
 */
const playGeminiTTS = async (text: string): Promise<boolean> => {
  const cacheKey = text.toLowerCase().trim();

  // 1. Revisar Caché
  if (audioCache[cacheKey]) {
    await playPCMData(audioCache[cacheKey]);
    return true;
  }

  // 2. Llamar API
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: text }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: 'Kore' }, // 'Kore' es excelente para educación
            },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (base64Audio) {
      const pcmData = decodeBase64ToPCM(base64Audio);
      audioCache[cacheKey] = pcmData;
      await playPCMData(pcmData);
      return true;
    }
    return false;
  } catch (error) {
    console.warn("Gemini TTS failed, falling back to browser voice:", error);
    return false;
  }
};


// --- BROWSER FALLBACK LOGIC ---

export const getTopUSAVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];
  const allVoices = window.speechSynthesis.getVoices();
  const usVoices = allVoices.filter(v => v.lang.toLowerCase().replace('_', '-') === 'en-us');
  const sortedVoices = [...usVoices].sort((a, b) => {
    const aIsPremium = isPremiumVoice(a) ? 1 : 0;
    const bIsPremium = isPremiumVoice(b) ? 1 : 0;
    return bIsPremium - aIsPremium; 
  });
  return sortedVoices.slice(0, 10);
};

export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return name.includes('google') || name.includes('premium') || name.includes('enhanced') || name.includes('siri') || name.includes('natural') || name.includes('neural');
};

const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null, lang: string } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null, lang: 'en-US' };
  const voices = window.speechSynthesis.getVoices();
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice, lang: userVoice.lang };
  }
  const usPremium = voices.find(v => v.lang.toLowerCase().replace('_', '-') === 'en-us' && isPremiumVoice(v));
  if (usPremium) return { voice: usPremium, lang: usPremium.lang };
  const us = voices.find(v => v.lang.toLowerCase().replace('_', '-') === 'en-us');
  if (us) return { voice: us, lang: 'en-US' };
  return { voice: null, lang: 'en-US' }; 
};

export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise(async (resolve) => {
    if (typeof window === 'undefined') {
      resolve();
      return;
    }

    if (interrupt) {
      stopAudio(); // Detiene tanto WebAudio como SpeechSynthesis
    }

    // Inicializar AudioContext si no está activo (especialmente para iOS)
    initAudioContext();

    const isSingleLetter = word.length === 1 && /^[a-zA-Z]$/.test(word);

    // INTENTO 1: GEMINI TTS (Solo palabras completas)
    if (!isSingleLetter) {
        const success = await playGeminiTTS(word);
        if (success) {
            resolve();
            return;
        }
    }

    // INTENTO 2: FALLBACK NAVEGADOR
    if (!window.speechSynthesis) {
        resolve();
        return;
    }

    const settings = loadVoiceSettings();
    const { voice, lang: voiceLang } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance();

    let textToSpeak = word;

    if (voice) {
      utterance.voice = voice;
      utterance.lang = voiceLang;
      const baseRate = settings.rate;
      if (isSingleLetter) {
        utterance.rate = Math.max(0.5, baseRate - 0.1);
        utterance.pitch = settings.pitch;
      } else {
        utterance.rate = Math.max(0.65, baseRate * 0.9); 
        utterance.pitch = Math.max(0.8, settings.pitch * 0.95);
        textToSpeak = `${word}...`;
      }
    } else {
      utterance.lang = 'en-US';
      utterance.rate = 0.75; 
      if (!isSingleLetter) {
        textToSpeak = `${word}...`;
      }
    }

    utterance.text = textToSpeak;
    utterance.onend = () => resolve();
    utterance.onerror = () => resolve();
    window.speechSynthesis.speak(utterance);
  });
};

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
