    }
  }, []);

  const handleStartGameWrapper = (listId: string, mode: 'normal' | 'repaso') => {
    // CRÍTICO PARA IOS: Inicializar audio en la interacción del usuario
    initAudioContext();
    onStartGame(listId, mode);
  };

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    setIsLoadingImage(true);
