                <h2 className="text-2xl font-elegant font-bold text-slate-800 text-center mb-6">Voz USA</h2>
                <button onClick={() => setVoiceViewMode('list')} className="w-full mb-6 p-4 rounded-2xl border border-slate-100 bg-white hover:bg-slate-50 flex items-center justify-between">
