export const stopAudio = () => {
  if (typeof window !== 'undefined' && window.speechSynthesis) {
    window.speechSynthesis.cancel();
  }
};

/**
 * Detecta si una voz es de alta calidad basándose en palabras clave del sistema.
 */
export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return (
    name.includes('google') || 
    name.includes('premium') || 
    name.includes('enhanced') || 
    name.includes('siri') || 
    name.includes('natural') || 
    name.includes('zoe') || 
    name.includes('ava') || 
    name.includes('samantha')
  );
};

/**
 * Algoritmo de "Caza de Voces".
 * Prioriza voces humanas sobre las robóticas (Compact).
 */
export const getTopUSAVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];

  const allVoices = window.speechSynthesis.getVoices();

  // Filtro estricto: Solo inglés de USA
  const usVoices = allVoices.filter(v => v.lang === 'en-US'); // Strict match preferido

  // Si no hay estricto, buscamos laxo (ej. en_US)
  const candidates = usVoices.length > 0 
    ? usVoices 
    : allVoices.filter(v => v.lang.toLowerCase().replace('_', '-').startsWith('en-us'));

  const sortedVoices = [...candidates].sort((a, b) => {
    // Sistema de Puntuación
    const getScore = (v: SpeechSynthesisVoice) => {
      let score = 0;
      const n = v.name.toLowerCase();

      if (n.includes('enhanced') || n.includes('premium')) score += 10; // Apple High Quality
      if (n.includes('google')) score += 8; // Android High Quality
      if (n.includes('samantha') || n.includes('ava') || n.includes('alex')) score += 5; // Nombres conocidos Apple
      if (n.includes('compact')) score -= 5; // Apple Robotic
      return score;
    };

    return getScore(b) - getScore(a);
  });

  return sortedVoices.slice(0, 15);
};

/**
 * Encuentra la mejor voz disponible según configuración o defecto inteligente.
 */
const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null };

  const voices = window.speechSynthesis.getVoices();

  // 1. Preferencia del usuario
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice };
  }

  // 2. Selección automática (Top 1 del algoritmo)
  const topVoices = getTopUSAVoices();
  if (topVoices.length > 0) return { voice: topVoices[0] };

  // 3. Fallback absoluto
  const defaultEn = voices.find(v => v.lang.startsWith('en'));
  return { voice: defaultEn || null };
};

/**
 * Motor principal de habla.
 * Aplica "Maquillaje Auditivo" si detecta que la voz es robótica.
 */
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise((resolve) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const settings = loadVoiceSettings();
    const { voice } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance(word);

    // FORZADO DE IDIOMA ESTRICTO
    utterance.lang = 'en-US'; 

    if (voice) {
      utterance.voice = voice;

      const isRobot = !isPremiumVoice(voice) || voice.name.toLowerCase().includes('compact');
      const isSingleLetter = word.length === 1;

      // --- LOGICA DE MAQUILLAJE AUDITIVO ---
      if (isRobot) {
        // Si es robótica, aumentamos un poco la velocidad para que los "cortes" se noten menos
        // y bajamos el pitch para darle cuerpo.
        utterance.rate = isSingleLetter ? 0.6 : 0.9; 
        utterance.pitch = 0.9; // Un poco más grave oculta lo metálico
      } else {
        // Si es Premium (Humana), usamos la configuración del usuario o los defaults óptimos
        if (isSingleLetter) {
           utterance.rate = Math.max(0.5, settings.rate - 0.2); // Letras lentas y claras
           utterance.pitch = settings.pitch;
        } else {
           // Las palabras completas suenan mejor un poco más lentas para niños (Legato)
           utterance.rate = settings.rate * 0.85; 
           utterance.pitch = settings.pitch;
        }
      }
    }

    // Manejo de eventos para resolver la promesa
    utterance.onend = () => resolve();
    utterance.onerror = (e) => {
      console.warn("Speech error", e);
      resolve(); // Resolvemos igual para no bloquear la app
    };

    // Timeout de seguridad por si el evento onend nunca se dispara (bug común en Android)
    const safetyTimeout = setTimeout(() => {
        resolve();
    }, 4000);

    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { generateBackgroundImage, getTopUSAVoices } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // Estados del Estudio de Voz
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false); // Estado para la guía de ayuda
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setAvailableVoices(getTopUSAVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    setIsLoadingImage(true);
    // Nota: generateBackgroundImage devuelve null actualmente para evitar costes, 
    // pero la lógica se mantiene por si se integra otra solución gratuita.
    let bg = undefined;
    if (theme) bg = await generateBackgroundImage(theme);

    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: extractWords(inputText), backgroundImage: bg || l.backgroundImage } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), backgroundImage: bg || undefined, settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setTheme(''); setEditingListId(null); setIsAdding(false); setIsLoadingImage(false);
  };

  const getVoiceDisplayName = () => {
    if (!voiceSettings.voiceURI) return "Automática (USA)";
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    // Limpieza agresiva del nombre para que se vea bonito en la UI
    return v ? v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim() : "Voz USA";
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');

      const u = new SpeechSynthesisUtterance("I am ready to read.");
      u.voice = voice;
      u.lang = 'en-US';
      u.rate = s.rate;
      u.pitch = s.pitch;
      window.speechSynthesis.cancel();
      window.speechSynthesis.speak(u);
  };

  const isIOS = () => {
    if (typeof window === 'undefined') return false;
    return /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48 animate-in fade-in duration-700">
      <header className="flex flex-col items-center mb-6 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-6"></div>

