            <div className="flex flex-col items-start z-10">
              <span className="text-[10px] font-bold tracking-[0.2em] uppercase opacity-70 mb-1">Entrenamiento Maestro</span>
              <h2 className="text-2xl font-elegant font-bold">ESTUDIO DE REPASO</h2>
