            </div>
            <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center text-2xl group-hover:bg-white/30 transition-colors">🎯</div>
          </button>
        </div>
      )}

      {/* Formulario (Solo Padre) */}
