        isAdding ? (
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4">
            <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Lista' : 'Nueva Lista'}</h2>
            <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg" placeholder="Título" value={newListName} onChange={e => setNewListName(e.target.value)} />
            <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg" placeholder="Palabras..." value={inputText} onChange={e => setInputText(e.target.value)} />
            <div className="flex gap-3">
              <button disabled={isLoadingImage} onClick={handleSaveList} className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold">{isLoadingImage ? 'Guardando...' : 'Guardar'}</button>
              <button onClick={resetForm} className="px-6 rounded-2xl bg-slate-100 text-slate-500 font-bold">×</button>
            </div>
          </div>
        ) : (
          <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all">
            <span className="text-2xl font-light">+</span> Nueva Lista
          </button>
        )
      )}

      {/* Lista de Listas */}
      <div className="space-y-4">
        {lists.map(list => {
          const criticalCount = list.words.filter(w => w.errors >= 2).length;
          const warningCount = list.words.filter(w => w.errors === 1).length;

          return (
            <div key={list.id} onClick={() => role === 'parent' ? (setEditingListId(list.id), setIsAdding(true), setNewListName(list.name), setInputText(list.words.map(w => w.original).join(' '))) : onStartGame(list.id, 'normal')} 
                 className={`bg-white p-4 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer relative ${editingListId === list.id ? 'ring-2 ring-slate-900' : ''}`}>
              <div className="flex items-center gap-4 min-w-0">
                <div className="w-16 h-16 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl shadow-inner overflow-hidden shrink-0">
                  {list.backgroundImage ? <img src={list.backgroundImage} className="w-full h-full object-cover" /> : '📝'}
                </div>
                <div className="min-w-0">
                  <h3 className="text-lg font-bold text-slate-800 leading-tight truncate">{list.name}</h3>
                  <div className="flex gap-2 mt-1">
                    {criticalCount > 0 && <span className="px-2 py-0.5 bg-rose-50 text-rose-500 text-[9px] font-bold rounded-full border border-rose-100 uppercase tracking-widest">⚠️ {criticalCount} críticas</span>}
                    {warningCount > 0 && <span className="px-2 py-0.5 bg-amber-50 text-amber-600 text-[9px] font-bold rounded-full border border-amber-100 uppercase tracking-widest">↻ {warningCount} repaso</span>}
                    {criticalCount === 0 && warningCount === 0 && <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} palabras</span>}
                  </div>
                </div>
              </div>
              <div className="text-slate-300 pr-2">›</div>
            </div>
          );
        })}
      </div>

      {/* Modal: ESTUDIO DE VOZ */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>

          {isHelpOpen ? (
             // --- GUÍA DE AYUDA IOS ---
             <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl relative z-20 animate-in zoom-in-95">
                <h2 className="text-xl font-elegant font-bold text-slate-800 mb-4 text-center">¿Voz robótica en iPhone?</h2>
                <div className="space-y-4 text-sm text-slate-600 leading-relaxed mb-6">
                  <p>Apple incluye voces "Mejoradas" gratuitas pero ocultas. Sigue estos pasos:</p>
                  <ol className="list-decimal pl-5 space-y-2 font-medium">
                    <li>Abre <strong className="text-slate-800">Ajustes</strong> del iPhone.</li>
                    <li>Ve a <strong className="text-slate-800">Accesibilidad</strong> &gt; <strong className="text-slate-800">Contenido Leído</strong>.</li>
                    <li>Entra en <strong className="text-slate-800">Voces</strong> &gt; <strong className="text-slate-800">Inglés</strong>.</li>
                    <li>Busca <strong className="text-indigo-600">Samantha</strong> o <strong className="text-indigo-600">Ava</strong>.</li>
                    <li>Toca la nube para descargar la versión <strong className="text-emerald-600">Premium / Mejorada</strong>.</li>
                  </ol>
                  <p className="text-xs bg-slate-100 p-3 rounded-xl mt-2">
                    Una vez descargada, vuelve aquí y selecciónala en la lista. ¡Sonará humana!
                  </p>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full bg-slate-100 text-slate-500 py-3 rounded-2xl font-bold">Volver</button>
             </div>
          ) : (
            // --- MENÚ PRINCIPAL VOZ ---
            <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-10 flex flex-col max-h-[70vh]">
              {voiceViewMode === 'settings' ? (
                <>
                  <div className="flex items-center justify-center relative mb-6">
                    <h2 className="text-2xl font-elegant font-bold text-slate-800">Voz USA</h2>
                    {isIOS() && (
                      <button onClick={() => setIsHelpOpen(true)} className="absolute right-0 w-8 h-8 flex items-center justify-center bg-indigo-50 text-indigo-500 rounded-full font-bold text-sm shadow-sm border border-indigo-100">
                        ?
                      </button>
                    )}
                  </div>

                  <button onClick={() => setVoiceViewMode('list')} className="w-full mb-6 p-4 rounded-2xl border border-slate-100 bg-white hover:bg-slate-50 flex items-center justify-between transition-colors">
                    <div className="flex flex-col items-start min-w-0">
                      <span className="text-[10px] uppercase font-bold text-slate-400 tracking-widest">Voz Seleccionada</span>
                      <span className="text-lg font-bold text-slate-800 truncate max-w-[200px]">{getVoiceDisplayName()}</span>
                    </div>
                    <span className="text-slate-300">›</span>
                  </button>

                  <div className="flex gap-4 mb-8">
                    <div className="flex-1 bg-slate-50 rounded-2xl p-4 flex flex-col items-center">
                      <span className="text-[10px] font-bold text-slate-400 uppercase mb-3">Ritmo</span>
                      <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => { const s = {...voiceSettings, rate: parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }} className="w-full accent-slate-800" />
                    </div>
                    <div className="flex-1 bg-slate-50 rounded-2xl p-4 flex flex-col items-center">
                      <span className="text-[10px] font-bold text-slate-400 uppercase mb-3">Tono</span>
                      <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => { const s = {...voiceSettings, pitch: parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }} className="w-full accent-slate-800" />
                    </div>
                  </div>
                  <button onClick={() => setIsVoiceStudioOpen(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
                </>
              ) : (
                <>
                  <h2 className="text-xl font-bold mb-4">Voces Disponibles</h2>
                  <div className="flex-1 overflow-y-auto space-y-2 mb-4 pr-1">
                    {availableVoices.length === 0 && <p className="text-center text-slate-400 py-4">No se encontraron voces (iOS a veces tarda en cargarlas, intenta reabrir).</p>}
                    {availableVoices.map(v => (
                      <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)}
                          className={`p-4 rounded-xl border flex items-center justify-between cursor-pointer active:scale-[0.98] transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 text-white border-slate-900' : 'bg-white border-slate-100 text-slate-600'}`}>
                        <div className="flex flex-col">
                          <span className="font-bold text-sm">{v.name.replace(/Microsoft|Google|English|United States|en-US/g, '').trim()}</span>
                          {/* Etiqueta Visual de Calidad */}
                          {(v.name.toLowerCase().includes('enhanced') || v.name.toLowerCase().includes('premium')) && 
                             <span className="text-[9px] uppercase tracking-wider font-bold text-emerald-500 mt-0.5">Alta Calidad</span>}
                        </div>
                        {voiceSettings.voiceURI === v.voiceURI && <span>●</span>}
                      </div>
                    ))}
                  </div>
                  <button onClick={() => setVoiceViewMode('settings')} className="w-full py-3 text-slate-400 font-bold">Atrás</button>
                </>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
};

