  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      stopAudio(); // Detener cualquier audio al desmontar
    };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;

    // Reset inmediato de estados críticos
    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setValidationStatus('none');
    setShowNextButton(false);
    setIsTransitioning(false);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    // Evitar que salga ya armada por azar
    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));

    // Pequeña pausa para que la transición de entrada respire
    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);

    // Pronunciar palabra
    try {
      await Promise.race([
        speakWordPromise(currentWord.original, 'en-US', true),
        new Promise(resolve => setTimeout(resolve, 3500))
      ]);
    } catch (e) {
      console.warn("Speech synthesis timeout or error");
    }

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex, listId]); // Dependencia de listId por si cambia la sesión

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      try {
        await Promise.race([
          speakWordPromise(letterObj.char, 'en-US', true),
          new Promise(resolve => setTimeout(resolve, 1000))
        ]);
      } catch(e) {}

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots.join(''));
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (constructed: string) => {
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true);

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      await new Promise(resolve => setTimeout(resolve, 500));
      if (!isMounted.current) return;

      setShowRevelation(true);

      // Secuencia de éxito: Palabra -> Deletreo -> Palabra
      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
        await new Promise(resolve => setTimeout(resolve, 300));
        for (const char of currentWord.original.split('')) {
          if (!isMounted.current) return;
          await speakWordPromise(char, 'en-US', false);
        }
        await speakWordPromise(currentWord.original, 'en-US', false);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    } else {
      setValidationStatus('incorrect');

      // Registrar error en la lista persistente
      const allLists = loadLists();
      const targetList = allLists.find(l => l.id === listId);
      if (targetList) {
        const wordInMain = targetList.words.find(w => w.original === currentWord.original);
        if (wordInMain) wordInMain.errors += 1;
        saveLists(allLists);
      }

      try {
        await speakWordPromise(currentWord.original, 'en-US', true);
      } catch(e) {}

      if (isMounted.current) { 
        setShowNextButton(true); 
        setIsAudioLocked(false); 
      }
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    stopAudio();
    setIsTransitioning(true);

    // Esperar a que la animación de fade-out termine
    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { stopAudio(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8">
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/70 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/50'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-32 px-4 text-center flex flex-col items-center justify-start w-full max-w-lg">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center">
                  <h2 className="text-3xl sm:text-4xl font-elegant font-bold text-slate-800 uppercase tracking-widest mb-2">{currentWord.original}</h2>
                  <div className="bg-white/40 backdrop-blur-sm rounded-xl p-3 border border-white/50 shadow-sm">
                    <p className="text-base font-semibold text-slate-700 leading-snug">{getMeaning(currentWord.original)}</p>
                    <p className="text-xs text-slate-500 mt-1 flex items-center justify-center gap-1">
                      <span className="opacity-50">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100/80 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold shadow-sm">
                  Try again
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.3em] mt-2 animate-pulse">Modo Repaso</span>
              )}
            </div>
        </div>

        <div className="flex gap-2 flex-wrap justify-center px-4 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char}
            </div>
          ))}
        </div>

        <div className={`w-full px-4 pb-20 flex gap-2 flex-wrap justify-center items-end min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {validationStatus !== 'correct' && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import { loadVoiceSettings } from "./store";

// --- GESTIÓN DE AUDIO NATIVO ---

export const stopAudio = () => {
  if (typeof window !== 'undefined' && window.speechSynthesis) {
    window.speechSynthesis.cancel();
  }
};

/**
 * Detecta si una voz es de alta calidad basándose en palabras clave del sistema.
 */
export const isPremiumVoice = (voice: SpeechSynthesisVoice): boolean => {
  const name = voice.name.toLowerCase();
  return (
    name.includes('premium') || 
    name.includes('enhanced') || 
    name.includes('natural') || 
    name.includes('neural') ||
    name.includes('siri') || 
    name.includes('google') ||
    name.includes('ava') || 
    name.includes('samantha')
  );
};

/**
 * Algoritmo de "Autoconfiguración de Élite".
 * Regla: Voz 'Flo' (si existe) + las 5 mejores voces premium descargadas.
 * Si no hay ninguna, devuelve la mejor disponible de fábrica como salvavidas.
 */
export const getTopUSAVoices = (): SpeechSynthesisVoice[] => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return [];

  const allVoices = window.speechSynthesis.getVoices();

  // Filtro estricto: Solo inglés de USA
  const usVoices = allVoices.filter(v => 
    v.lang.toLowerCase().replace('_', '-').startsWith('en-us')
  );

  if (usVoices.length === 0) return [];

  // Separar voces por categorías
  const floVoice = usVoices.find(v => v.name.toLowerCase().includes('flo'));
  const premiumVoices = usVoices.filter(v => isPremiumVoice(v) && !v.name.toLowerCase().includes('flo'));

  // Ranking de calidad para las voces premium
  const sortedPremium = [...premiumVoices].sort((a, b) => {
    const getScore = (v: SpeechSynthesisVoice) => {
      let score = 0;
      const n = v.name.toLowerCase();
      if (n.includes('enhanced')) score += 10;
      if (n.includes('premium')) score += 8;
      if (n.includes('natural') || n.includes('neural')) score += 7;
      if (n.includes('google')) score += 5;
      if (n.includes('compact')) score -= 10;
      return score;
    };
    return getScore(b) - getScore(a);
  });

  // Construir lista final: Flo + Top 5 Premiums
  const result: SpeechSynthesisVoice[] = [];
  if (floVoice) result.push(floVoice);

  // Añadir las 5 mejores premium (o menos si no hay tantas)
  const topFivePremium = sortedPremium.slice(0, 5);
  result.push(...topFivePremium);

  // --- SISTEMA DE SALVAVIDAS ---
  // Si después de los filtros la lista está vacía, tomamos la primera de sistema
  if (result.length === 0 && usVoices.length > 0) {
    // Priorizamos una que no sea 'compact' si es posible
    const basicVoice = usVoices.find(v => !v.name.toLowerCase().includes('compact')) || usVoices[0];
    result.push(basicVoice);
  }

  return result;
};

/**
 * Encuentra la mejor voz disponible según configuración o defecto inteligente.
 */
const getBestVoice = (settings: ReturnType<typeof loadVoiceSettings>): { voice: SpeechSynthesisVoice | null } => {
  if (typeof window === 'undefined' || !window.speechSynthesis) return { voice: null };

  const voices = window.speechSynthesis.getVoices();

  // 1. Preferencia guardada del usuario
  if (settings.voiceURI) {
    const userVoice = voices.find(v => v.voiceURI === settings.voiceURI);
    if (userVoice) return { voice: userVoice };
  }

  // 2. Selección automática (La mejor de nuestra lista de élite)
  const eliteVoices = getTopUSAVoices();
  if (eliteVoices.length > 0) return { voice: eliteVoices[0] };

  // 3. Fallback absoluto (Cualquier inglés)
  const anyEnglish = voices.find(v => v.lang.startsWith('en'));
  return { voice: anyEnglish || null };
};

/**
 * Motor principal de habla.
 * Aplica "Maquillaje Auditivo" para mejorar voces de baja calidad.
 */
export const speakWordPromise = (word: string, lang: string = 'en-US', interrupt: boolean = true): Promise<void> => {
  return new Promise((resolve) => {
    if (typeof window === 'undefined' || !window.speechSynthesis) {
      resolve();
      return;
    }

    if (interrupt) {
      window.speechSynthesis.cancel();
    }

    const settings = loadVoiceSettings();
    const { voice } = getBestVoice(settings);
    const utterance = new SpeechSynthesisUtterance(word);

    utterance.lang = 'en-US'; 

    if (voice) {
      utterance.voice = voice;

      const isRobot = !isPremiumVoice(voice) || voice.name.toLowerCase().includes('compact');
      const isSingleLetter = word.length === 1;

      // --- MAQUILLAJE AUDITIVO ---
      if (isRobot) {
        // Mejoramos la claridad de voces básicas
        utterance.rate = isSingleLetter ? 0.65 : 0.85; 
        utterance.pitch = 0.95; // Un tono ligeramente más bajo reduce la sensación metálica
      } else {
        // Voces de alta calidad usan el ritmo optimizado para niños
        if (isSingleLetter) {
           utterance.rate = 0.6;
           utterance.pitch = settings.pitch;
        } else {
           utterance.rate = settings.rate; 
           utterance.pitch = settings.pitch;
        }
      }
    }

    utterance.onend = () => resolve();
    utterance.onerror = () => resolve();

    // Seguridad para navegadores que fallan al disparar onend
    const safetyTimeout = setTimeout(() => resolve(), 5000);
    utterance.onstart = () => clearTimeout(safetyTimeout);

    window.speechSynthesis.speak(utterance);
  });
};

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { getTopUSAVoices } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [theme, setTheme] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [isLoadingImage, setIsLoadingImage] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  // Estados del Estudio de Voz
  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [availableVoices, setAvailableVoices] = useState<SpeechSynthesisVoice[]>([]);

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setAvailableVoices(getTopUSAVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    setIsLoadingImage(true);

    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: extractWords(inputText) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setTheme(''); setEditingListId(null); setIsAdding(false); setIsLoadingImage(false);
  };

  const getVoiceDisplayName = () => {
    const v = availableVoices.find(v => v.voiceURI === voiceSettings.voiceURI);
    if (!v) return "Automática Inteligente";
    return v.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');

      const u = new SpeechSynthesisUtterance("I am ready to help you.");
      u.voice = voice;
      u.lang = 'en-US';
      u.rate = s.rate;
      u.pitch = s.pitch;
      window.speechSynthesis.cancel();
      window.speechSynthesis.speak(u);
  };

  const isIOS = () => {
    if (typeof window === 'undefined') return false;
    return /iPad|iPhone|iPod/.test(navigator.userAgent) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48 animate-in fade-in duration-700">
      <header className="flex flex-col items-center mb-6 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-6"></div>

        {role === 'parent' && (
          <button onClick={() => setIsVoiceStudioOpen(true)} className="flex items-center gap-3 px-4 py-2 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 active:scale-95 transition-all">
            <span className="text-lg">🔊</span>
            <div className="flex flex-col items-start min-w-0">
               <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300">Voz USA</span>
               <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
            </div>
          </button>
        )}
      </header>

      {/* Tarjeta de Repaso */}
      {lists.some(l => l.words.some(w => w.errors > 0)) && role === 'child' && (
        <div className="mb-8 animate-in slide-in-from-top-10 duration-700">
          <button onClick={() => {
            const listWithMostErrors = [...lists].sort((a,b) => 
              b.words.filter(w => w.errors > 0).length - a.words.filter(w => w.errors > 0).length
            )[0];
            onStartGame(listWithMostErrors.id, 'repaso');
          }} className="w-full bg-gradient-to-br from-indigo-500 to-purple-600 p-6 rounded-[2.5rem] shadow-xl text-white flex items-center justify-between group active:scale-[0.98] transition-all overflow-hidden relative">
            <div className="absolute top-0 right-0 p-4 opacity-10 scale-150 rotate-12">🧠</div>
            <div className="flex flex-col items-start z-10">
              <span className="text-[10px] font-bold tracking-[0.2em] uppercase opacity-70 mb-1">Entrenamiento</span>
              <h2 className="text-2xl font-elegant font-bold">ESTUDIO DE REPASO</h2>
            </div>
            <div className="w-12 h-12 bg-white/20 rounded-full flex items-center justify-center text-2xl">🎯</div>
          </button>
        </div>
      )}

      {/* Formulario de Lista */}
      {role === 'parent' && (
        isAdding ? (
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4">
            <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Lista' : 'Nueva Lista'}</h2>
            <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg" placeholder="Nombre de la lista" value={newListName} onChange={e => setNewListName(e.target.value)} />
            <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg" placeholder="Escribe las palabras separadas por espacios..." value={inputText} onChange={e => setInputText(e.target.value)} />
            <div className="flex gap-3">
              <button onClick={handleSaveList} className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold">Guardar</button>
              <button onClick={resetForm} className="px-6 rounded-2xl bg-slate-100 text-slate-500 font-bold">×</button>
            </div>
          </div>
        ) : (
          <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all">
            <span className="text-2xl font-light">+</span> Nueva Lista
          </button>
        )
      )}

      {/* Lista de Listas */}
      <div className="space-y-4">
        {lists.map(list => (
          <div key={list.id} onClick={() => role === 'parent' ? (setEditingListId(list.id), setIsAdding(true), setNewListName(list.name), setInputText(list.words.map(w => w.original).join(' '))) : onStartGame(list.id, 'normal')} 
               className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl">📝</div>
              <div>
                <h3 className="text-lg font-bold text-slate-800 leading-tight">{list.name}</h3>
                <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} palabras</span>
              </div>
            </div>
            <div className="text-slate-300 pr-2">›</div>
          </div>
        ))}
      </div>

      {/* Modal de Voz */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>

