                    <ol className="list-decimal pl-5 space-y-2">
                      <li>Ve a <strong className="text-slate-800">Ajustes &gt; Accesibilidad</strong>.</li>
                      <li>Entra en <strong className="text-slate-800">Contenido Leído &gt; Voces</strong>.</li>
                      <li>Busca <strong className="text-slate-800">Inglés (EE. UU.)</strong>.</li>
                      <li>Descarga la versión <strong className="text-indigo-600">Premium</strong> o <strong className="text-indigo-600">Mejorada</strong> de Samantha o Siri.</li>
                    </ol>
                  ) : (
                    <ol className="list-decimal pl-5 space-y-2">
                      <li>Ve a <strong className="text-slate-800">Ajustes &gt; Google</strong>.</li>
                      <li>Busca <strong className="text-slate-800">Ajustes para apps &gt; Voz</strong>.</li>
                      <li>Entra en <strong className="text-slate-800">Síntesis de voz &gt; Instalar datos de voz</strong>.</li>
                      <li>Descarga el paquete <strong className="text-indigo-600">Inglés (USA)</strong>.</li>
                    </ol>
                  )}
                  <p className="bg-indigo-50 p-3 rounded-xl text-indigo-700 text-[11px] font-bold">💡 Una vez descargada, vuelve aquí y la voz aparecerá en la sección "Élite".</p>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full bg-slate-900 text-white py-3 rounded-2xl font-bold">Entendido</button>
             </div>
          ) : (
            <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-10 flex flex-col max-h-[85vh]">
              {voiceViewMode === 'settings' ? (
                <>
                  <div className="flex items-center justify-between mb-6">
                    <h2 className="text-2xl font-elegant font-bold text-slate-800">Estudio de Voz</h2>
                    <button onClick={() => setIsHelpOpen(true)} className="w-10 h-10 flex items-center justify-center bg-indigo-50 text-indigo-500 rounded-full font-bold">?</button>
                  </div>

                  <button onClick={() => setVoiceViewMode('list')} className="w-full mb-6 p-4 rounded-2xl border-2 border-slate-50 bg-slate-50/50 flex items-center justify-between group active:scale-[0.98] transition-all">
                    <div className="flex flex-col items-start min-w-0">
                      <span className="text-[10px] uppercase font-bold text-slate-400 tracking-widest">Voz Seleccionada</span>
                      <span className="text-lg font-bold text-slate-800 truncate">{getVoiceDisplayName()}</span>
                    </div>
                    <span className="text-slate-300 group-hover:text-slate-600">›</span>
                  </button>

                  <div className="space-y-6 mb-8 relative">
                    {/* Botón de Reset Discreto */}
                    <button 
                      onClick={handleResetSettings}
                      className="absolute -top-4 right-0 text-[9px] font-bold text-slate-300 hover:text-indigo-400 transition-colors uppercase tracking-widest flex items-center gap-1"
                      title="Restablecer ajustes"
                    >
                      <span className="text-xs">↺</span> Restablecer
                    </button>

                    <div>
                      <div className="flex justify-between mb-2">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Velocidad</span>
                        <span className="text-xs font-bold text-slate-600">{Math.round(voiceSettings.rate * 100)}%</span>
                      </div>
                      <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => { const s = {...voiceSettings, rate: parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }} className="w-full h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600 transition-all" />
                    </div>
                    <div>
                      <div className="flex justify-between mb-2">
                        <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Tono</span>
                        <span className="text-xs font-bold text-slate-600">{Math.round(voiceSettings.pitch * 100)}%</span>
                      </div>
                      <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => { const s = {...voiceSettings, pitch: parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }} className="w-full h-2 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600 transition-all" />
                    </div>
                  </div>

                  <button onClick={() => setIsVoiceStudioOpen(false)} className="w-full bg-slate-900 text-white py-4 rounded-2xl font-bold shadow-xl shadow-slate-200">Guardar Ajustes</button>
                </>
              ) : (
                <>
                  <div className="flex items-center justify-between mb-6">
                    <h2 className="text-xl font-bold text-slate-800">Seleccionar Voz</h2>
                    <button onClick={() => setIsHelpOpen(true)} className="text-xs font-bold text-indigo-500">¿Cómo mejorar?</button>
                  </div>
                  <div className="flex-1 overflow-y-auto space-y-4 mb-4 pr-1">
                    {/* SECCIÓN ÉLITE */}
                    {categorizedVoices.elite.length > 0 && (
                      <div className="space-y-2">
                        <h3 className="text-[10px] font-bold text-indigo-400 uppercase tracking-[0.2em] ml-1">Voces Élite (Humanas)</h3>
                        {categorizedVoices.elite.map(v => (
                          <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)}
                              className={`p-4 rounded-xl border-2 flex items-center justify-between cursor-pointer transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-50 hover:border-indigo-100 text-slate-600'}`}>
                            <div className="flex flex-col">
                              <span className="font-bold text-sm">{v.name.replace(/Microsoft|Google|English|United States|en-US/g, '').trim()}</span>
