        <div className={`w-full px-4 pb-20 flex gap-2 flex-wrap justify-center items-end min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

