      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: extractWords(inputText) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

