                      {categorizedVoices.backup.map(v => (
                        <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)}
                            className={`p-4 rounded-xl border-2 flex items-center justify-between cursor-pointer transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 border-slate-900 text-white' : 'bg-slate-50 border-transparent text-slate-400'}`}>
