import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const childGradients = [
  'from-emerald-400 to-teal-500',
  'from-indigo-400 to-purple-500',
  'from-rose-400 to-orange-400',
  'from-cyan-400 to-blue-500',
  'from-amber-400 to-yellow-500',
  'from-violet-400 to-fuchsia-500'
];

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: extractWords(inputText) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);
  const isUsingBackup = currentVoice ? !isPremiumVoice(currentVoice) : categorizedVoices.elite.length === 0;

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');
      speakWordPromise("I am ready to help you.", 'en-US', true);
  };

  const renderParentView = () => (
    <div className="animate-in fade-in duration-700 space-y-4">
      {isAdding ? (
        <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 mb-8 space-y-4 animate-in slide-in-from-bottom-4">
          <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Lista' : 'Nueva Lista'}</h2>
          <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg" placeholder="Nombre de la lista" value={newListName} onChange={e => setNewListName(e.target.value)} />
          <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg" placeholder="Palabras..." value={inputText} onChange={e => setInputText(e.target.value)} />
          <div className="flex gap-3">
            <button onClick={handleSaveList} className="flex-grow bg-slate-900 text-white p-4 rounded-2xl font-bold">Guardar</button>
            <button onClick={resetForm} className="px-6 rounded-2xl bg-slate-100 text-slate-500 font-bold">×</button>
          </div>
        </div>
      ) : (
        <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all">+ Nueva Lista</button>
      )}

      {lists.map(list => {
        const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
        const errorCount = list.words.filter(w => w.errors > 0).length;
        return (
          <div key={list.id} onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setInputText(list.words.map(w => w.original).join(' ')); }} 
               className="bg-white p-4 rounded-[2rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-95 transition-all cursor-pointer">
            <div className="flex items-center gap-4">
              <div className="w-16 h-16 rounded-2xl bg-slate-50 flex items-center justify-center text-2xl">📝</div>
              <div>
                <h3 className="text-lg font-bold text-slate-800 leading-tight">{list.name}</h3>
                <div className="flex items-center gap-3 mt-0.5">
                  <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
                  {(correctCount + errorCount) > 0 && (
                    <div className="flex items-center gap-2">
                      {correctCount > 0 && <span className="text-[10px] font-bold text-emerald-500">✓ {correctCount}</span>}
                      {errorCount > 0 && <span className="text-[10px] font-bold text-rose-400">! {errorCount}</span>}
                    </div>
                  )}
                </div>
              </div>
            </div>
            <span className="text-slate-300 pr-2">›</span>
          </div>
        );
      })}
    </div>
  );

  const renderChildView = () => {
    const listWithErrors = [...lists].sort((a,b) => 
      b.words.filter(w => w.errors > 0).length - a.words.filter(w => w.errors > 0).length
    )[0];
    const hasErrorsGlobal = listWithErrors && listWithErrors.words.some(w => w.errors > 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-8">
        {/* Banner Heroico de Repaso */}
        {hasErrorsGlobal && (
          <button 
            onClick={() => onStartGame(listWithErrors.id, 'repaso')}
            className="w-full bg-gradient-to-r from-indigo-600 to-purple-700 p-8 rounded-[3rem] shadow-2xl shadow-indigo-200 text-white flex items-center justify-between group active:scale-[0.98] transition-all overflow-hidden relative animate-glow-signal"
          >
            <div className="absolute top-0 right-0 p-6 opacity-20 scale-150 rotate-12 animate-levitate text-5xl">🧠</div>
            <div className="flex flex-col items-start z-10 text-left">
              <span className="text-xs font-bold tracking-[0.3em] uppercase opacity-70 mb-2">Misión de Maestro</span>
              <h2 className="text-3xl font-elegant font-bold leading-tight">ESTUDIO DE<br/>REPASO</h2>
              <div className="mt-4 px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-bold tracking-widest uppercase">
                ¡Tienes retos por vencer!
              </div>
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-xl rounded-full flex items-center justify-center text-4xl shadow-inner group-hover:scale-110 transition-transform">🎯</div>
          </button>
        )}

        {/* Galería de Mundos */}
        <div className="grid grid-cols-2 gap-4">
          {lists.map((list, idx) => {
            const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
            const errorCount = list.words.filter(w => w.errors > 0).length;
            const isMaster = correctCount === list.words.length && list.words.length > 0;
            const progress = (list.words.filter(w => w.completed).length / list.words.length) * 100;
            const gradient = childGradients[idx % childGradients.length];

            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className={`relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden ${isMaster ? 'ring-4 ring-amber-400 animate-in zoom-in-95' : ''}`}>

                {/* Fondo de Mundo */}
                <div className={`absolute inset-0 bg-gradient-to-br ${gradient} transition-transform group-hover:scale-110`}></div>
                {isMaster && <div className="absolute inset-0 animate-shimmer-gold opacity-30"></div>}
                <div className="absolute inset-0 bg-black/5"></div>

                {/* Contenido */}
                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="flex justify-between items-start">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg">
                      {isMaster ? '🏆' : '🌎'}
                    </div>
                  </div>

                  <div>
                    <h3 className="text-white font-bold text-xl leading-tight mb-3 drop-shadow-md">{list.name}</h3>

                    {/* Medallas Logros y Retos */}
                    <div className="flex flex-wrap gap-2 mb-4">
                       <div className="flex items-center gap-1.5 px-3 py-1 bg-white/20 backdrop-blur-md rounded-full border border-white/30 shadow-sm">
                          <span className="text-white font-bold text-xs">✓</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{correctCount}</span>
                       </div>
                       {errorCount > 0 && (
                        <div className="flex items-center gap-1.5 px-3 py-1 bg-rose-500/30 backdrop-blur-md rounded-full border border-rose-200/40 shadow-sm animate-pulse">
                          <span className="text-white font-bold text-xs">!</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{errorCount}</span>
                        </div>
                       )}
                    </div>

                    {/* Barra de Líquido */}
                    <div className="w-full h-2 bg-black/10 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white transition-all duration-1000 ease-out rounded-full shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
                           style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-8"></div>

        {role === 'parent' && (
          <div className="w-full space-y-3 animate-in fade-in">
