            </button>
          </div>
        )}
      </header>

      {role === 'child' ? renderChildView() : renderParentView()}

      {/* Modal de Voz (Simplificado) */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            {isHelpOpen ? (
              <div className="p-2">
                <h2 className="text-xl font-bold mb-4">Mejorar Sonido</h2>
                <div className="text-sm space-y-4 text-slate-600">
                  <p>Activa voces naturales en ajustes:</p>
                  <ol className="list-decimal pl-4 space-y-2">
                    <li>Ve a <strong className="text-slate-800">Ajustes > Accesibilidad</strong>.</li>
                    <li>Entra en <strong className="text-slate-800">Contenido Leído > Voces</strong>.</li>
                    <li>Busca <strong className="text-slate-800">Inglés (EE. UU.)</strong>.</li>
                    <li>Descarga voces <strong className="text-indigo-600">Mejoradas</strong>.</li>
                  </ol>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full mt-6 bg-slate-900 text-white py-3 rounded-2xl font-bold">Entendido</button>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-elegant font-bold">Estudio de Voz</h2>
                  <button onClick={() => setIsHelpOpen(true)} className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full font-bold">?</button>
                </div>
                <div className="flex-1 overflow-y-auto pr-1 space-y-6">
                   <button onClick={() => setVoiceViewMode(voiceViewMode === 'list' ? 'settings' : 'list')} className="w-full p-4 bg-slate-50 rounded-2xl flex justify-between items-center">
                     <span className="font-bold text-slate-800">{voiceViewMode === 'list' ? 'Volver a Ajustes' : getVoiceDisplayName()}</span>
                     <span>{voiceViewMode === 'list' ? '←' : '›'}</span>
                   </button>
                   {voiceViewMode === 'settings' ? (
                     <div className="space-y-6">
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => {const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => {const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                     </div>
                   ) : (
                     <div className="space-y-2">
                       {categorizedVoices.elite.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-50'}`}>
                           <span className="font-bold">{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                       {categorizedVoices.backup.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 text-white' : 'bg-slate-50'}`}>
                           <span>{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                     </div>
                   )}
                </div>
                <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

