import React, { useState, useEffect, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise, stopAudio } from '../geminiService';
import { getMeaning, getSynonyms, saveLists, loadLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  backgroundImage?: string;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, backgroundImage, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);
  const [attempts, setAttempts] = useState(0);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      stopAudio(); 
    };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;

    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setValidationStatus('none');
    setShowNextButton(false);
    setIsTransitioning(false);
    setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));

    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
    } catch (e) {
      console.warn("Speech synthesis error");
    }

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex, listId]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || (validationStatus === 'incorrect' && showNextButton)) return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      try {
        await speakWordPromise(letterObj.char, 'en-US', true);
      } catch(e) {}

      // CRITICAL: We pass the actual NEW array (newSlots) to the logic
      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots);
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const updateGlobalWordStats = (isCorrect: boolean, isFinalAttempt: boolean) => {
    const allLists = loadLists();
    const targetList = allLists.find(l => l.id === listId);
    if (targetList) {
      const wordInMain = targetList.words.find(w => w.original === currentWord.original);
      if (wordInMain) {
        if (!isCorrect) {
          wordInMain.errors += 1;
        }
        if (isCorrect || isFinalAttempt) {
          wordInMain.completed = true;
        }
        saveLists(allLists);
      }
    }
  };

  const handleCompletion = async (currentSlots: (string | null)[]) => {
    const constructed = currentSlots.join('');
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true); 

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      updateGlobalWordStats(true, true);
      await playSuccessSequence();
    } else {
      const newAttemptCount = attempts + 1;
      setAttempts(newAttemptCount);
      setValidationStatus('incorrect');
      updateGlobalWordStats(false, newAttemptCount >= 2);

      if (newAttemptCount === 1) {
        try {
          await speakWordPromise(currentWord.original, 'en-US', true);
          await new Promise(resolve => setTimeout(resolve, 800));
        } catch(e) {}

        if (isMounted.current) {
          // FIX: Use currentSlots passed as parameter instead of 'slots' from state
          const lettersToReturn = currentSlots.filter(s => s !== null).map(s => ({ 
            char: s!, 
            id: Math.random().toString() 
          }));

          setSlots(new Array(currentWord.original.length).fill(null));
          setAvailableLetters(lettersToReturn);
          setValidationStatus('none');
          setIsAudioLocked(false);
        }
      } else {
        await playSuccessSequence();
      }
    }
  };

  const playSuccessSequence = async () => {
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;

    setShowRevelation(true);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));

      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 300));

      if (isMounted.current) {
        await speakWordPromise(currentWord.original, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 500));
    } catch(e) {}

    if (isMounted.current) { 
      setShowNextButton(true); 
      setIsAudioLocked(false); 
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (isAudioLocked && !showNextButton) return;

    stopAudio();
    setIsTransitioning(true);

    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { stopAudio(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8">
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/70 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/50'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-32 px-4 text-center flex flex-col items-center justify-start w-full max-w-lg">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center">
                  <h2 className="text-3xl sm:text-4xl font-elegant font-bold text-slate-800 uppercase tracking-widest mb-2">{currentWord.original}</h2>
                  <div className="bg-white/40 backdrop-blur-sm rounded-xl p-3 border border-white/50 shadow-sm">
                    <p className="text-base font-semibold text-slate-700 leading-snug">{getMeaning(currentWord.original)}</p>
                    <p className="text-xs text-slate-500 mt-1 flex items-center justify-center gap-1">
                      <span className="opacity-50">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100/80 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold shadow-sm">
                  {attempts === 1 ? 'Escucha con atención' : 'Aprendamos juntos'}
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.3em] mt-2 animate-pulse">Modo Repaso</span>
              )}
            </div>
        </div>

        <div className="flex gap-2 flex-wrap justify-center px-4 w-full max-w-2xl my-4">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`w-12 h-14 sm:w-14 sm:h-16 rounded-xl border-2 flex items-center justify-center text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char}
            </div>
          ))}
        </div>

        <div className={`w-full px-4 pb-20 flex gap-2 flex-wrap justify-center items-end min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-16 sm:h-16 bg-white rounded-2xl shadow-xl flex items-center justify-center text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const childGradients = [
  'from-emerald-400 to-teal-500',
  'from-indigo-400 to-purple-500',
  'from-rose-400 to-orange-400',
  'from-cyan-400 to-blue-500',
  'from-amber-400 to-yellow-500',
  'from-violet-400 to-fuchsia-500'
];

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  // Función para mantener el progreso de las palabras existentes al editar el texto
  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);
  const isUsingBackup = currentVoice ? !isPremiumVoice(currentVoice) : categorizedVoices.elite.length === 0;

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');
      speakWordPromise("I am ready to help you.", 'en-US', true);
  };

  const renderParentView = () => {
    const currentList = editingListId ? lists.find(l => l.id === editingListId) : null;

    return (
      <div className="animate-in fade-in duration-700 space-y-4">
        {isAdding ? (
          <div className="space-y-6 pb-20">
            <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 space-y-4 animate-in slide-in-from-bottom-4">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
                <button onClick={resetForm} className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">×</button>
              </div>
              <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg font-bold placeholder:font-normal" placeholder="Nombre de la aventura..." value={newListName} onChange={e => setNewListName(e.target.value)} />
              <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg leading-relaxed placeholder:font-normal" placeholder="Escribe las palabras separadas por espacios..." value={inputText} onChange={e => setInputText(e.target.value)} />
              <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-transform">Guardar Cambios</button>
            </div>

            {currentList && (
              <div className="space-y-4 animate-in fade-in slide-in-from-bottom-2 duration-700">
                <div className="flex items-center justify-between px-2">
                  <h3 className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em]">Estado de Aprendizaje</h3>
                  <div className="flex gap-4">
                    <span className="text-[10px] font-bold text-emerald-500">✓ Logradas</span>
                    <span className="text-[10px] font-bold text-rose-400">! Retos</span>
                  </div>
                </div>

                <div className="grid grid-cols-1 gap-2">
                  {currentList.words.map(word => {
                    const hasErrors = word.errors > 0;
                    const isDone = word.completed && !hasErrors;
                    return (
                      <div key={word.id} onClick={() => speakWordPromise(word.original, 'en-US', true)}
                           className={`p-4 rounded-2xl flex items-center justify-between border transition-all active:scale-98 cursor-pointer
                           ${isDone ? 'bg-emerald-50/50 border-emerald-100' : hasErrors ? 'bg-rose-50/50 border-rose-100' : 'bg-white border-slate-50'}`}>
                        <div className="flex items-center gap-3">
                          <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-lg shadow-sm
                            ${isDone ? 'bg-emerald-500 text-white' : hasErrors ? 'bg-rose-500 text-white animate-vibrate' : 'bg-slate-100 text-slate-400'}`}>
                            {isDone ? '✓' : hasErrors ? '!' : '·'}
                          </div>
                          <div>
                            <span className="text-lg font-bold text-slate-700 block capitalize">{word.original}</span>
                            {hasErrors && <span className="text-[10px] font-bold text-rose-400 uppercase tracking-tighter">{word.errors} {word.errors === 1 ? 'intento fallido' : 'intentos fallidos'}</span>}
                          </div>
                        </div>
                        <span className="text-xl opacity-30">🔊</span>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        ) : (
          <>
            <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold">+ Nueva Lista de Palabras</button>
            {lists.map(list => {
              const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
              const errorCount = list.words.filter(w => w.errors > 0).length;
              return (
                <div key={list.id} onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setInputText(list.words.map(w => w.original).join(' ')); }} 
                     className="bg-white p-5 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-95 transition-all cursor-pointer">
                  <div className="flex items-center gap-4">
                    <div className="w-16 h-16 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl shadow-inner">📝</div>
                    <div>
                      <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                      <div className="flex items-center gap-3 mt-1">
                        <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
                        {(correctCount + errorCount) > 0 && (
                          <div className="flex items-center gap-2">
                            {correctCount > 0 && <span className="text-[10px] font-bold text-emerald-500">✓ {correctCount}</span>}
                            {errorCount > 0 && <span className="text-[10px] font-bold text-rose-400">! {errorCount}</span>}
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                  <span className="text-slate-300 text-2xl pr-2">›</span>
                </div>
              );
            })}
          </>
        )}
      </div>
    );
  };

  const renderChildView = () => {
    const listWithErrors = [...lists].sort((a,b) => 
      b.words.filter(w => w.errors > 0).length - a.words.filter(w => w.errors > 0).length
    )[0];
    const hasErrorsGlobal = listWithErrors && listWithErrors.words.some(w => w.errors > 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-8">
        {/* Banner Heroico de Repaso */}
        {hasErrorsGlobal && (
          <button 
            onClick={() => onStartGame(listWithErrors.id, 'repaso')}
            className="w-full bg-gradient-to-r from-indigo-600 to-purple-700 p-8 rounded-[3rem] shadow-2xl shadow-indigo-200 text-white flex items-center justify-between group active:scale-[0.98] transition-all overflow-hidden relative animate-glow-signal"
          >
            <div className="absolute top-0 right-0 p-6 opacity-20 scale-150 rotate-12 animate-levitate text-5xl">🧠</div>
            <div className="flex flex-col items-start z-10 text-left">
              <span className="text-xs font-bold tracking-[0.3em] uppercase opacity-70 mb-2">Misión de Maestro</span>
              <h2 className="text-3xl font-elegant font-bold leading-tight">ESTUDIO DE<br/>REPASO</h2>
              <div className="mt-4 px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-bold tracking-widest uppercase">
                ¡Tienes retos por vencer!
              </div>
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-xl rounded-full flex items-center justify-center text-4xl shadow-inner group-hover:scale-110 transition-transform">🎯</div>
          </button>
        )}

        {/* Galería de Mundos */}
        <div className="grid grid-cols-2 gap-4">
          {lists.map((list, idx) => {
            const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
            const errorCount = list.words.filter(w => w.errors > 0).length;
            const isMaster = correctCount === list.words.length && list.words.length > 0;
            const progress = (list.words.filter(w => w.completed).length / list.words.length) * 100;
            const gradient = childGradients[idx % childGradients.length];

            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className={`relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden ${isMaster ? 'ring-4 ring-amber-400 animate-in zoom-in-95' : ''}`}>

                {/* Fondo de Mundo */}
                <div className={`absolute inset-0 bg-gradient-to-br ${gradient} transition-transform group-hover:scale-110`}></div>
                {isMaster && <div className="absolute inset-0 animate-shimmer-gold"></div>}
                <div className="absolute inset-0 bg-black/5"></div>

                {/* Contenido */}
                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="flex justify-between items-start">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg">
                      {isMaster ? '🏆' : '🌎'}
                    </div>
                  </div>

                  <div>
                    <h3 className="text-white font-bold text-xl leading-tight mb-4 drop-shadow-md">{list.name}</h3>

                    {/* Medallas Traslúcidas (Gamificación Minimalista) */}
                    <div className="flex flex-wrap gap-2 mb-4">
                       <div className="flex items-center gap-1.5 px-3 py-1 bg-white/20 backdrop-blur-md rounded-full border border-white/30 shadow-sm transition-transform hover:scale-110">
                          <span className="text-white font-bold text-xs">✓</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{correctCount} Logros</span>
                       </div>
                       {errorCount > 0 && (
                        <div className="flex items-center gap-1.5 px-3 py-1 bg-rose-500/30 backdrop-blur-md rounded-full border border-rose-200/40 shadow-sm animate-vibrate">
                          <span className="text-white font-bold text-xs">!</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{errorCount} Retos</span>
                        </div>
                       )}
                    </div>

                    {/* Barra de Líquido */}
                    <div className="w-full h-2 bg-black/10 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white transition-all duration-1000 ease-out rounded-full shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
                           style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-8"></div>

        {role === 'parent' && (
          <div className="w-full space-y-3 animate-in fade-in">
            {isUsingBackup && (
              <button onClick={() => { setIsVoiceStudioOpen(true); setIsHelpOpen(true); }} className="w-full bg-amber-50 border border-amber-100 p-3 rounded-2xl flex items-center gap-3 animate-glow-signal active:scale-[0.98] transition-all">
                <span className="text-lg">📢</span>
                <div className="flex flex-col items-start min-w-0 text-left">
                  <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Mejora mi sonido</span>
                  <p className="text-xs text-amber-700 font-semibold">Toca aquí para descargar voces humanas gratis</p>
                </div>
              </button>
            )}
            <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 active:scale-95 transition-all">
              <div className="flex items-center gap-3">
                <span className="text-lg">🔊</span>
                <div className="flex flex-col items-start min-w-0">
                  <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300">Voz actual</span>
                  <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
                </div>
              </div>
              <span className={`text-[9px] px-2 py-1 rounded-full font-bold uppercase ${isUsingBackup ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-500'}`}>{isUsingBackup ? 'Repuesto' : 'Élite'}</span>
            </button>
          </div>
        )}
      </header>

      {role === 'child' ? renderChildView() : renderParentView()}

      {/* Modal de Voz (Simplificado) */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            {isHelpOpen ? (
              <div className="p-2">
                <h2 className="text-xl font-bold mb-4">Mejorar Sonido</h2>
                <div className="text-sm space-y-4 text-slate-600">
                  <p>Activa voces naturales en ajustes:</p>
                  <ol className="list-decimal pl-4 space-y-2">
                    <li>Ve a <strong className="text-slate-800">Ajustes > Accesibilidad</strong>.</li>
                    <li>Entra en <strong className="text-slate-800">Contenido Leído > Voces</strong>.</li>
                    <li>Busca <strong className="text-slate-800">Inglés (EE. UU.)</strong>.</li>
                    <li>Descarga voces <strong className="text-indigo-600">Mejoradas</strong>.</li>
                  </ol>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full mt-6 bg-slate-900 text-white py-3 rounded-2xl font-bold">Entendido</button>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-elegant font-bold">Estudio de Voz</h2>
                  <button onClick={() => setIsHelpOpen(true)} className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full font-bold">?</button>
                </div>
                <div className="flex-1 overflow-y-auto pr-1 space-y-6">
                   <button onClick={() => setVoiceViewMode(voiceViewMode === 'list' ? 'settings' : 'list')} className="w-full p-4 bg-slate-50 rounded-2xl flex justify-between items-center">
                     <span className="font-bold text-slate-800">{voiceViewMode === 'list' ? 'Volver a Ajustes' : getVoiceDisplayName()}</span>
                     <span>{voiceViewMode === 'list' ? '←' : '›'}</span>
                   </button>
                   {voiceViewMode === 'settings' ? (
                     <div className="space-y-6">
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => {const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => {const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                     </div>
                   ) : (
                     <div className="space-y-2">
                       {categorizedVoices.elite.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-50'}`}>
                           <span className="font-bold">{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                       {categorizedVoices.backup.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 text-white' : 'bg-slate-50'}`}>
                           <span>{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                     </div>
                   )}
                </div>
                <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings, getMeaning } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const childGradients = [
  'from-emerald-400 to-teal-500',
  'from-indigo-400 to-purple-500',
  'from-rose-400 to-orange-400',
  'from-cyan-400 to-blue-500',
  'from-amber-400 to-yellow-500',
  'from-violet-400 to-fuchsia-500'
];

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);
  const isUsingBackup = currentVoice ? !isPremiumVoice(currentVoice) : categorizedVoices.elite.length === 0;

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');
      speakWordPromise("I am ready to help you.", 'en-US', true);
  };

  const renderProgressReport = (listId: string) => {
    const list = lists.find(l => l.id === listId);
    if (!list) return null;

    // Ordenar: Retos primero, luego por errores
    const sortedWords = [...list.words].sort((a, b) => {
      if (b.errors !== a.errors) return b.errors - a.errors;
      if (a.completed !== b.completed) return a.completed ? 1 : -1;
      return 0;
    });

    return (
      <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-center p-0 sm:p-6">
        <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingReportId(null)}></div>
        <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 shadow-2xl relative z-20 animate-in slide-in-from-bottom-20 duration-500 max-h-[90vh] flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div>
              <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.2em] mb-1 block">Diagnóstico de Aprendizaje</span>
              <h2 className="text-2xl font-elegant font-bold text-slate-800">{list.name}</h2>
            </div>
            <button onClick={() => setViewingReportId(null)} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-400 text-xl">✕</button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-3 mb-4 custom-scrollbar">
            {sortedWords.map(word => {
              const hasErrors = word.errors > 0;
              const isDone = word.completed && !hasErrors;
              return (
                <div key={word.id} onClick={() => speakWordPromise(word.original, 'en-US', true)}
                     className={`group p-4 rounded-2xl flex items-center justify-between border transition-all active:scale-98 cursor-pointer
                     ${isDone ? 'bg-emerald-50/40 border-emerald-100/50' : hasErrors ? 'bg-rose-50/40 border-rose-100/50' : 'bg-slate-50/50 border-slate-100/50'}`}>
                  <div className="flex items-center gap-4">
                    <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-xl shadow-sm transition-transform group-hover:scale-105
                      ${isDone ? 'bg-emerald-500 text-white' : hasErrors ? 'bg-rose-500 text-white animate-vibrate' : 'bg-slate-200 text-slate-400'}`}>
                      {isDone ? '✓' : hasErrors ? '!' : '·'}
                    </div>
                    <div>
                      <span className="text-lg font-bold text-slate-700 block capitalize">{word.original}</span>
                      <div className="flex items-center gap-2">
                        {hasErrors ? (
                          <span className="text-[10px] font-bold text-rose-400 uppercase tracking-tight">{word.errors} {word.errors === 1 ? 'error registrado' : 'errores registrados'}</span>
                        ) : (
                          <span className="text-[10px] font-medium text-slate-400 italic leading-none">{getMeaning(word.original)}</span>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="w-10 h-10 flex items-center justify-center bg-white/50 rounded-full opacity-40 group-hover:opacity-100 transition-opacity">
                    <span className="text-lg">🔊</span>
                  </div>
                </div>
              );
            })}
          </div>

          <button onClick={() => setViewingReportId(null)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg shadow-xl shadow-slate-200">Cerrar Informe</button>
        </div>
      </div>
    );
  };

  const renderParentView = () => {
    return (
      <div className="animate-in fade-in duration-700 space-y-4">
        {isAdding ? (
          <div className="space-y-6 pb-20">
            <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 space-y-4 animate-in slide-in-from-bottom-4">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
                <button onClick={resetForm} className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">×</button>
              </div>
              <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg font-bold placeholder:font-normal" placeholder="Nombre de la aventura..." value={newListName} onChange={e => setNewListName(e.target.value)} />
              <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg leading-relaxed placeholder:font-normal" placeholder="Escribe las palabras separadas por espacios..." value={inputText} onChange={e => setInputText(e.target.value)} />
              <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-transform">Guardar Cambios</button>
            </div>
          </div>
        ) : (
          <>
            <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold">+ Nueva Lista de Palabras</button>
            {lists.map(list => {
              const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
              const errorCount = list.words.filter(w => w.errors > 0).length;
              return (
                <div key={list.id} className="relative group">
                  <div onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setInputText(list.words.map(w => w.original).join(' ')); }} 
                       className="bg-white p-5 pr-20 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
                    <div className="flex items-center gap-4">
                      <div className="w-16 h-16 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl shadow-inner group-hover:scale-105 transition-transform">📝</div>
                      <div>
                        <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                        <div className="flex items-center gap-3 mt-1">
                          <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
                          {(correctCount + errorCount) > 0 && (
                            <div className="flex items-center gap-2">
                              {correctCount > 0 && <span className="text-[10px] font-bold text-emerald-500">✓ {correctCount}</span>}
                              {errorCount > 0 && <span className="text-[10px] font-bold text-rose-400 animate-vibrate">! {errorCount}</span>}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); setViewingReportId(list.id); }}
                    className="absolute right-4 top-1/2 -translate-y-1/2 w-14 h-14 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-indigo-100"
                    title="Ver Diagnóstico"
                  >
                    <span className="text-2xl">📈</span>
                  </button>
                </div>
              );
            })}
          </>
        )}
      </div>
    );
  };

  const renderChildView = () => {
    const listWithErrors = [...lists].sort((a,b) => 
      b.words.filter(w => w.errors > 0).length - a.words.filter(w => w.errors > 0).length
    )[0];
    const hasErrorsGlobal = listWithErrors && listWithErrors.words.some(w => w.errors > 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-8">
        {hasErrorsGlobal && (
          <button 
            onClick={() => onStartGame(listWithErrors.id, 'repaso')}
            className="w-full bg-gradient-to-r from-indigo-600 to-purple-700 p-8 rounded-[3rem] shadow-2xl shadow-indigo-200 text-white flex items-center justify-between group active:scale-[0.98] transition-all overflow-hidden relative animate-glow-signal"
          >
            <div className="absolute top-0 right-0 p-6 opacity-20 scale-150 rotate-12 animate-levitate text-5xl">🧠</div>
            <div className="flex flex-col items-start z-10 text-left">
              <span className="text-xs font-bold tracking-[0.3em] uppercase opacity-70 mb-2">Misión de Maestro</span>
              <h2 className="text-3xl font-elegant font-bold leading-tight">ESTUDIO DE<br/>REPASO</h2>
              <div className="mt-4 px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-bold tracking-widest uppercase">
                ¡Tienes retos por vencer!
              </div>
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-xl rounded-full flex items-center justify-center text-4xl shadow-inner group-hover:scale-110 transition-transform">🎯</div>
          </button>
        )}

        <div className="grid grid-cols-2 gap-4">
          {lists.map((list, idx) => {
            const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
            const errorCount = list.words.filter(w => w.errors > 0).length;
            const isMaster = correctCount === list.words.length && list.words.length > 0;
            const progress = (list.words.filter(w => w.completed).length / list.words.length) * 100;
            const gradient = childGradients[idx % childGradients.length];

            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className={`relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden ${isMaster ? 'ring-4 ring-amber-400 animate-in zoom-in-95' : ''}`}>

                <div className={`absolute inset-0 bg-gradient-to-br ${gradient} transition-transform group-hover:scale-110`}></div>
                {isMaster && <div className="absolute inset-0 animate-shimmer-gold"></div>}
                <div className="absolute inset-0 bg-black/5"></div>

                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="flex justify-between items-start">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg">
                      {isMaster ? '🏆' : '🌎'}
                    </div>
                  </div>

                  <div>
                    <h3 className="text-white font-bold text-xl leading-tight mb-4 drop-shadow-md">{list.name}</h3>

                    <div className="flex flex-wrap gap-2 mb-4">
                       <div className="flex items-center gap-1.5 px-3 py-1 bg-white/20 backdrop-blur-md rounded-full border border-white/30 shadow-sm transition-transform hover:scale-110">
                          <span className="text-white font-bold text-xs">✓</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{correctCount} Logros</span>
                       </div>
                       {errorCount > 0 && (
                        <div className="flex items-center gap-1.5 px-3 py-1 bg-rose-500/30 backdrop-blur-md rounded-full border border-rose-200/40 shadow-sm animate-vibrate">
                          <span className="text-white font-bold text-xs">!</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{errorCount} Retos</span>
                        </div>
                       )}
                    </div>

                    <div className="w-full h-2 bg-black/10 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white transition-all duration-1000 ease-out rounded-full shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
                           style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-8"></div>

        {role === 'parent' && (
          <div className="w-full space-y-3 animate-in fade-in">
            {isUsingBackup && (
              <button onClick={() => { setIsVoiceStudioOpen(true); setIsHelpOpen(true); }} className="w-full bg-amber-50 border border-amber-100 p-3 rounded-2xl flex items-center gap-3 animate-glow-signal active:scale-[0.98] transition-all">
                <span className="text-lg">📢</span>
                <div className="flex flex-col items-start min-w-0 text-left">
                  <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Mejora mi sonido</span>
                  <p className="text-xs text-amber-700 font-semibold">Toca aquí para descargar voces humanas gratis</p>
                </div>
              </button>
            )}
            <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 active:scale-95 transition-all">
              <div className="flex items-center gap-3">
                <span className="text-lg">🔊</span>
                <div className="flex flex-col items-start min-w-0">
                  <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300">Voz actual</span>
                  <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
                </div>
              </div>
              <span className={`text-[9px] px-2 py-1 rounded-full font-bold uppercase ${isUsingBackup ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-500'}`}>{isUsingBackup ? 'Repuesto' : 'Élite'}</span>
            </button>
          </div>
        )}
      </header>

      {role === 'child' ? renderChildView() : renderParentView()}

      {/* Panel de Diagnóstico */}
      {viewingReportId && renderProgressReport(viewingReportId)}

      {/* Modal de Voz (Simplificado) */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            {isHelpOpen ? (
              <div className="p-2">
                <h2 className="text-xl font-bold mb-4">Mejorar Sonido</h2>
                <div className="text-sm space-y-4 text-slate-600">
                  <p>Activa voces naturales en ajustes:</p>
                  <ol className="list-decimal pl-4 space-y-2">
                    <li>Ve a <strong className="text-slate-800">Ajustes > Accesibilidad</strong>.</li>
                    <li>Entra en <strong className="text-slate-800">Contenido Leído > Voces</strong>.</li>
                    <li>Busca <strong className="text-slate-800">Inglés (EE. UU.)</strong>.</li>
                    <li>Descarga voces <strong className="text-indigo-600">Mejoradas</strong>.</li>
                  </ol>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full mt-6 bg-slate-900 text-white py-3 rounded-2xl font-bold">Entendido</button>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-elegant font-bold">Estudio de Voz</h2>
                  <button onClick={() => setIsHelpOpen(true)} className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full font-bold">?</button>
                </div>
                <div className="flex-1 overflow-y-auto pr-1 space-y-6">
                   <button onClick={() => setVoiceViewMode(voiceViewMode === 'list' ? 'settings' : 'list')} className="w-full p-4 bg-slate-50 rounded-2xl flex justify-between items-center">
                     <span className="font-bold text-slate-800">{voiceViewMode === 'list' ? 'Volver a Ajustes' : getVoiceDisplayName()}</span>
                     <span>{voiceViewMode === 'list' ? '←' : '›'}</span>
                   </button>
                   {voiceViewMode === 'settings' ? (
                     <div className="space-y-6">
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} onChange={e => {const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                       <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} onChange={e => {const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s);}} className="w-full accent-indigo-600"/>
                     </div>
                   ) : (
                     <div className="space-y-2">
                       {categorizedVoices.elite.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-white border-slate-50'}`}>
                           <span className="font-bold">{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                       {categorizedVoices.backup.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 text-white' : 'bg-slate-50'}`}>
                           <span>{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                     </div>
                   )}
                </div>
                <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings, getMeaning } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const childGradients = [
  'from-emerald-400 to-teal-500',
  'from-indigo-400 to-purple-500',
  'from-rose-400 to-orange-400',
  'from-cyan-400 to-blue-500',
  'from-amber-400 to-yellow-500',
  'from-violet-400 to-fuchsia-500'
];

// Valores por defecto para comparaciones de reinicio
const DEFAULT_RATE = 0.8;
const DEFAULT_PITCH = 1.1;

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = async () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);
  const isUsingBackup = currentVoice ? !isPremiumVoice(currentVoice) : categorizedVoices.elite.length === 0;

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');
      speakWordPromise("I am ready to help you.", 'en-US', true);
  };

  // Función para disparar feedback auditivo al ajustar parámetros
  const triggerVoiceFeedback = (type: 'rate' | 'pitch') => {
    const text = type === 'rate' ? "Testing my new speed" : "Testing my new tone";
    speakWordPromise(text, 'en-US', true);
  };

  const resetSetting = (type: 'rate' | 'pitch') => {
    const newVal = type === 'rate' ? DEFAULT_RATE : DEFAULT_PITCH;
    const s = { ...voiceSettings, [type]: newVal };
    setVoiceSettings(s);
    saveVoiceSettings(s);
    triggerVoiceFeedback(type);
  };

  const renderProgressReport = (listId: string) => {
    const list = lists.find(l => l.id === listId);
    if (!list) return null;

    const sortedWords = [...list.words].sort((a, b) => {
      if (b.errors !== a.errors) return b.errors - a.errors;
      if (a.completed !== b.completed) return a.completed ? 1 : -1;
      return 0;
    });

    return (
      <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-center p-0 sm:p-6">
        <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingReportId(null)}></div>
        <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 shadow-2xl relative z-20 animate-in slide-in-from-bottom-20 duration-500 max-h-[90vh] flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div>
              <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.2em] mb-1 block">Diagnóstico de Aprendizaje</span>
              <h2 className="text-2xl font-elegant font-bold text-slate-800">{list.name}</h2>
            </div>
            <button onClick={() => setViewingReportId(null)} className="w-10 h-10 rounded-full bg-slate-50 flex items-center justify-center text-slate-400 text-xl">✕</button>
          </div>

          <div className="flex-1 overflow-y-auto pr-2 space-y-3 mb-4 custom-scrollbar">
            {sortedWords.map(word => {
              const hasErrors = word.errors > 0;
              const isDone = word.completed && !hasErrors;
              return (
                <div key={word.id} onClick={() => speakWordPromise(word.original, 'en-US', true)}
                     className={`group p-4 rounded-2xl flex items-center justify-between border transition-all active:scale-98 cursor-pointer
                     ${isDone ? 'bg-emerald-50/40 border-emerald-100/50' : hasErrors ? 'bg-rose-50/40 border-rose-100/50' : 'bg-slate-50/50 border-slate-100/50'}`}>
                  <div className="flex items-center gap-4">
                    <div className={`w-11 h-11 rounded-2xl flex items-center justify-center text-xl shadow-sm transition-transform group-hover:scale-105
                      ${isDone ? 'bg-emerald-500 text-white' : hasErrors ? 'bg-rose-500 text-white animate-vibrate' : 'bg-slate-200 text-slate-400'}`}>
                      {isDone ? '✓' : hasErrors ? '!' : '·'}
                    </div>
                    <div>
                      <span className="text-lg font-bold text-slate-700 block capitalize">{word.original}</span>
                      <div className="flex items-center gap-2">
                        {hasErrors ? (
                          <span className="text-[10px] font-bold text-rose-400 uppercase tracking-tight">{word.errors} {word.errors === 1 ? 'error registrado' : 'errores registrados'}</span>
                        ) : (
                          <span className="text-[10px] font-medium text-slate-400 italic leading-none">{getMeaning(word.original)}</span>
                        )}
                      </div>
                    </div>
                  </div>
                  <div className="w-10 h-10 flex items-center justify-center bg-white/50 rounded-full opacity-40 group-hover:opacity-100 transition-opacity">
                    <span className="text-lg">🔊</span>
                  </div>
                </div>
              );
            })}
          </div>

          <button onClick={() => setViewingReportId(null)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold text-lg shadow-xl shadow-slate-200">Cerrar Informe</button>
        </div>
      </div>
    );
  };

  const renderParentView = () => {
    return (
      <div className="animate-in fade-in duration-700 space-y-4">
        {isAdding ? (
          <div className="space-y-6 pb-20">
            <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 space-y-4 animate-in slide-in-from-bottom-4">
              <div className="flex justify-between items-center">
                <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
                <button onClick={resetForm} className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">×</button>
              </div>
              <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg font-bold placeholder:font-normal" placeholder="Nombre de la aventura..." value={newListName} onChange={e => setNewListName(e.target.value)} />
              <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg leading-relaxed placeholder:font-normal" placeholder="Escribe las palabras separadas por espacios..." value={inputText} onChange={e => setInputText(e.target.value)} />
              <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-transform">Guardar Cambios</button>
            </div>
          </div>
        ) : (
          <>
            <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold">+ Nueva Lista de Palabras</button>
            {lists.map(list => {
              const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
              const errorCount = list.words.filter(w => w.errors > 0).length;
              return (
                <div key={list.id} className="relative group">
                  <div onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setInputText(list.words.map(w => w.original).join(' ')); }} 
                       className="bg-white p-5 pr-20 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
                    <div className="flex items-center gap-4">
                      <div className="w-16 h-16 rounded-3xl bg-slate-50 flex items-center justify-center text-3xl shadow-inner group-hover:scale-105 transition-transform">📝</div>
                      <div>
                        <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                        <div className="flex items-center gap-3 mt-1">
                          <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
                          {(correctCount + errorCount) > 0 && (
                            <div className="flex items-center gap-2">
                              {correctCount > 0 && <span className="text-[10px] font-bold text-emerald-500">✓ {correctCount}</span>}
                              {errorCount > 0 && <span className="text-[10px] font-bold text-rose-400 animate-vibrate">! {errorCount}</span>}
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  </div>
                  <button 
                    onClick={(e) => { e.stopPropagation(); setViewingReportId(list.id); }}
                    className="absolute right-4 top-1/2 -translate-y-1/2 w-14 h-14 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-indigo-100"
                    title="Ver Diagnóstico"
                  >
                    <span className="text-2xl">📈</span>
                  </button>
                </div>
              );
            })}
          </>
        )}
      </div>
    );
  };

  const renderChildView = () => {
    const listWithErrors = [...lists].sort((a,b) => 
      b.words.filter(w => w.errors > 0).length - a.words.filter(w => w.errors > 0).length
    )[0];
    const hasErrorsGlobal = listWithErrors && listWithErrors.words.some(w => w.errors > 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-8">
        {hasErrorsGlobal && (
          <button 
            onClick={() => onStartGame(listWithErrors.id, 'repaso')}
            className="w-full bg-gradient-to-r from-indigo-600 to-purple-700 p-8 rounded-[3rem] shadow-2xl shadow-indigo-200 text-white flex items-center justify-between group active:scale-[0.98] transition-all overflow-hidden relative animate-glow-signal"
          >
            <div className="absolute top-0 right-0 p-6 opacity-20 scale-150 rotate-12 animate-levitate text-5xl">🧠</div>
            <div className="flex flex-col items-start z-10 text-left">
              <span className="text-xs font-bold tracking-[0.3em] uppercase opacity-70 mb-2">Misión de Maestro</span>
              <h2 className="text-3xl font-elegant font-bold leading-tight">ESTUDIO DE<br/>REPASO</h2>
              <div className="mt-4 px-4 py-1.5 bg-white/20 backdrop-blur-md rounded-full text-[10px] font-bold tracking-widest uppercase">
                ¡Tienes retos por vencer!
              </div>
            </div>
            <div className="w-20 h-20 bg-white/10 backdrop-blur-xl rounded-full flex items-center justify-center text-4xl shadow-inner group-hover:scale-110 transition-transform">🎯</div>
          </button>
        )}

        <div className="grid grid-cols-2 gap-4">
          {lists.map((list, idx) => {
            const correctCount = list.words.filter(w => w.completed && w.errors === 0).length;
            const errorCount = list.words.filter(w => w.errors > 0).length;
            const isMaster = correctCount === list.words.length && list.words.length > 0;
            const progress = (list.words.filter(w => w.completed).length / list.words.length) * 100;
            const gradient = childGradients[idx % childGradients.length];

            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className={`relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden ${isMaster ? 'ring-4 ring-amber-400 animate-in zoom-in-95' : ''}`}>

                <div className={`absolute inset-0 bg-gradient-to-br ${gradient} transition-transform group-hover:scale-110`}></div>
                {isMaster && <div className="absolute inset-0 animate-shimmer-gold"></div>}
                <div className="absolute inset-0 bg-black/5"></div>

                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="flex justify-between items-start">
                    <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg">
                      {isMaster ? '🏆' : '🌎'}
                    </div>
                  </div>

                  <div>
                    <h3 className="text-white font-bold text-xl leading-tight mb-4 drop-shadow-md">{list.name}</h3>

                    <div className="flex flex-wrap gap-2 mb-4">
                       <div className="flex items-center gap-1.5 px-3 py-1 bg-white/20 backdrop-blur-md rounded-full border border-white/30 shadow-sm transition-transform hover:scale-110">
                          <span className="text-white font-bold text-xs">✓</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{correctCount} Logros</span>
                       </div>
                       {errorCount > 0 && (
                        <div className="flex items-center gap-1.5 px-3 py-1 bg-rose-500/30 backdrop-blur-md rounded-full border border-rose-200/40 shadow-sm animate-vibrate">
                          <span className="text-white font-bold text-xs">!</span>
                          <span className="text-white font-bold text-[10px] tracking-tighter">{errorCount} Retos</span>
                        </div>
                       )}
                    </div>

                    <div className="w-full h-2 bg-black/10 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white transition-all duration-1000 ease-out rounded-full shadow-[0_0_10px_rgba(255,255,255,0.5)]" 
                           style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-8"></div>

        {role === 'parent' && (
          <div className="w-full space-y-3 animate-in fade-in">
            {isUsingBackup && (
              <button onClick={() => { setIsVoiceStudioOpen(true); setIsHelpOpen(true); }} className="w-full bg-amber-50 border border-amber-100 p-3 rounded-2xl flex items-center gap-3 animate-glow-signal active:scale-[0.98] transition-all">
                <span className="text-lg">📢</span>
                <div className="flex flex-col items-start min-w-0 text-left">
                  <span className="text-[10px] font-bold text-amber-600 uppercase tracking-widest">Mejora mi sonido</span>
                  <p className="text-xs text-amber-700 font-semibold">Toca aquí para descargar voces humanas gratis</p>
                </div>
              </button>
            )}
            <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 hover:text-slate-800 active:scale-95 transition-all">
              <div className="flex items-center gap-3">
                <span className="text-lg">🔊</span>
                <div className="flex flex-col items-start min-w-0">
                  <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300">Voz actual</span>
                  <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
                </div>
              </div>
              <span className={`text-[9px] px-2 py-1 rounded-full font-bold uppercase ${isUsingBackup ? 'bg-slate-100 text-slate-400' : 'bg-indigo-50 text-indigo-500'}`}>{isUsingBackup ? 'Repuesto' : 'Élite'}</span>
            </button>
          </div>
        )}
      </header>

      {role === 'child' ? renderChildView() : renderParentView()}

      {/* Panel de Diagnóstico */}
      {viewingReportId && renderProgressReport(viewingReportId)}

      {/* Modal de Voz */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => {setIsVoiceStudioOpen(false); setIsHelpOpen(false);}}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            {isHelpOpen ? (
              <div className="p-2">
                <h2 className="text-xl font-bold mb-4">Mejorar Sonido</h2>
                <div className="text-sm space-y-4 text-slate-600">
                  <p>Activa voces naturales en ajustes:</p>
                  <ol className="list-decimal pl-4 space-y-2">
                    <li>Ve a <strong className="text-slate-800">Ajustes > Accesibilidad</strong>.</li>
                    <li>Entra en <strong className="text-slate-800">Contenido Leído > Voces</strong>.</li>
                    <li>Busca <strong className="text-slate-800">Inglés (EE. UU.)</strong>.</li>
                    <li>Descarga voces <strong className="text-indigo-600">Mejoradas</strong>.</li>
                  </ol>
                </div>
                <button onClick={() => setIsHelpOpen(false)} className="w-full mt-6 bg-slate-900 text-white py-3 rounded-2xl font-bold">Entendido</button>
              </div>
            ) : (
              <>
                <div className="flex justify-between items-center mb-6">
                  <h2 className="text-2xl font-elegant font-bold">Estudio de Voz</h2>
                  <button onClick={() => setIsHelpOpen(true)} className="w-10 h-10 bg-indigo-50 text-indigo-500 rounded-full font-bold">?</button>
                </div>
                <div className="flex-1 overflow-y-auto pr-1 space-y-8 custom-scrollbar">
                   <button onClick={() => setVoiceViewMode(voiceViewMode === 'list' ? 'settings' : 'list')} className="w-full p-4 bg-slate-50 rounded-2xl flex justify-between items-center active:scale-98 transition-transform">
                     <div className="flex flex-col items-start">
                       <span className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Personalizando</span>
                       <span className="font-bold text-slate-800 font-elegant">{voiceViewMode === 'list' ? 'Volver a Ajustes' : getVoiceDisplayName()}</span>
                     </div>
                     <span className="text-xl text-slate-300">{voiceViewMode === 'list' ? '←' : '›'}</span>
                   </button>

                   {voiceViewMode === 'settings' ? (
                     <div className="space-y-8 py-2">
                       {/* Control de Velocidad (Rate) */}
                       <div className="space-y-4">
                         <div className="flex justify-between items-end">
                           <div className="flex items-center gap-2">
                             <label className="text-sm font-elegant font-bold text-slate-700 tracking-tight">Ritmo del Eco</label>
                             {voiceSettings.rate !== DEFAULT_RATE && (
                               <button onClick={() => resetSetting('rate')} className="w-6 h-6 rounded-full bg-indigo-50 text-indigo-500 flex items-center justify-center text-xs animate-in zoom-in">↺</button>
                             )}
                           </div>
                           <span className="text-[10px] font-bold text-indigo-400 bg-indigo-50 px-2 py-0.5 rounded-full">{Math.round(voiceSettings.rate * 100)}%</span>
                         </div>
                         <input 
                            type="range" min="0.5" max="1.5" step="0.1" 
                            value={voiceSettings.rate} 
                            onChange={e => {
                               const val = parseFloat(e.target.value);
                               const s={...voiceSettings, rate:val}; 
                               setVoiceSettings(s); 
                               saveVoiceSettings(s);
                            }}
                            onMouseUp={() => triggerVoiceFeedback('rate')}
                            onTouchEnd={() => triggerVoiceFeedback('rate')}
                            className="w-full h-2 bg-slate-100 rounded-full appearance-none cursor-pointer accent-indigo-600"
                         />
                       </div>

                       {/* Control de Tono (Pitch) */}
                       <div className="space-y-4">
                         <div className="flex justify-between items-end">
                           <div className="flex items-center gap-2">
                             <label className="text-sm font-elegant font-bold text-slate-700 tracking-tight">Color de la Voz</label>
                             {voiceSettings.pitch !== DEFAULT_PITCH && (
                               <button onClick={() => resetSetting('pitch')} className="w-6 h-6 rounded-full bg-fuchsia-50 text-fuchsia-500 flex items-center justify-center text-xs animate-in zoom-in">↺</button>
                             )}
                           </div>
                           <span className="text-[10px] font-bold text-fuchsia-400 bg-fuchsia-50 px-2 py-0.5 rounded-full">{Math.round(voiceSettings.pitch * 100)}%</span>
                         </div>
                         <input 
                            type="range" min="0.5" max="1.5" step="0.1" 
                            value={voiceSettings.pitch} 
                            onChange={e => {
                               const val = parseFloat(e.target.value);
                               const s={...voiceSettings, pitch:val}; 
                               setVoiceSettings(s); 
                               saveVoiceSettings(s);
                            }} 
                            onMouseUp={() => triggerVoiceFeedback('pitch')}
                            onTouchEnd={() => triggerVoiceFeedback('pitch')}
                            className="w-full h-2 bg-slate-100 rounded-full appearance-none cursor-pointer accent-fuchsia-600"
                         />
                       </div>
                     </div>
                   ) : (
                     <div className="space-y-2">
                       {categorizedVoices.elite.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 transition-all active:scale-98 cursor-pointer ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white shadow-lg' : 'bg-white border-slate-50 text-slate-700'}`}>
                           <span className="font-bold font-elegant">{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                       {categorizedVoices.backup.map(v => (
                         <div key={v.voiceURI} onClick={() => handleVoiceSelect(v)} className={`p-4 rounded-xl border-2 transition-all active:scale-98 cursor-pointer ${voiceSettings.voiceURI === v.voiceURI ? 'bg-slate-900 border-slate-900 text-white' : 'bg-slate-50 border-transparent text-slate-500'}`}>
                           <span className="font-elegant">{v.name.replace(/Microsoft|Google|English|en-US/g, '').trim()}</span>
                         </div>
                       ))}
                     </div>
                   )}
                </div>
                <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold text-lg active:scale-95 transition-transform">Guardar y Cerrar</button>
              </>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise, stopAudio } from '../geminiService';
import { getMeaning, getSynonyms, saveLists, loadLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  backgroundImage?: string;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, backgroundImage, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);
  const [attempts, setAttempts] = useState(0);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      stopAudio(); 
    };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;

    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setValidationStatus('none');
    setShowNextButton(false);
    setIsTransitioning(false);
    setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));

    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
    } catch (e) {
      console.warn("Speech synthesis error");
    }

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex, listId]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || (validationStatus === 'incorrect' && showNextButton)) return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      try {
        await speakWordPromise(letterObj.char, 'en-US', true);
      } catch(e) {}

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots);
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const updateGlobalWordStats = (isCorrect: boolean, isFinalAttempt: boolean) => {
    const allLists = loadLists();
    const targetList = allLists.find(l => l.id === listId);
    if (targetList) {
      const wordInMain = targetList.words.find(w => w.original === currentWord.original);
      if (wordInMain) {
        if (!isCorrect) {
          wordInMain.errors += 1;
        }
        if (isCorrect || isFinalAttempt) {
          wordInMain.completed = true;
        }
        saveLists(allLists);
      }
    }
  };

  const handleCompletion = async (currentSlots: (string | null)[]) => {
    const constructed = currentSlots.join('');
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true); 

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      updateGlobalWordStats(true, true);
      await playSuccessSequence();
    } else {
      const newAttemptCount = attempts + 1;
      setAttempts(newAttemptCount);
      setValidationStatus('incorrect');
      updateGlobalWordStats(false, newAttemptCount >= 2);

      if (newAttemptCount === 1) {
        try {
          await speakWordPromise(currentWord.original, 'en-US', true);
          await new Promise(resolve => setTimeout(resolve, 800));
        } catch(e) {}

        if (isMounted.current) {
          const lettersToReturn = currentSlots.filter(s => s !== null).map(s => ({ 
            char: s!, 
            id: Math.random().toString() 
          }));

          setSlots(new Array(currentWord.original.length).fill(null));
          setAvailableLetters(lettersToReturn);
          setValidationStatus('none');
          setIsAudioLocked(false);
        }
      } else {
        await playSuccessSequence();
      }
    }
  };

  const playSuccessSequence = async () => {
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;

    setShowRevelation(true);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));

      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 300));

      if (isMounted.current) {
        await speakWordPromise(currentWord.original, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 500));
    } catch(e) {}

    if (isMounted.current) { 
      setShowNextButton(true); 
      setIsAudioLocked(false); 
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (isAudioLocked && !showNextButton) return;

    stopAudio();
    setIsTransitioning(true);

    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  // Dinamismo para las cajas de letras basado en el largo de la palabra
  const wordLength = slots.length;
  const isWordLong = wordLength > 8;

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { stopAudio(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8 w-full">
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-20 h-20 bg-white/70 backdrop-blur-md rounded-full flex items-center justify-center shadow-xl transition-all mb-6 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/50'}`}>
              <span className="text-4xl">🔊</span>
            </button>
            <div className="h-32 px-4 text-center flex flex-col items-center justify-start w-full">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center max-w-lg">
                  <h2 className="text-3xl sm:text-4xl font-elegant font-bold text-slate-800 uppercase tracking-widest mb-2">{currentWord.original}</h2>
                  <div className="bg-white/40 backdrop-blur-sm rounded-xl p-3 border border-white/50 shadow-sm">
                    <p className="text-base font-semibold text-slate-700 leading-snug">{getMeaning(currentWord.original)}</p>
                    <p className="text-xs text-slate-500 mt-1 flex items-center justify-center gap-1">
                      <span className="opacity-50">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-6 py-2 bg-rose-100/80 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold shadow-sm">
                  {attempts === 1 ? 'Escucha con atención' : 'Aprendamos juntos'}
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-[0.3em] mt-2 animate-pulse">Modo Repaso</span>
              )}
            </div>
        </div>

        {/* CONTENEDOR DE SLOTS (Una sola fila horizontal con escalado) */}
        <div className="flex flex-nowrap gap-1 sm:gap-2 justify-center px-4 w-full overflow-hidden my-6">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`flex-1 max-w-[48px] sm:max-w-[60px] min-w-[24px] aspect-[4/5] rounded-xl border-2 flex items-center justify-center text-xl sm:text-3xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char?.toUpperCase()}
            </div>
          ))}
        </div>

        {/* CONTENEDOR DE TECLAS (Una sola fila horizontal con escalado) */}
        <div className={`w-full px-4 pb-20 flex flex-nowrap gap-1 sm:gap-2 justify-center items-end min-h-[140px] transition-opacity duration-300 overflow-hidden ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`flex-1 max-w-[56px] sm:max-w-[72px] min-w-[32px] aspect-square bg-white rounded-2xl shadow-xl flex items-center justify-center text-xl sm:text-3xl font-bold text-slate-800 transition-all border-b-4 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char.toUpperCase()}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-10 right-8 z-[110] w-20 h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors"
          aria-label="Siguiente palabra"
        >
          <svg width="36" height="36" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise, stopAudio } from '../geminiService';
import { getMeaning, getSynonyms, saveLists, loadLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  backgroundImage?: string;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, backgroundImage, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);
  const [attempts, setAttempts] = useState(0);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      stopAudio(); 
    };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;

    setIsAudioLocked(true);
    setIsReadyToPlay(false);
    setShowRevelation(false);
    setValidationStatus('none');
    setShowNextButton(false);
    setIsTransitioning(false);
    setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);

    if (chars.length > 1) {
       while(shuffled.map(s => s.char).join('') === currentWord.original) {
         shuffled = [...chars].sort(() => Math.random() - 0.5);
       }
    }

    setSlots(new Array(currentWord.original.length).fill(null));

    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;

    setAvailableLetters(shuffled);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
    } catch (e) {
      console.warn("Speech synthesis error");
    }

    if (isMounted.current) {
      setIsReadyToPlay(true);
      setIsAudioLocked(false);
    }
  };

  useEffect(() => {
    initWord();
  }, [currentIndex, listId]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || (validationStatus === 'incorrect' && showNextButton)) return;
    setIsAudioLocked(true); 

    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      const newSlots = [...slots];
      newSlots[nextEmpty] = letterObj.char;
      setSlots(newSlots);

      const newAvailable = [...availableLetters];
      newAvailable.splice(index, 1);
      setAvailableLetters(newAvailable);

      try {
        await speakWordPromise(letterObj.char, 'en-US', true);
      } catch(e) {}

      if (newSlots.indexOf(null) === -1) {
        handleCompletion(newSlots);
      } else {
        setIsAudioLocked(false);
      }
    } else {
      setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots];
    newSlots[index] = null;
    setSlots(newSlots);
    setValidationStatus('none'); 
    setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const updateGlobalWordStats = (isCorrect: boolean, isFinalAttempt: boolean) => {
    const allLists = loadLists();
    const targetList = allLists.find(l => l.id === listId);
    if (targetList) {
      const wordInMain = targetList.words.find(w => w.original === currentWord.original);
      if (wordInMain) {
        if (!isCorrect) {
          wordInMain.errors += 1;
        }
        if (isCorrect || isFinalAttempt) {
          wordInMain.completed = true;
        }
        saveLists(allLists);
      }
    }
  };

  const handleCompletion = async (currentSlots: (string | null)[]) => {
    const constructed = currentSlots.join('');
    const isActuallyCorrect = constructed.toLowerCase() === currentWord.original.toLowerCase();
    setIsAudioLocked(true); 

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      updateGlobalWordStats(true, true);
      await playSuccessSequence();
    } else {
      const newAttemptCount = attempts + 1;
      setAttempts(newAttemptCount);
      setValidationStatus('incorrect');
      updateGlobalWordStats(false, newAttemptCount >= 2);

      if (newAttemptCount === 1) {
        try {
          await speakWordPromise(currentWord.original, 'en-US', true);
          await new Promise(resolve => setTimeout(resolve, 800));
        } catch(e) {}

        if (isMounted.current) {
          const lettersToReturn = currentSlots.filter(s => s !== null).map(s => ({ 
            char: s!, 
            id: Math.random().toString() 
          }));

          setSlots(new Array(currentWord.original.length).fill(null));
          setAvailableLetters(lettersToReturn);
          setValidationStatus('none');
          setIsAudioLocked(false);
        }
      } else {
        await playSuccessSequence();
      }
    }
  };

  const playSuccessSequence = async () => {
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;

    setShowRevelation(true);

    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));

      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 300));

      if (isMounted.current) {
        await speakWordPromise(currentWord.original, 'en-US', false);
      }

      await new Promise(resolve => setTimeout(resolve, 500));
    } catch(e) {}

    if (isMounted.current) { 
      setShowNextButton(true); 
      setIsAudioLocked(false); 
    }
  };

  const nextWord = (e?: React.MouseEvent) => {
    if (e) {
      e.preventDefault();
      e.stopPropagation();
    }

    if (isAudioLocked && !showNextButton) return;

    stopAudio();
    setIsTransitioning(true);

    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        onExit();
      }
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] select-none overflow-hidden transition-all duration-500 ${isTransitioning ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}
         style={{ backgroundImage: backgroundImage ? `url(${backgroundImage})` : 'none', backgroundSize: 'cover', backgroundPosition: 'center' }}>

      <div className={`absolute inset-0 pointer-events-none transition-colors duration-1000 ${mode === 'repaso' ? 'bg-indigo-900/15' : 'bg-white/10'} backdrop-blur-3xl`}></div>

      <button onClick={() => { stopAudio(); onExit(); }} className="fixed top-4 right-4 z-[100] w-12 h-12 flex items-center justify-center bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm mt-[env(safe-area-inset-top)] active:scale-90">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        <div className="flex flex-col items-center pt-8 w-full">
            {/* BOCINA HEROICA (Aumentada de w-20 a w-28) */}
            <button 
              disabled={isAudioLocked}
              onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
              className={`w-28 h-28 bg-white/75 backdrop-blur-md rounded-full flex items-center justify-center shadow-2xl transition-all mb-8 border-4 border-white/50 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-emerald-200/60'}`}>
              <span className="text-6xl drop-shadow-sm">🔊</span>
            </button>

            <div className="h-40 px-4 text-center flex flex-col items-center justify-start w-full">
              {showRevelation && (
                <div className="animate-in fade-in zoom-in-95 duration-700 flex flex-col items-center max-w-lg w-full">
                  {/* PALABRA GIGANTE */}
                  <h2 className="text-5xl sm:text-6xl font-elegant font-bold text-slate-800 uppercase tracking-widest mb-4 drop-shadow-sm">{currentWord.original}</h2>

                  {/* CONTENEDOR DE REVELACIÓN ESCALADO */}
                  <div className="bg-white/50 backdrop-blur-md rounded-[2.5rem] p-6 sm:p-8 border border-white/60 shadow-xl w-full">
                    <p className="text-xl sm:text-2xl font-bold text-slate-700 leading-tight mb-3">{getMeaning(currentWord.original)}</p>
                    <p className="text-sm sm:text-lg text-slate-500 flex items-center justify-center gap-2 font-medium">
                      <span className="opacity-40 text-lg">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  </div>
                </div>
              )}
              {validationStatus === 'incorrect' && !showRevelation && (
                <div className="animate-in fade-in slide-in-from-bottom-4 px-8 py-3 bg-rose-100/90 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold text-lg shadow-md">
                  {attempts === 1 ? 'Escucha con atención' : 'Aprendamos juntos'}
                </div>
              )}
              {mode === 'repaso' && !showRevelation && validationStatus === 'none' && (
                <span className="text-xs font-bold text-indigo-500 uppercase tracking-[0.4em] mt-2 animate-pulse bg-indigo-50/50 px-4 py-1 rounded-full border border-indigo-100/50">Modo Repaso</span>
              )}
            </div>
        </div>

        {/* CONTENEDOR DE SLOTS (Una sola fila horizontal con escalado) */}
        <div className="flex flex-nowrap gap-1 sm:gap-2 justify-center px-4 w-full overflow-hidden my-6">
          {slots.map((char, i) => (
            <div key={i} onClick={() => handleSlotClick(i)}
              className={`flex-1 max-w-[50px] sm:max-w-[64px] min-w-[26px] aspect-[4/5] rounded-2xl border-2 flex items-center justify-center text-2xl sm:text-4xl font-bold transition-all duration-300
                ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-lg text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/50'}`}>
              {char?.toUpperCase()}
            </div>
          ))}
        </div>

        {/* CONTENEDOR DE TECLAS (Una sola fila horizontal con escalado) */}
        <div className={`w-full px-4 pb-24 flex flex-nowrap gap-1 sm:gap-2 justify-center items-end min-h-[140px] transition-opacity duration-300 overflow-hidden ${isAudioLocked && !showNextButton ? 'opacity-50 pointer-events-none' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`flex-1 max-w-[58px] sm:max-w-[76px] min-w-[34px] aspect-square bg-white rounded-2xl shadow-xl flex items-center justify-center text-2xl sm:text-4xl font-bold text-slate-800 transition-all border-b-8 border-slate-200 active:border-b-0 active:translate-y-2 animate-bounce-drop
                  ${isReadyToPlay && !isAudioLocked ? 'ring-4 ring-emerald-400/20' : ''}`}>
              {letterObj.char.toUpperCase()}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button 
          onClick={nextWord} 
          className="fixed bottom-12 right-10 z-[110] w-24 h-24 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 mb-[env(safe-area-inset-bottom)] active:scale-90 hover:bg-emerald-600 transition-colors border-4 border-white/20"
          aria-label="Siguiente palabra"
        >
          <svg width="42" height="42" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

const CACHE_NAME = 'echofy-v1';
const ASSETS = [
  './',
  './index.html',
  './index.tsx',
  './manifest.json',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Outfit:wght@300;400;600&family=Quicksand:wght@400;600;700&display=swap'
];

self.addEventListener('install', (e) => {
  e.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (e) => {
  e.respondWith(
    caches.match(e.request).then((res) => res || fetch(e.request))
  );
});

export interface Word {
  original: string;
  id: string;
  errors: number;
  completed: boolean;
}

export interface WordList {
  id: string;
  name: string;
  words: Word[];
  themeIndex: number;
  lastPlayed?: number;
  settings: {
    rainEnabled: boolean;
  };
}

export type AppRole = 'parent' | 'child';

export interface GameSession {
  listId: string;
  words: Word[];
  mode: 'normal' | 'repaso';
}

export interface VoiceSettings {
  voiceURI: string | null;
  rate: number;
  pitch: number;
}

import React, { useState, useEffect } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings, getMeaning, THEMES } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
}

const DEFAULT_RATE = 0.8;
const DEFAULT_PITCH = 1.1;

const ParentDashboard: React.FC<Props> = ({ onStartGame, role }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [selectedTheme, setSelectedTheme] = useState(0);
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [isHelpOpen, setIsHelpOpen] = useState(false);
  const [voiceViewMode, setVoiceViewMode] = useState<'settings' | 'list'>('settings');
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  const handleSaveList = () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, themeIndex: selectedTheme, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, themeIndex: selectedTheme, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
  };

  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false); setSelectedTheme(0);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);
  const isUsingBackup = currentVoice ? !isPremiumVoice(currentVoice) : categorizedVoices.elite.length === 0;

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      setVoiceViewMode('settings');
      speakWordPromise("Voice updated", 'en-US', true);
  };

  const triggerVoiceFeedback = (type: 'rate' | 'pitch') => {
    const text = type === 'rate' ? "Testing speed" : "Testing tone";
    speakWordPromise(text, 'en-US', true);
  };

  const resetSetting = (type: 'rate' | 'pitch') => {
    const newVal = type === 'rate' ? DEFAULT_RATE : DEFAULT_PITCH;
    const s = { ...voiceSettings, [type]: newVal };
    setVoiceSettings(s);
    saveVoiceSettings(s);
    triggerVoiceFeedback(type);
  };

  const renderParentView = () => (
    <div className="animate-in fade-in duration-700 space-y-4">
      {isAdding ? (
        <div className="space-y-6 pb-20">
          <div className="bg-white p-6 rounded-[2.5rem] shadow-2xl border border-slate-50 space-y-4 animate-in slide-in-from-bottom-4">
            <div className="flex justify-between items-center">
              <h2 className="text-xl font-elegant font-semibold text-slate-700">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
              <button onClick={resetForm} className="w-8 h-8 rounded-full bg-slate-50 flex items-center justify-center text-slate-400">×</button>
            </div>

            <input className="w-full p-4 rounded-2xl bg-slate-50 text-lg font-bold placeholder:font-normal" placeholder="Nombre de la aventura..." value={newListName} onChange={e => setNewListName(e.target.value)} />

            <div className="space-y-2">
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-2">Elige un Mundo</p>
              <div className="grid grid-cols-3 gap-2">
                {THEMES.map(theme => (
                  <button key={theme.id} onClick={() => setSelectedTheme(theme.id)} 
                          className={`h-12 rounded-xl bg-gradient-to-br ${theme.gradient} border-4 transition-all ${selectedTheme === theme.id ? 'border-slate-800 scale-105' : 'border-transparent opacity-60'}`}>
                  </button>
                ))}
              </div>
            </div>

            <textarea className="w-full p-4 h-32 rounded-2xl bg-slate-50 text-lg leading-relaxed placeholder:font-normal" placeholder="Palabras separadas por espacios..." value={inputText} onChange={e => setInputText(e.target.value)} />
            <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-transform">Guardar Cambios</button>
          </div>
        </div>
      ) : (
        <>
          <button onClick={() => setIsAdding(true)} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold">+ Nueva Aventura</button>
          {lists.map(list => (
            <div key={list.id} className="relative group mb-4">
              <div onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setSelectedTheme(list.themeIndex); setInputText(list.words.map(w => w.original).join(' ')); }} 
                   className="bg-white p-5 pr-20 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
                <div className="flex items-center gap-4">
                  <div className={`w-14 h-14 rounded-3xl bg-gradient-to-br ${THEMES[list.themeIndex]?.gradient || THEMES[0].gradient} flex items-center justify-center text-2xl shadow-inner group-hover:scale-105 transition-transform`}>📝</div>
                  <div>
                    <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                    <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
                  </div>
                </div>
              </div>
              <button onClick={(e) => { e.stopPropagation(); setViewingReportId(list.id); }}
                className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-indigo-100">
                📈
              </button>
            </div>
          ))}
        </>
      )}
    </div>
  );

  const renderChildView = () => (
    <div className="animate-in fade-in duration-700 space-y-6">
      <div className="grid grid-cols-2 gap-4">
        {lists.map((list) => {
          const progress = (list.words.filter(w => w.completed).length / list.words.length) * 100;
          const theme = THEMES[list.themeIndex] || THEMES[0];
          return (
            <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                 className="relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden">
              <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} transition-transform group-hover:scale-110`}></div>
              <div className="absolute inset-0 bg-black/5"></div>
              <div className="relative h-full flex flex-col justify-between z-10">
                <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg">🌎</div>
                <div>
                  <h3 className="text-white font-bold text-lg leading-tight mb-2 drop-shadow-md">{list.name}</h3>
                  <div className="w-full h-1.5 bg-black/10 rounded-full overflow-hidden">
                    <div className="h-full bg-white transition-all duration-1000" style={{ width: `${Math.max(5, progress)}%` }}></div>
                  </div>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );

  return (
