import React, { useState, useEffect, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise, stopAudio } from '../geminiService';
import { getMeaning, getSynonyms, THEMES, loadLists, saveLists } from '../store';

interface Props {
  listId: string;
  words: Word[];
  themeIndex: number;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, themeIndex, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [isReadyToPlay, setIsReadyToPlay] = useState(false); 
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [showNextButton, setShowNextButton] = useState(false);
  const [attempts, setAttempts] = useState(0);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];
  const theme = THEMES[themeIndex] || THEMES[0];

  // Cálculo de tamaño dinámico para los recuadros de la palabra
  const wordLength = currentWord?.original.length || 1;
  const getSlotSizeClass = () => {
    if (wordLength > 10) return 'w-7 h-9 text-xl sm:w-8 sm:h-10 sm:text-2xl';
    if (wordLength > 7) return 'w-9 h-12 text-2xl sm:w-11 sm:h-14 sm:text-3xl';
    return 'w-12 h-16 text-3xl sm:w-16 sm:h-20 sm:text-4xl';
  };

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; stopAudio(); };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;
    setIsAudioLocked(true); setIsReadyToPlay(false); setShowRevelation(false);
    setValidationStatus('none'); setShowNextButton(false); setIsTransitioning(false); setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    while(shuffled.map(s => s.char).join('') === currentWord.original && chars.length > 1) {
      shuffled = [...chars].sort(() => Math.random() - 0.5);
    }

    setSlots(new Array(currentWord.original.length).fill(null));
    await new Promise(resolve => setTimeout(resolve, 400));
    if (!isMounted.current) return;
    setAvailableLetters(shuffled);
    try { await speakWordPromise(currentWord.original, 'en-US', true); } catch (e) {}
    if (isMounted.current) { setIsReadyToPlay(true); setIsAudioLocked(false); }
  };

  useEffect(() => { initWord(); }, [currentIndex, listId]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;
    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      setIsAudioLocked(true);
      const newSlots = [...slots]; newSlots[nextEmpty] = letterObj.char; setSlots(newSlots);
      const newAvailable = [...availableLetters]; newAvailable.splice(index, 1); setAvailableLetters(newAvailable);
      try { await speakWordPromise(letterObj.char, 'en-US', true); } catch(e) {}
      if (newSlots.indexOf(null) === -1) handleCompletion(newSlots); else setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    const char = slots[index]!;
    const newSlots = [...slots]; newSlots[index] = null; setSlots(newSlots);
    setValidationStatus('none'); setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (currentSlots: (string | null)[]) => {
    const constructed = currentSlots.join('').toLowerCase();
    const isActuallyCorrect = constructed === currentWord.original.toLowerCase();
    setIsAudioLocked(true); 

    if (isActuallyCorrect) {
      setValidationStatus('correct');
      updateStats(true);
      await playSuccessSequence();
    } else {
      const newAttemptCount = attempts + 1;
      setAttempts(newAttemptCount);
      setValidationStatus('incorrect');
      if (newAttemptCount === 1) {
        await new Promise(resolve => setTimeout(resolve, 800));
        if (isMounted.current) {
          setSlots(new Array(currentWord.original.length).fill(null));
          setAvailableLetters(currentSlots.map(s => ({ char: s!, id: Math.random().toString() })));
          setValidationStatus('none'); setIsAudioLocked(false);
        }
      } else {
        updateStats(false);
        await playSuccessSequence();
      }
    }
  };

  const updateStats = (correct: boolean) => {
    const lists = loadLists();
    const list = lists.find(l => l.id === listId);
    if (list) {
      const word = list.words.find(w => w.original === currentWord.original);
      if (word) {
        if (!correct) word.errors += 1;
        word.completed = true;
        saveLists(lists);
      }
    }
  };

  const playSuccessSequence = async () => {
    await new Promise(resolve => setTimeout(resolve, 600));
    if (!isMounted.current) return;
    setShowRevelation(true);
    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));
      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }
      await new Promise(resolve => setTimeout(resolve, 400));
      await speakWordPromise(currentWord.original, 'en-US', false);
    } catch(e) {}
    if (isMounted.current) { setShowNextButton(true); setIsAudioLocked(false); }
  };

  const nextWord = () => {
    setIsTransitioning(true);
    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) setCurrentIndex(prev => prev + 1); else onExit();
    }, 500);
  };

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] transition-all duration-500 overflow-hidden ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}>
      <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} opacity-20`}></div>
      <div className={`absolute inset-0 ${theme.bg}`}></div>

      <button onClick={onExit} className="fixed top-4 right-4 z-[100] w-10 h-10 bg-white/40 backdrop-blur-md rounded-full text-slate-600 shadow-sm active:scale-90 flex items-center justify-center font-bold">✕</button>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10">
        {/* Zona Superior: Audio e Info */}
        <div className="flex flex-col items-center w-full px-6 flex-1 justify-center">
          <button disabled={isAudioLocked} onClick={() => !isAudioLocked && speakWordPromise(currentWord.original, 'en-US', true)}
            className={`w-24 h-24 sm:w-32 sm:h-32 bg-white rounded-full flex items-center justify-center shadow-2xl transition-all mb-4 border-4 border-white/50 ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-indigo-200/60 animate-glow-signal'}`}>
            <span className="text-5xl sm:text-7xl">🔊</span>
          </button>

          <div className="min-h-[140px] flex items-center justify-center w-full">
            {showRevelation ? (
              <div className="animate-in fade-in zoom-in-95 duration-700 w-full px-4">
                <h2 className={`font-elegant font-bold text-slate-800 uppercase tracking-widest mb-2 drop-shadow-sm text-center ${wordLength > 8 ? 'text-3xl' : 'text-4xl sm:text-5xl'}`}>
                  {currentWord.original}
                </h2>
                <div className="bg-white/60 backdrop-blur-md rounded-3xl p-4 sm:p-6 border border-white/80 shadow-lg max-w-sm mx-auto">
                  <p className="text-lg sm:text-xl font-bold text-slate-700 leading-tight mb-2">{getMeaning(currentWord.original)}</p>
                  <p className="text-sm text-slate-500 flex items-center justify-center gap-2">
                    <span className="opacity-40">🔗</span> {getSynonyms(currentWord.original)}
                  </p>
                </div>
              </div>
            ) : validationStatus === 'incorrect' && (
              <div className="animate-in fade-in slide-in-from-bottom-4 px-8 py-3 bg-rose-100/90 backdrop-blur-sm rounded-full border border-rose-200 text-rose-600 font-bold text-lg shadow-md">
                ¡Escucha con atención!
              </div>
            )}
          </div>
        </div>

        {/* Zona Media: Palabra a Construir (Slots) */}
        <div className="w-full px-2 mb-6">
          <div className="flex flex-wrap gap-1 sm:gap-2 justify-center w-full">
            {slots.map((char, i) => (
              <div key={i} onClick={() => handleSlotClick(i)}
                className={`rounded-xl sm:rounded-2xl border-2 flex items-center justify-center font-bold transition-all duration-300 ${getSlotSizeClass()}
                  ${char ? (validationStatus === 'incorrect' ? 'bg-rose-50 border-rose-200 text-rose-500' : validationStatus === 'correct' ? 'bg-emerald-50 border-emerald-200 text-emerald-600' : 'bg-white border-slate-100 shadow-xl text-slate-800') : 'bg-slate-900/5 border-dashed border-slate-300/40'}`}>
                {char?.toUpperCase()}
              </div>
            ))}
          </div>
        </div>

        {/* Zona Inferior: Teclado de Letras Disponibles */}
        <div className={`w-full px-4 pb-12 flex flex-wrap gap-2 justify-center content-center min-h-[120px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-40' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className="w-12 h-12 sm:w-16 sm:h-16 bg-white rounded-xl sm:rounded-2xl shadow-lg flex items-center justify-center text-2xl sm:text-3xl font-bold text-slate-800 border-b-4 sm:border-b-8 border-slate-200 active:border-b-0 active:translate-y-1 animate-bounce-drop">
              {letterObj.char.toUpperCase()}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button onClick={nextWord} 
          className="fixed bottom-6 right-6 z-[110] w-16 h-16 sm:w-20 sm:h-20 bg-emerald-500 text-white rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 active:scale-90 border-4 border-white/20">
          <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

