                <h2 className={`font-elegant font-bold text-slate-800 uppercase tracking-widest mb-1 drop-shadow-sm text-center ${wordLength > 8 ? 'text-2xl sm:text-4xl' : 'text-3xl sm:text-5xl'}`}>
                  {currentWord.original}
                </h2>
                <div className="bg-white/60 backdrop-blur-md rounded-[2rem] p-4 sm:p-5 border border-white/80 shadow-lg max-w-sm mx-auto">
