        </div>

        {/* Zona Inferior: Teclado de Letras (Wrap Activado) */}
        <div className={`w-full px-4 pb-10 flex flex-wrap gap-2 justify-center content-center min-h-[140px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-40' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
