  const wordLength = currentWord?.original.length || 1;
  const getSlotSizeClass = () => {
    // Escalamiento agresivo para mantener una sola fila
    if (wordLength > 12) return 'w-[6.5vw] h-[8vw] text-base sm:w-8 sm:h-10 sm:text-lg';
    if (wordLength > 10) return 'w-[8vw] h-[10vw] text-xl sm:w-10 sm:h-12 sm:text-2xl';
    if (wordLength > 8) return 'w-[10vw] h-[13vw] text-2xl sm:w-12 sm:h-16 sm:text-3xl';
    if (wordLength > 6) return 'w-[13vw] h-[17vw] text-3xl sm:w-16 sm:h-20 sm:text-4xl';
