        </div>
        {subtitle && <p className="text-[9px] text-slate-300 italic mt-0.5">{subtitle}</p>}
      </div>
    );

    return (
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 mb-6">
        {criticas.length > 0 && (
          <div className="animate-in fade-in">
            <SectionHeader title="Retos Críticos" count={criticas.length} subtitle="Alerta, situación por resolver" />
            <div className="space-y-2">
              {criticas.map(w => <WordItem key={w.id} word={w} type="critical" />)}
            </div>
          </div>
        )}

        {enProceso.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-2">
            <SectionHeader title="En Proceso" count={enProceso.length} subtitle="Qué paso ahí? Después lo hiciste bien" />
            <div className="space-y-2">
              {enProceso.map(w => <WordItem key={w.id} word={w} type="process" />)}
            </div>
          </div>
        )}

        {dominadas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-3">
            <SectionHeader title="Dominadas" count={dominadas.length} subtitle="Confianza total" />
            <div className="space-y-2">
              {dominadas.map(w => <WordItem key={w.id} word={w} type="mastered" />)}
            </div>
          </div>
        )}

        {noVistas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-4">
            <SectionHeader title="Por Descubrir" count={noVistas.length} />
            <div className="space-y-2">
              {noVistas.map(w => (
                <div key={w.id} className="p-4 bg-white rounded-2xl border border-dashed border-slate-100 flex justify-between items-center opacity-40">
                  <span className="font-semibold text-slate-400 capitalize">{w.original}</span>
                  <span className="text-[10px] font-bold text-slate-200">NUEVA</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="mt-12 mb-6 px-1">
           <button onClick={() => handleResetProgress(viewingReportId!)} 
             className="w-full py-4 rounded-2xl border-2 border-dashed border-slate-200 text-slate-400 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 active:scale-95 transition-all">
             Reiniciar Todo el Progreso
           </button>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      <header className="flex flex-col items-center mb-10 mt-6">
        <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
        <div className="h-1 w-12 bg-slate-200 rounded-full mb-8"></div>
        {role === 'parent' && (
          <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 active:scale-95 transition-all">
            <div className="flex items-center gap-3">
              <span className="text-lg">🔊</span>
              <div className="flex flex-col items-start min-w-0">
                <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300 text-left">Voz actual</span>
                <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
              </div>
            </div>
          </button>
        )}
      </header>

      {role === 'child' ? renderChildView() : renderParentView()}

      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => setIsVoiceStudioOpen(false)}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold mb-6">Estudio de Voz</h2>
            <div className="flex-1 overflow-y-auto space-y-6 custom-scrollbar pr-1">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Ritmo</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} 
                       onChange={e => { const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('rate')} onTouchEnd={() => triggerVoiceFeedback('rate')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-indigo-600" />
              </div>
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Tono</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} 
                       onChange={e => { const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('pitch')} onTouchEnd={() => triggerVoiceFeedback('pitch')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-fuchsia-600" />
              </div>
              <div className="space-y-2">
                <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Voces en el dispositivo</p>
                {categorizedVoices.elite.concat(categorizedVoices.backup).map(v => (
                  <button key={v.voiceURI} onClick={() => handleVoiceSelect(v)} 
                          className={`w-full p-4 rounded-xl text-left border-2 transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-slate-50 border-transparent text-slate-600'}`}>
                    <span className="font-bold text-sm">{v.name.replace(/Google|Microsoft|English|en-US/gi, '').trim()}</span>
                  </button>
                ))}
              </div>
            </div>
            <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
          </div>
        </div>
      )}

      {viewingReportId && (
        <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-center p-0 sm:p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingReportId(null)}></div>
          <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 shadow-2xl relative z-20 animate-in slide-in-from-bottom-20 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold text-slate-800 mb-1">Estado de Aprendizaje</h2>
            <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest mb-4">Progreso de la aventura</p>
            {renderReportList()}
            <button onClick={() => setViewingReportId(null)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold active:scale-95 transition-transform">Volver</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings, getMeaning, THEMES, resetListProgress, PRACTICE_THEME, getBackupData, restoreBackupData } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
  onModalStateChange: (isOpen: boolean) => void;
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role, onModalStateChange }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [selectedTheme, setSelectedTheme] = useState(0);
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  // Estado para Configuración / Backup
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Estado para Toasts (Notificaciones)
  const [toast, setToast] = useState<{msg: string, type: 'success' | 'info'} | null>(null);

  useEffect(() => {
    setLists(loadLists());
    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  // Notificar a App.tsx si algún modal está abierto
  useEffect(() => {
    const isAnyModalOpen = isAdding || !!viewingReportId || isVoiceStudioOpen || isSettingsOpen;
    onModalStateChange(isAnyModalOpen);
  }, [isAdding, viewingReportId, isVoiceStudioOpen, isSettingsOpen, onModalStateChange]);

  const showToast = (msg: string, type: 'success' | 'info' = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleSaveList = () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, themeIndex: selectedTheme, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, themeIndex: selectedTheme, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
    showToast(editingListId ? "Mundo actualizado" : "Aventura creada");
  };

  const handleResetProgress = (id: string) => {
    if (window.confirm("¿Seguro que quieres reiniciar todo el progreso de este mundo?")) {
      const updated = resetListProgress(id);
      setLists(updated);
      showToast("Progreso reiniciado");
    }
  };

  // --- LOGICA DE BACKUP ---
  const handleExportBackup = () => {
    const data = getBackupData();
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = `echofy_respaldo_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast("Copia descargada", "info");
  };

  const handleImportClick = () => {
    if (fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (restoreBackupData(content)) {
        setLists(loadLists());
        setVoiceSettings(loadVoiceSettings());
        showToast("Datos restaurados correctamente");
        setIsSettingsOpen(false);
      } else {
        alert("El archivo no es válido o está dañado.");
      }
    };
    reader.readAsText(file);
    // Limpiar input para permitir seleccionar el mismo archivo de nuevo si falla
    e.target.value = ''; 
  };
  // -------------------------

  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false); setSelectedTheme(0);
  };

  const openNewListModal = () => {
    setNewListName(''); 
    setInputText(''); 
    setEditingListId(null); 
    setSelectedTheme(0);
    setIsAdding(true);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      speakWordPromise("Voice updated", 'en-US', true);
  };

  const triggerVoiceFeedback = (type: 'rate' | 'pitch') => {
    const text = type === 'rate' ? "Testing speed" : "Testing tone";
    speakWordPromise(text, 'en-US', true);
  };

  const renderParentView = () => (
    <div className="animate-in fade-in duration-700 space-y-4">
      <button onClick={openNewListModal} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold group hover:border-indigo-200 hover:bg-indigo-50/50">
        <span className="group-hover:text-indigo-400 transition-colors">+ Nueva Aventura</span>
      </button>

      {lists.map(list => (
        <div key={list.id} className="relative group mb-4">
          <div onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setSelectedTheme(list.themeIndex); setInputText(list.words.map(w => w.original).join(' ')); }} 
                className="bg-white p-5 pr-20 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-3xl bg-gradient-to-br ${THEMES[list.themeIndex]?.gradient || THEMES[0].gradient} flex items-center justify-center text-2xl shadow-inner group-hover:scale-105 transition-transform text-white shadow-black/10`}>📝</div>
              <div>
                <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
              </div>
            </div>
          </div>
          <button onClick={(e) => { e.stopPropagation(); setViewingReportId(list.id); }}
            className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-indigo-100">
            📈
          </button>
        </div>
      ))}

      {isAdding && (
        <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-end sm:items-center justify-center">
          <div className="w-full h-[95vh] sm:h-auto sm:max-h-[85vh] bg-[#fdfdfe] rounded-t-[2.5rem] sm:rounded-[3rem] shadow-2xl overflow-y-auto flex flex-col animate-in slide-in-from-bottom-20 duration-500">
            <div className="p-6 sticky top-0 bg-[#fdfdfe]/90 backdrop-blur-md z-10 border-b border-slate-50 flex justify-between items-center">
              <h2 className="text-2xl font-elegant font-bold text-slate-800">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
              <button onClick={resetForm} className="w-10 h-10 rounded-full bg-slate-100 text-slate-400 font-bold flex items-center justify-center active:scale-90 hover:bg-slate-200 transition-colors">✕</button>
            </div>

            <div className="p-6 space-y-8 pb-32">
              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Nombre de la Aventura</label>
                <input className="w-full p-5 rounded-2xl bg-slate-50 border border-slate-100 text-xl font-bold placeholder:font-normal placeholder:text-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                       placeholder="Ej: Animales del Bosque" value={newListName} onChange={e => setNewListName(e.target.value)} />
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Elige el Ambiente</label>
                <div className="grid grid-cols-3 gap-3">
                  {THEMES.map(theme => (
                    <button key={theme.id} onClick={() => setSelectedTheme(theme.id)} 
                            className={`h-16 rounded-2xl bg-gradient-to-br ${theme.gradient} border-4 transition-all shadow-sm ${selectedTheme === theme.id ? 'border-slate-800 scale-105 shadow-xl ring-2 ring-offset-2 ring-slate-200' : 'border-transparent opacity-70 hover:opacity-100'}`}>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Palabras (Separadas por espacio)</label>
                <textarea className="w-full p-5 h-48 rounded-2xl bg-slate-50 border border-slate-100 text-lg leading-relaxed placeholder:font-normal placeholder:text-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-100 transition-all font-medium text-slate-600" 
                          placeholder="gato perro sol luna..." value={inputText} onChange={e => setInputText(e.target.value)} />
              </div>

              <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-all shadow-xl shadow-slate-200 hover:shadow-2xl">
                {editingListId ? 'Guardar Cambios' : 'Crear Aventura'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderChildView = () => {
    // Buscar si hay alguna palabra en alguna lista que tenga errores (Modo Práctica disponible)
    const listsWithErrors = lists.filter(l => l.words.some(w => (w.errors || 0) > 0));
    const totalErrors = listsWithErrors.reduce((acc, l) => acc + l.words.filter(w => (w.errors || 0) > 0).length, 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-6">
        {/* ISLA DE PRÁCTICA - Solo visible si hay deudas de aprendizaje */}
        {totalErrors > 0 && (
          <div onClick={() => onStartGame(listsWithErrors[0].id, 'repaso')}
            className="w-full p-6 rounded-[3rem] bg-gradient-to-br from-indigo-900 via-purple-900 to-slate-900 shadow-2xl relative overflow-hidden group active:scale-95 transition-all mb-8 cursor-pointer border border-white/10">
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-20"></div>
            <div className="relative z-10 flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 bg-white/10 backdrop-blur-xl rounded-3xl flex items-center justify-center text-3xl shadow-lg border border-white/10 animate-levitate">✨</div>
                <div>
                  <h2 className="text-2xl font-bold text-white tracking-tight">Isla de Práctica</h2>
                  <p className="text-indigo-200 text-sm font-semibold">{totalErrors} palabras por rescatar</p>
                </div>
              </div>
              <div className="w-12 h-12 rounded-full bg-indigo-500/30 flex items-center justify-center text-white font-bold animate-pulse border border-white/10">
                ➜
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          {lists.map((list) => {
            const progress = (list.words.filter(w => w.completed && (w.errors || 0) === 0).length / list.words.length) * 100;
            const theme = THEMES[list.themeIndex] || THEMES[0];
            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className="relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden">
                <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} transition-transform group-hover:scale-110`}></div>
                <div className="absolute inset-0 bg-black/5 mix-blend-overlay"></div>
                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg border border-white/10">
                    <span className="drop-shadow-sm">🌎</span>
                  </div>
                  <div>
                    <h3 className="text-white font-bold text-lg leading-tight mb-2 drop-shadow-md">{list.name}</h3>
                    <div className="w-full h-1.5 bg-black/20 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white/90 shadow-[0_0_10px_rgba(255,255,255,0.5)] transition-all duration-1000" style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderReportList = () => {
    const list = lists.find(l => l.id === viewingReportId);
    if (!list) return null;

    const criticas = list.words.filter(w => w.completed && (w.errors || 0) >= 2);
    const enProceso = list.words.filter(w => w.completed && (w.errors || 0) === 1);
    const dominadas = list.words.filter(w => w.completed && (w.errors || 0) === 0);
    const noVistas = list.words.filter(w => !w.completed);

    const WordItem: React.FC<{ 
        word: Word, 
        type: 'critical' | 'process' | 'mastered' 
    }> = ({ word, type }) => {
        let config = {
            symbol: '✓',
            colorClass: 'text-emerald-500',
            bgClass: 'bg-emerald-50/50',
            borderClass: 'border-emerald-100/50'
        };

        if (type === 'critical') {
            config = {
                symbol: '!',
                colorClass: 'text-rose-500',
                bgClass: 'bg-rose-50/50',
                borderClass: 'border-rose-100/50'
            };
        } else if (type === 'process') {
            config = {
                symbol: '?',
                colorClass: 'text-amber-500',
                bgClass: 'bg-amber-50/50',
                borderClass: 'border-amber-100/50'
            };
        }

        return (
            <div className={`p-4 rounded-2xl flex justify-between items-center border ${config.bgClass} ${config.borderClass}`}>
                <span className="font-bold text-slate-700 capitalize">{word.original}</span>
                <div className="flex items-center gap-3">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Intentos</span>
                        <span className="text-xs font-bold text-slate-500">{(word.successes || 0) + (word.errors || 0)}</span>
                    </div>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-lg bg-white shadow-sm ${config.colorClass}`}>
                        {config.symbol}
                    </div>
                </div>
            </div>
        );
    };

    const SectionHeader: React.FC<{ title: string, count: number, subtitle?: string }> = ({ title, count, subtitle }) => (
      <div className="mt-8 mb-3 px-1">
        <div className="flex items-center justify-between">
            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">{title}</h3>
            <span className="bg-slate-100 text-slate-400 text-[9px] font-bold px-2 py-0.5 rounded-full">{count}</span>
        </div>
        {subtitle && <p className="text-[9px] text-slate-300 italic mt-0.5">{subtitle}</p>}
      </div>
    );

    return (
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 mb-6">
        {criticas.length > 0 && (
          <div className="animate-in fade-in">
            <SectionHeader title="Retos Críticos" count={criticas.length} subtitle="Alerta, situación por resolver" />
            <div className="space-y-2">
              {criticas.map(w => <WordItem key={w.id} word={w} type="critical" />)}
            </div>
          </div>
        )}

        {enProceso.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-2">
            <SectionHeader title="En Proceso" count={enProceso.length} subtitle="Qué paso ahí? Después lo hiciste bien" />
            <div className="space-y-2">
              {enProceso.map(w => <WordItem key={w.id} word={w} type="process" />)}
            </div>
          </div>
        )}

        {dominadas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-3">
            <SectionHeader title="Dominadas" count={dominadas.length} subtitle="Confianza total" />
            <div className="space-y-2">
              {dominadas.map(w => <WordItem key={w.id} word={w} type="mastered" />)}
            </div>
          </div>
        )}

        {noVistas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-4">
            <SectionHeader title="Por Descubrir" count={noVistas.length} />
            <div className="space-y-2">
              {noVistas.map(w => (
                <div key={w.id} className="p-4 bg-white rounded-2xl border border-dashed border-slate-100 flex justify-between items-center opacity-40">
                  <span className="font-semibold text-slate-400 capitalize">{w.original}</span>
                  <span className="text-[10px] font-bold text-slate-200">NUEVA</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="mt-12 mb-6 px-1">
           <button onClick={() => handleResetProgress(viewingReportId!)} 
             className="w-full py-4 rounded-2xl border-2 border-dashed border-slate-200 text-slate-400 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 active:scale-95 transition-all">
             Reiniciar Todo el Progreso
           </button>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      {/* HEADER CON BOTÓN DE AJUSTES */}
      <header className="flex items-center justify-between mb-10 mt-6 relative">
        <div className="w-10"></div> {/* Spacer */}
        <div className="flex flex-col items-center">
            <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
            <div className="h-1 w-12 bg-slate-200 rounded-full"></div>
        </div>
        {role === 'parent' ? (
             <button onClick={() => setIsSettingsOpen(true)} className="w-10 h-10 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center active:bg-slate-200 transition-colors">
                ⚙️
             </button>
        ) : <div className="w-10"></div>}
      </header>

      {role === 'parent' && (
          <div className="mb-8">
            <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 active:scale-95 transition-all">
                <div className="flex items-center gap-3">
                <span className="text-lg">🔊</span>
                <div className="flex flex-col items-start min-w-0">
                    <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300 text-left">Voz actual</span>
                    <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
                </div>
                </div>
            </button>
          </div>
      )}


      {role === 'child' ? renderChildView() : renderParentView()}

      {/* MODAL ESTUDIO DE VOZ */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => setIsVoiceStudioOpen(false)}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold mb-6">Estudio de Voz</h2>
            <div className="flex-1 overflow-y-auto space-y-6 custom-scrollbar pr-1">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Ritmo</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} 
                       onChange={e => { const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('rate')} onTouchEnd={() => triggerVoiceFeedback('rate')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-indigo-600" />
              </div>
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Tono</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} 
                       onChange={e => { const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('pitch')} onTouchEnd={() => triggerVoiceFeedback('pitch')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-fuchsia-600" />
              </div>
              <div className="space-y-2">
                <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Voces en el dispositivo</p>
                {categorizedVoices.elite.concat(categorizedVoices.backup).map(v => (
                  <button key={v.voiceURI} onClick={() => handleVoiceSelect(v)} 
                          className={`w-full p-4 rounded-xl text-left border-2 transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-slate-50 border-transparent text-slate-600'}`}>
                    <span className="font-bold text-sm">{v.name.replace(/Google|Microsoft|English|en-US/gi, '').trim()}</span>
                  </button>
                ))}
              </div>
            </div>
            <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN / RESPALDO */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl relative z-20 animate-in zoom-in-95 flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-slate-100 rounded-3xl flex items-center justify-center text-3xl mb-4">🛡️</div>
            <h2 className="text-2xl font-elegant font-bold text-slate-800 mb-2">Seguridad de Datos</h2>
            <p className="text-sm text-slate-400 font-medium mb-8 leading-relaxed">
               Guarda una copia de seguridad para no perder el progreso de tu hija si cambias de dispositivo.
            </p>

            <div className="w-full space-y-4">
                <button onClick={handleExportBackup} className="w-full py-4 bg-indigo-50 text-indigo-600 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all border border-indigo-100">
                    <span>💾</span> Guardar Copia de Seguridad
                </button>

                <div className="relative">
                    <input 
                        type="file" 
                        accept=".json" 
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        className="hidden" 
                    />
                    <button onClick={handleImportClick} className="w-full py-4 bg-white text-slate-500 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all border-2 border-dashed border-slate-200 hover:border-slate-300">
                        <span>📂</span> Restaurar Datos
                    </button>
                </div>
            </div>

            <button onClick={() => setIsSettingsOpen(false)} className="mt-8 text-slate-400 font-bold text-sm uppercase tracking-widest p-2">
                Cerrar
            </button>
          </div>
        </div>
      )}

      {/* MODAL REPORTE */}
      {viewingReportId && (
        <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-center p-0 sm:p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingReportId(null)}></div>
          <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 shadow-2xl relative z-20 animate-in slide-in-from-bottom-20 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold text-slate-800 mb-1">Estado de Aprendizaje</h2>
            <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest mb-4">Progreso de la aventura</p>
            {renderReportList()}
            <button onClick={() => setViewingReportId(null)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold active:scale-95 transition-transform">Volver</button>
          </div>
        </div>
      )}

      {/* TOAST NOTIFICATION */}
      {toast && (
          <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[300] px-6 py-3 rounded-full shadow-xl flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 ${toast.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-indigo-600 text-white'}`}>
              <span className="font-bold text-lg">{toast.type === 'success' ? '✓' : 'ℹ︎'}</span>
              <span className="font-bold text-sm">{toast.msg}</span>
          </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect, useRef } from 'react';
import { Word } from '../types';
import { speakWordPromise, stopAudio, triggerHaptic, generateVictoryGift } from '../geminiService';
import { getMeaning, getSynonyms, THEMES, loadLists, saveLists, PRACTICE_THEME } from '../store';

interface Props {
  listId: string;
  words: Word[];
  themeIndex: number;
  mode: 'normal' | 'repaso';
  onExit: () => void;
}

const GameScreen: React.FC<Props> = ({ listId, words, themeIndex, mode, onExit }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [slots, setSlots] = useState<(string | null)[]>([]);
  const [availableLetters, setAvailableLetters] = useState<{char: string, id: string}[]>([]);
  const [showRevelation, setShowRevelation] = useState(false);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [isAudioLocked, setIsAudioLocked] = useState(true);
  const [validationStatus, setValidationStatus] = useState<'none' | 'correct' | 'incorrect'>('none');
  const [feedbackSymbol, setFeedbackSymbol] = useState<'check' | 'alert' | 'none'>('none');
  const [showNextButton, setShowNextButton] = useState(false);
  const [attempts, setAttempts] = useState(0);
  const [sessionSuccesses, setSessionSuccesses] = useState(0);
  const [sessionChallenges, setSessionChallenges] = useState(0);

  // Estado para la Victoria Final del Mundo
  const [isWorldComplete, setIsWorldComplete] = useState(false);
  const [victoryImage, setVictoryImage] = useState<string | null>(null);
  const [loadingGift, setLoadingGift] = useState(false);

  // Estado visual de guardado
  const [showSavedIndicator, setShowSavedIndicator] = useState(false);

  const isMounted = useRef(true);
  const currentWord = words[currentIndex];
  // Unificamos la lógica del tema: siempre se usa el gradiente completo.
  const theme = mode === 'repaso' ? PRACTICE_THEME : (THEMES[themeIndex] || THEMES[0]);
  const wordLength = currentWord?.original.length || 1;

  const calculateSlotMetrics = () => {
    const screenWidth = typeof window !== 'undefined' ? window.innerWidth : 400;
    const padding = 48;
    const availableWidth = screenWidth - padding;
    const gap = wordLength > 8 ? 4 : 8;
    const maxSlotWidth = (availableWidth - (gap * (wordLength - 1))) / wordLength;
    const finalWidth = Math.min(80, Math.max(28, maxSlotWidth));
    const finalHeight = finalWidth * 1.3;
    const fontSize = finalWidth * 0.65;
    return { width: `${finalWidth}px`, height: `${finalHeight}px`, fontSize: `${fontSize}px`, gap: `${gap}px` };
  };

  const metrics = calculateSlotMetrics();

  useEffect(() => {
    isMounted.current = true;
    return () => { isMounted.current = false; stopAudio(); };
  }, []);

  const initWord = async () => {
    if (!currentWord) return;
    setIsAudioLocked(true); setShowRevelation(false);
    setValidationStatus('none'); setFeedbackSymbol('none'); setShowNextButton(false); setIsTransitioning(false); setAttempts(0);

    const chars = currentWord.original.split('').map(c => ({ char: c, id: Math.random().toString() }));
    let shuffled = [...chars].sort(() => Math.random() - 0.5);
    while(shuffled.map(s => s.char).join('') === currentWord.original && chars.length > 1) {
      shuffled = [...chars].sort(() => Math.random() - 0.5);
    }

    setSlots(new Array(currentWord.original.length).fill(null));
    await new Promise(resolve => setTimeout(resolve, 500));
    if (!isMounted.current) return;
    setAvailableLetters(shuffled);
    try { await speakWordPromise(currentWord.original, 'en-US', true); } catch (e) {}
    if (isMounted.current) { setIsAudioLocked(false); }
  };

  useEffect(() => { initWord(); }, [currentIndex, listId]);

  const handleLetterClick = async (letterObj: {char: string, id: string}, index: number) => {
    if (isAudioLocked || validationStatus === 'correct') return;
    const nextEmpty = slots.indexOf(null);
    if (nextEmpty !== -1) {
      triggerHaptic('click');
      setIsAudioLocked(true);
      const newSlots = [...slots]; newSlots[nextEmpty] = letterObj.char; setSlots(newSlots);
      const newAvailable = [...availableLetters]; newAvailable.splice(index, 1); setAvailableLetters(newAvailable);
      try { await speakWordPromise(letterObj.char, 'en-US', true); } catch(e) {}
      if (newSlots.indexOf(null) === -1) handleCompletion(newSlots); else setIsAudioLocked(false);
    }
  };

  const handleSlotClick = (index: number) => {
    if (isAudioLocked || validationStatus === 'correct' || slots[index] === null) return;
    triggerHaptic('click');
    const char = slots[index]!;
    const newSlots = [...slots]; newSlots[index] = null; setSlots(newSlots);
    setValidationStatus('none'); setFeedbackSymbol('none'); setAvailableLetters([...availableLetters, { char, id: Math.random().toString() }]);
  };

  const handleCompletion = async (currentSlots: (string | null)[]) => {
    const constructed = currentSlots.join('').toLowerCase();
    const isActuallyCorrect = constructed === currentWord.original.toLowerCase();
    setIsAudioLocked(true); 

    if (isActuallyCorrect) {
      triggerHaptic('success');
      setValidationStatus('correct');
      setFeedbackSymbol('check');
      setSessionSuccesses(prev => prev + 1);
      updatePersistentStats(attempts === 0 ? 0 : 1);
      await playSuccessSequence();
    } else {
      triggerHaptic('error');
      setFeedbackSymbol('alert');
      const newAttemptCount = attempts + 1;
      setAttempts(newAttemptCount);
      setValidationStatus('incorrect');
      setSessionChallenges(prev => prev + 1);

      await new Promise(resolve => setTimeout(resolve, 1200));
      if (!isMounted.current) return;

      if (newAttemptCount === 1) {
        setSlots(new Array(currentWord.original.length).fill(null));
        setAvailableLetters(currentSlots.map(s => ({ char: s!, id: Math.random().toString() })));
        setValidationStatus('none'); setFeedbackSymbol('none'); setIsAudioLocked(false);
      } else {
        updatePersistentStats(2);
        await playSuccessSequence();
      }
    }
  };

  const updatePersistentStats = (finalErrorLevel: number) => {
    const lists = loadLists();
    const list = lists.find(l => l.id === listId);
    if (list) {
      const word = list.words.find(w => w.original === currentWord.original);
      if (word) {
        word.errors = finalErrorLevel;
        if (finalErrorLevel === 0) word.successes = (word.successes || 0) + 1;
        word.completed = true;
        saveLists(lists);

        // Trigger Saved Indicator
        setShowSavedIndicator(true);
        setTimeout(() => setShowSavedIndicator(false), 2000);
      }
    }
  };

  const playSuccessSequence = async () => {
    await new Promise(resolve => setTimeout(resolve, 800));
    if (!isMounted.current) return;
    setFeedbackSymbol('none');
    setShowRevelation(true);
    try {
      await speakWordPromise(currentWord.original, 'en-US', true);
      await new Promise(resolve => setTimeout(resolve, 400));
      for (const char of currentWord.original.split('')) {
        if (!isMounted.current) return;
        await speakWordPromise(char, 'en-US', false);
      }
      await new Promise(resolve => setTimeout(resolve, 400));
      await speakWordPromise(currentWord.original, 'en-US', false);
    } catch(e) {}
    if (isMounted.current) { setShowNextButton(true); setIsAudioLocked(false); }
  };

  const checkWorldCompletion = async () => {
    const lists = loadLists();
    const list = lists.find(l => l.id === listId);
    if (list && list.words.every(w => w.completed && w.errors === 0)) {
      setIsWorldComplete(true);
      setLoadingGift(true);
      const gift = await generateVictoryGift(list.name);
      if (isMounted.current) {
        setVictoryImage(gift);
        setLoadingGift(false);
        triggerHaptic('success');
      }
    } else {
      onExit();
    }
  };

  const nextWord = () => {
    triggerHaptic('click');
    setIsTransitioning(true);
    setTimeout(() => {
      if (!isMounted.current) return;
      if (currentIndex < words.length - 1) {
        setCurrentIndex(prev => prev + 1);
      } else {
        checkWorldCompletion();
      }
    }, 500);
  };

  if (isWorldComplete) {
    return (
      <div className="fixed inset-0 z-[200] bg-slate-900 flex flex-col items-center justify-center p-8 animate-in fade-in duration-1000">
        <div className="absolute inset-0 bg-cover bg-center transition-opacity duration-1000" style={{ backgroundImage: victoryImage ? `url(${victoryImage})` : 'none', opacity: victoryImage ? 0.4 : 0 }}></div>
        <div className="relative z-10 text-center space-y-8 max-w-sm">
          <div className="w-24 h-24 bg-white/10 backdrop-blur-xl rounded-[2rem] border border-white/20 mx-auto flex items-center justify-center text-5xl shadow-2xl animate-levitate">🏆</div>
          <div className="space-y-2">
            <h1 className="text-4xl font-elegant font-bold text-white tracking-widest uppercase">¡MAESTRÍA TOTAL!</h1>
            <p className="text-indigo-200 font-semibold tracking-wide">Has completado este mundo sin errores.</p>
          </div>

          {loadingGift && (
            <div className="flex flex-col items-center gap-4 py-8">
              <div className="w-12 h-12 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
              <p className="text-white/40 text-xs font-bold uppercase tracking-widest">Generando tu Postal de Victoria...</p>
            </div>
          )}

          {victoryImage && (
            <div className="animate-in zoom-in-95 duration-700 bg-white/10 backdrop-blur-md p-2 rounded-[2.5rem] border border-white/10 shadow-2xl">
              <img src={victoryImage} alt="Victory Gift" className="w-full h-auto rounded-[2rem] shadow-inner" />
            </div>
          )}

          <button onClick={onExit} className="w-full bg-white text-slate-900 py-5 rounded-2xl font-bold text-lg shadow-xl active:scale-95 transition-all">
            Volver al Mapa
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className={`fixed inset-0 flex flex-col pt-[env(safe-area-inset-top)] pb-[env(safe-area-inset-bottom)] transition-all duration-500 overflow-hidden ${isTransitioning ? 'opacity-0 scale-95' : 'opacity-100 scale-100'}`}>

      {/* FONDO: Gradiente completo siempre, para coincidir con la lista seleccionada */}
      <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient}`}></div>
      {/* Capa de textura y oscurecimiento para garantizar que el texto blanco se lea */}
      <div className={`absolute inset-0 bg-black/10 mix-blend-overlay ${mode === 'repaso' ? "bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-30" : ""}`}></div>

      <button onClick={onExit} className="fixed top-4 right-4 z-[100] w-10 h-10 bg-white/10 text-white backdrop-blur-md rounded-full shadow-sm active:scale-90 flex items-center justify-center font-bold border border-white/10">✕</button>

      {/* INDICADOR DE GUARDADO AUTOMÁTICO */}
      {showSavedIndicator && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 z-[150] px-4 py-1.5 bg-emerald-500/90 backdrop-blur-md rounded-full border border-emerald-400/50 shadow-lg animate-in fade-in slide-in-from-top-2">
            <div className="flex items-center gap-2">
                <div className="w-2 h-2 bg-white rounded-full animate-pulse"></div>
                <span className="text-[10px] font-bold text-white uppercase tracking-widest">Progreso Guardado</span>
            </div>
        </div>
      )}

      <div className="fixed top-[calc(1rem+env(safe-area-inset-top))] left-4 z-[100] flex gap-3">
        <div className="flex items-center gap-2 px-3 py-1.5 bg-white/10 backdrop-blur-md rounded-full border border-white/20 shadow-sm">
          <span className="text-emerald-400 font-bold">✓</span>
          <span className="text-white font-bold text-sm min-w-[12px] text-center">{sessionSuccesses}</span>
        </div>
        <div className="flex items-center gap-2 px-3 py-1.5 bg-white/10 backdrop-blur-md rounded-full border border-white/20 shadow-sm">
          <span className="text-amber-400 font-bold">!</span>
          <span className="text-white font-bold text-sm min-w-[12px] text-center">{sessionChallenges}</span>
        </div>
      </div>

      <div className="flex flex-col items-center justify-between h-full w-full py-4 relative z-10 safe-padding-top safe-padding-bottom">
        <div className="flex flex-col items-center w-full px-6 flex-1 justify-center relative">
          <button disabled={isAudioLocked} onClick={() => !isAudioLocked && (triggerHaptic('click'), speakWordPromise(currentWord.original, 'en-US', true))}
            className={`transition-all duration-500 bg-white/20 backdrop-blur-xl rounded-full flex items-center justify-center shadow-xl border-4 border-white/30 
              ${showRevelation ? 'w-16 h-16 sm:w-20 sm:h-20 mb-4' : 'w-28 h-28 sm:w-36 sm:h-36 mb-6'}
              ${isAudioLocked ? 'opacity-40 scale-95' : 'active:scale-90 shadow-white/20 animate-glow-signal'}`}>
            <span className={`${showRevelation ? 'text-3xl' : 'text-6xl sm:text-7xl'} filter drop-shadow-md`}>🔊</span>
          </button>

          <div className={`${showRevelation ? 'min-h-[180px]' : 'min-h-[100px]'} flex items-center justify-center w-full transition-all duration-500`}>
            {showRevelation ? (
              <div className="animate-in fade-in zoom-in-95 duration-700 w-full px-4 text-center">
                <h2 className={`text-white font-elegant font-bold uppercase tracking-[0.15em] mb-2 drop-shadow-lg ${wordLength > 10 ? 'text-2xl' : 'text-4xl sm:text-6xl'}`}>
                  {currentWord.original}
                </h2>
                <div className="bg-white/10 backdrop-blur-xl rounded-[2.5rem] p-5 sm:p-6 border border-white/20 shadow-2xl max-w-sm mx-auto animate-levitate text-white">
                  <p className="text-xl sm:text-2xl font-bold leading-tight mb-2 drop-shadow-sm">{getMeaning(currentWord.original)}</p>
                  {getSynonyms(currentWord.original) && (
                    <p className="text-sm text-white/70 font-semibold flex items-center justify-center gap-2">
                      <span className="opacity-40">🔗</span> {getSynonyms(currentWord.original)}
                    </p>
                  )}
                </div>
              </div>
            ) : validationStatus === 'incorrect' && feedbackSymbol === 'none' && (
              <div className="animate-in fade-in slide-in-from-bottom-4 px-8 py-3 bg-rose-500/80 backdrop-blur-md rounded-full border border-rose-400/50 text-white font-bold text-lg shadow-lg">
                ¡Escucha con atención!
              </div>
            )}
          </div>
        </div>

        <div className="w-full px-6 mb-6 flex justify-center pt-6">
          <div className="flex flex-nowrap justify-center w-full max-w-full items-center relative" style={{ gap: metrics.gap }}>
            {slots.map((char, i) => (
              <div key={i} onClick={() => handleSlotClick(i)}
                style={{ width: metrics.width, height: metrics.height, fontSize: metrics.fontSize }}
                className={`flex-shrink-0 rounded-xl sm:rounded-2xl border-2 flex items-center justify-center font-bold transition-all duration-300 relative shadow-lg backdrop-blur-md
                  ${char ? (validationStatus === 'incorrect' ? 'bg-rose-500 text-white border-rose-400' : validationStatus === 'correct' ? 'bg-emerald-500 text-white border-emerald-400' : 'bg-white/20 border-white/40 text-white') : 'bg-black/10 border-dashed border-white/20'}`}>
                <span className="drop-shadow-sm">{char?.toUpperCase()}</span>
              </div>
            ))}
          </div>
        </div>

        <div className={`w-full px-6 pb-12 flex flex-wrap gap-2.5 sm:gap-4 justify-center content-center min-h-[160px] transition-opacity duration-300 ${isAudioLocked && !showNextButton ? 'opacity-40' : 'opacity-100'}`}>
          {!showRevelation && availableLetters.map((letterObj, i) => (
            <button key={letterObj.id} onClick={() => handleLetterClick(letterObj, i)}
                className={`w-14 h-14 sm:w-20 sm:h-20 bg-white/95 text-slate-800 border-b-[6px] border-slate-200 rounded-2xl shadow-xl flex items-center justify-center text-3xl sm:text-4xl font-bold active:border-b-0 active:translate-y-1 animate-in zoom-in-95`}>
              {letterObj.char.toUpperCase()}
            </button>
          ))}
        </div>
      </div>

      {showNextButton && (
        <button onClick={nextWord} className="fixed bottom-8 right-8 z-[110] w-20 h-20 bg-white text-indigo-600 rounded-full shadow-2xl flex items-center justify-center animate-in slide-in-from-right-20 active:scale-90 border-4 border-indigo-100">
          <svg width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="4" strokeLinecap="round" strokeLinejoin="round">
            <line x1="5" y1="12" x2="19" y2="12"></line>
            <polyline points="12 5 19 12 12 19"></polyline>
          </svg>
        </button>
      )}
    </div>
  );
};

export default GameScreen;

import React, { useState, useEffect, useRef } from 'react';
import { WordList, VoiceSettings, Word } from '../types';
import { loadLists, saveLists, extractWords, loadVoiceSettings, saveVoiceSettings, getMeaning, THEMES, resetListProgress, PRACTICE_THEME, getBackupData, restoreBackupData, initPersistence, isSystemClean } from '../store';
import { getCategorizedVoices, isPremiumVoice, speakWordPromise } from '../geminiService';

interface Props {
  onStartGame: (listId: string, mode: 'normal' | 'repaso') => void;
  role: 'parent' | 'child';
  onModalStateChange: (isOpen: boolean) => void;
}

const ParentDashboard: React.FC<Props> = ({ onStartGame, role, onModalStateChange }) => {
  const [lists, setLists] = useState<WordList[]>([]);
  const [newListName, setNewListName] = useState('');
  const [inputText, setInputText] = useState('');
  const [selectedTheme, setSelectedTheme] = useState(0);
  const [isAdding, setIsAdding] = useState(false);
  const [editingListId, setEditingListId] = useState<string | null>(null);
  const [viewingReportId, setViewingReportId] = useState<string | null>(null);

  const [isVoiceStudioOpen, setIsVoiceStudioOpen] = useState(false);
  const [voiceSettings, setVoiceSettings] = useState<VoiceSettings>(loadVoiceSettings());
  const [categorizedVoices, setCategorizedVoices] = useState<{elite: SpeechSynthesisVoice[], backup: SpeechSynthesisVoice[]}>({elite: [], backup: []});

  // Estado para Configuración / Backup
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [showRecoveryAlert, setShowRecoveryAlert] = useState(false);

  // Estado para Toasts (Notificaciones)
  const [toast, setToast] = useState<{msg: string, type: 'success' | 'info'} | null>(null);

  useEffect(() => {
    // 1. Pedir al navegador que no borre datos
    initPersistence();

    // 2. Cargar datos iniciales
    setLists(loadLists());

    // 3. Detectar si estamos en "Amensia" (fábrica) para mostrar alerta
    if (isSystemClean()) {
        setShowRecoveryAlert(true);
    }

    const loadVoices = () => setCategorizedVoices(getCategorizedVoices());
    loadVoices();
    if (typeof window !== 'undefined' && window.speechSynthesis) {
      window.speechSynthesis.onvoiceschanged = loadVoices;
    }
  }, []);

  // Notificar a App.tsx si algún modal está abierto
  useEffect(() => {
    const isAnyModalOpen = isAdding || !!viewingReportId || isVoiceStudioOpen || isSettingsOpen;
    onModalStateChange(isAnyModalOpen);
  }, [isAdding, viewingReportId, isVoiceStudioOpen, isSettingsOpen, onModalStateChange]);

  const showToast = (msg: string, type: 'success' | 'info' = 'success') => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  const handleSaveList = () => {
    if (!newListName || !inputText) return;
    const updatedLists = editingListId 
      ? lists.map(l => l.id === editingListId ? { ...l, name: newListName, themeIndex: selectedTheme, words: mergeWords(l.words, extractWords(inputText)) } : l)
      : [...lists, { id: Math.random().toString(36).substr(2, 9), name: newListName, themeIndex: selectedTheme, words: extractWords(inputText), settings: { rainEnabled: true }, lastPlayed: Date.now() }];

    setLists(updatedLists);
    saveLists(updatedLists);
    resetForm();
    setShowRecoveryAlert(false); // Si crea una lista nueva, ya no mostramos alerta
    showToast(editingListId ? "Mundo actualizado" : "Aventura creada");
  };

  const handleResetProgress = (id: string) => {
    if (window.confirm("¿Seguro que quieres reiniciar todo el progreso de este mundo?")) {
      const updated = resetListProgress(id);
      setLists(updated);
      showToast("Progreso reiniciado");
    }
  };

  // --- LOGICA DE BACKUP ---
  const handleExportBackup = () => {
    const data = getBackupData();
    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const a = document.createElement('a');
    a.href = url;
    a.download = `echofy_respaldo_${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
    showToast("Copia descargada", "info");
  };

  const handleImportClick = () => {
    if (fileInputRef.current) fileInputRef.current.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      const content = event.target?.result as string;
      if (restoreBackupData(content)) {
        setLists(loadLists());
        setVoiceSettings(loadVoiceSettings());
        showToast("Datos restaurados correctamente");
        setIsSettingsOpen(false);
        setShowRecoveryAlert(false); // Ocultar alerta si se restauró con éxito
      } else {
        alert("El archivo no es válido o está dañado.");
      }
    };
    reader.readAsText(file);
    // Limpiar input para permitir seleccionar el mismo archivo de nuevo si falla
    e.target.value = ''; 
  };
  // -------------------------

  const mergeWords = (oldWords: Word[], newWords: Word[]): Word[] => {
    return newWords.map(nw => {
      const match = oldWords.find(ow => ow.original === nw.original);
      return match ? match : nw;
    });
  };

  const resetForm = () => {
    setNewListName(''); setInputText(''); setEditingListId(null); setIsAdding(false); setSelectedTheme(0);
  };

  const openNewListModal = () => {
    setNewListName(''); 
    setInputText(''); 
    setEditingListId(null); 
    setSelectedTheme(0);
    setIsAdding(true);
  };

  const currentVoice = [...categorizedVoices.elite, ...categorizedVoices.backup].find(v => v.voiceURI === voiceSettings.voiceURI);

  const getVoiceDisplayName = () => {
    if (!currentVoice) return "Automática";
    return currentVoice.name.replace(/Microsoft|Google|English|United States|Android|Speech|Engine|en-US|\(.*\)/gi, '').trim();
  };

  const handleVoiceSelect = (voice: SpeechSynthesisVoice) => {
      const s = {...voiceSettings, voiceURI: voice.voiceURI}; 
      setVoiceSettings(s); 
      saveVoiceSettings(s); 
      speakWordPromise("Voice updated", 'en-US', true);
  };

  const triggerVoiceFeedback = (type: 'rate' | 'pitch') => {
    const text = type === 'rate' ? "Testing speed" : "Testing tone";
    speakWordPromise(text, 'en-US', true);
  };

  const renderParentView = () => (
    <div className="animate-in fade-in duration-700 space-y-4">
      {/* BANNER DE RECUPERACIÓN (Solo si está limpio el sistema) */}
      {showRecoveryAlert && (
          <div className="bg-amber-50 border-l-4 border-amber-400 p-4 mb-6 rounded-r-2xl flex justify-between items-center shadow-sm animate-in fade-in slide-in-from-top-4">
              <div className="pr-4">
                  <p className="font-bold text-amber-800 text-sm mb-0.5">¿No ves tus listas?</p>
                  <p className="text-[11px] text-amber-600 leading-tight">Si tenías una copia guardada, restáurala aquí.</p>
              </div>
              <button onClick={handleImportClick} className="bg-white text-amber-600 px-4 py-2 rounded-xl text-xs font-bold shadow-sm border border-amber-100 active:scale-95 transition-transform whitespace-nowrap">
                  Restaurar
              </button>
          </div>
      )}

      <button onClick={openNewListModal} className="w-full p-6 border-2 border-dashed border-slate-200 rounded-[2.5rem] text-slate-400 mb-8 active:scale-98 transition-all font-bold group hover:border-indigo-200 hover:bg-indigo-50/50">
        <span className="group-hover:text-indigo-400 transition-colors">+ Nueva Aventura</span>
      </button>

      {lists.map(list => (
        <div key={list.id} className="relative group mb-4">
          <div onClick={() => { setEditingListId(list.id); setIsAdding(true); setNewListName(list.name); setSelectedTheme(list.themeIndex); setInputText(list.words.map(w => w.original).join(' ')); }} 
                className="bg-white p-5 pr-20 rounded-[2.5rem] shadow-sm border border-slate-50 flex items-center justify-between active:scale-[0.98] transition-all cursor-pointer">
            <div className="flex items-center gap-4">
              <div className={`w-14 h-14 rounded-3xl bg-gradient-to-br ${THEMES[list.themeIndex]?.gradient || THEMES[0].gradient} flex items-center justify-center text-2xl shadow-inner group-hover:scale-105 transition-transform text-white shadow-black/10`}>📝</div>
              <div>
                <h3 className="text-xl font-bold text-slate-800 leading-tight">{list.name}</h3>
                <span className="text-[10px] text-slate-300 font-bold uppercase tracking-widest">{list.words.length} PALABRAS</span>
              </div>
            </div>
          </div>
          <button onClick={(e) => { e.stopPropagation(); setViewingReportId(list.id); }}
            className="absolute right-4 top-1/2 -translate-y-1/2 w-12 h-12 bg-indigo-50 text-indigo-500 rounded-2xl flex items-center justify-center shadow-sm active:scale-90 transition-all hover:bg-indigo-100">
            📈
          </button>
        </div>
      ))}

      {isAdding && (
        <div className="fixed inset-0 z-[200] bg-slate-900/60 backdrop-blur-md flex items-end sm:items-center justify-center">
          <div className="w-full h-[95vh] sm:h-auto sm:max-h-[85vh] bg-[#fdfdfe] rounded-t-[2.5rem] sm:rounded-[3rem] shadow-2xl overflow-y-auto flex flex-col animate-in slide-in-from-bottom-20 duration-500">
            <div className="p-6 sticky top-0 bg-[#fdfdfe]/90 backdrop-blur-md z-10 border-b border-slate-50 flex justify-between items-center">
              <h2 className="text-2xl font-elegant font-bold text-slate-800">{editingListId ? 'Editar Mundo' : 'Nuevo Mundo'}</h2>
              <button onClick={resetForm} className="w-10 h-10 rounded-full bg-slate-100 text-slate-400 font-bold flex items-center justify-center active:scale-90 hover:bg-slate-200 transition-colors">✕</button>
            </div>

            <div className="p-6 space-y-8 pb-32">
              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Nombre de la Aventura</label>
                <input className="w-full p-5 rounded-2xl bg-slate-50 border border-slate-100 text-xl font-bold placeholder:font-normal placeholder:text-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-100 transition-all" 
                       placeholder="Ej: Animales del Bosque" value={newListName} onChange={e => setNewListName(e.target.value)} />
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Elige el Ambiente</label>
                <div className="grid grid-cols-3 gap-3">
                  {THEMES.map(theme => (
                    <button key={theme.id} onClick={() => setSelectedTheme(theme.id)} 
                            className={`h-16 rounded-2xl bg-gradient-to-br ${theme.gradient} border-4 transition-all shadow-sm ${selectedTheme === theme.id ? 'border-slate-800 scale-105 shadow-xl ring-2 ring-offset-2 ring-slate-200' : 'border-transparent opacity-70 hover:opacity-100'}`}>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-3">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-widest px-2">Palabras (Separadas por espacio)</label>
                <textarea className="w-full p-5 h-48 rounded-2xl bg-slate-50 border border-slate-100 text-lg leading-relaxed placeholder:font-normal placeholder:text-slate-300 focus:outline-none focus:ring-4 focus:ring-indigo-100 transition-all font-medium text-slate-600" 
                          placeholder="gato perro sol luna..." value={inputText} onChange={e => setInputText(e.target.value)} />
              </div>

              <button onClick={handleSaveList} className="w-full bg-slate-900 text-white p-5 rounded-2xl font-bold text-lg active:scale-95 transition-all shadow-xl shadow-slate-200 hover:shadow-2xl">
                {editingListId ? 'Guardar Cambios' : 'Crear Aventura'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  const renderChildView = () => {
    // Buscar si hay alguna palabra en alguna lista que tenga errores (Modo Práctica disponible)
    const listsWithErrors = lists.filter(l => l.words.some(w => (w.errors || 0) > 0));
    const totalErrors = listsWithErrors.reduce((acc, l) => acc + l.words.filter(w => (w.errors || 0) > 0).length, 0);

    return (
      <div className="animate-in fade-in duration-700 space-y-6">
        {/* ISLA DE PRÁCTICA - Solo visible si hay deudas de aprendizaje */}
        {totalErrors > 0 && (
          <div onClick={() => onStartGame(listsWithErrors[0].id, 'repaso')}
            className="w-full p-6 rounded-[3rem] bg-gradient-to-br from-indigo-900 via-purple-900 to-slate-900 shadow-2xl relative overflow-hidden group active:scale-95 transition-all mb-8 cursor-pointer border border-white/10">
            <div className="absolute inset-0 bg-[url('https://www.transparenttextures.com/patterns/stardust.png')] opacity-20"></div>
            <div className="relative z-10 flex items-center justify-between">
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 bg-white/10 backdrop-blur-xl rounded-3xl flex items-center justify-center text-3xl shadow-lg border border-white/10 animate-levitate">✨</div>
                <div>
                  <h2 className="text-2xl font-bold text-white tracking-tight">Isla de Práctica</h2>
                  <p className="text-indigo-200 text-sm font-semibold">{totalErrors} palabras por rescatar</p>
                </div>
              </div>
              <div className="w-12 h-12 rounded-full bg-indigo-500/30 flex items-center justify-center text-white font-bold animate-pulse border border-white/10">
                ➜
              </div>
            </div>
          </div>
        )}

        <div className="grid grid-cols-2 gap-4">
          {lists.map((list) => {
            const progress = (list.words.filter(w => w.completed && (w.errors || 0) === 0).length / list.words.length) * 100;
            const theme = THEMES[list.themeIndex] || THEMES[0];
            return (
              <div key={list.id} onClick={() => onStartGame(list.id, 'normal')}
                   className="relative aspect-[4/5] p-5 rounded-[2.5rem] shadow-xl transition-all active:scale-[0.93] group overflow-hidden">
                <div className={`absolute inset-0 bg-gradient-to-br ${theme.gradient} transition-transform group-hover:scale-110`}></div>
                <div className="absolute inset-0 bg-black/5 mix-blend-overlay"></div>
                <div className="relative h-full flex flex-col justify-between z-10">
                  <div className="w-12 h-12 bg-white/20 backdrop-blur-md rounded-2xl flex items-center justify-center text-2xl animate-levitate shadow-lg border border-white/10">
                    <span className="drop-shadow-sm">🌎</span>
                  </div>
                  <div>
                    <h3 className="text-white font-bold text-lg leading-tight mb-2 drop-shadow-md">{list.name}</h3>
                    <div className="w-full h-1.5 bg-black/20 rounded-full overflow-hidden backdrop-blur-sm">
                      <div className="h-full bg-white/90 shadow-[0_0_10px_rgba(255,255,255,0.5)] transition-all duration-1000" style={{ width: `${Math.max(5, progress)}%` }}></div>
                    </div>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  const renderReportList = () => {
    const list = lists.find(l => l.id === viewingReportId);
    if (!list) return null;

    const criticas = list.words.filter(w => w.completed && (w.errors || 0) >= 2);
    const enProceso = list.words.filter(w => w.completed && (w.errors || 0) === 1);
    const dominadas = list.words.filter(w => w.completed && (w.errors || 0) === 0);
    const noVistas = list.words.filter(w => !w.completed);

    const WordItem: React.FC<{ 
        word: Word, 
        type: 'critical' | 'process' | 'mastered' 
    }> = ({ word, type }) => {
        let config = {
            symbol: '✓',
            colorClass: 'text-emerald-500',
            bgClass: 'bg-emerald-50/50',
            borderClass: 'border-emerald-100/50'
        };

        if (type === 'critical') {
            config = {
                symbol: '!',
                colorClass: 'text-rose-500',
                bgClass: 'bg-rose-50/50',
                borderClass: 'border-rose-100/50'
            };
        } else if (type === 'process') {
            config = {
                symbol: '?',
                colorClass: 'text-amber-500',
                bgClass: 'bg-amber-50/50',
                borderClass: 'border-amber-100/50'
            };
        }

        return (
            <div className={`p-4 rounded-2xl flex justify-between items-center border ${config.bgClass} ${config.borderClass}`}>
                <span className="font-bold text-slate-700 capitalize">{word.original}</span>
                <div className="flex items-center gap-3">
                    <div className="flex flex-col items-end">
                        <span className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Intentos</span>
                        <span className="text-xs font-bold text-slate-500">{(word.successes || 0) + (word.errors || 0)}</span>
                    </div>
                    <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold text-lg bg-white shadow-sm ${config.colorClass}`}>
                        {config.symbol}
                    </div>
                </div>
            </div>
        );
    };

    const SectionHeader: React.FC<{ title: string, count: number, subtitle?: string }> = ({ title, count, subtitle }) => (
      <div className="mt-8 mb-3 px-1">
        <div className="flex items-center justify-between">
            <h3 className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">{title}</h3>
            <span className="bg-slate-100 text-slate-400 text-[9px] font-bold px-2 py-0.5 rounded-full">{count}</span>
        </div>
        {subtitle && <p className="text-[9px] text-slate-300 italic mt-0.5">{subtitle}</p>}
      </div>
    );

    return (
      <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 mb-6">
        {criticas.length > 0 && (
          <div className="animate-in fade-in">
            <SectionHeader title="Retos Críticos" count={criticas.length} subtitle="Alerta, situación por resolver" />
            <div className="space-y-2">
              {criticas.map(w => <WordItem key={w.id} word={w} type="critical" />)}
            </div>
          </div>
        )}

        {enProceso.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-2">
            <SectionHeader title="En Proceso" count={enProceso.length} subtitle="Qué paso ahí? Después lo hiciste bien" />
            <div className="space-y-2">
              {enProceso.map(w => <WordItem key={w.id} word={w} type="process" />)}
            </div>
          </div>
        )}

        {dominadas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-3">
            <SectionHeader title="Dominadas" count={dominadas.length} subtitle="Confianza total" />
            <div className="space-y-2">
              {dominadas.map(w => <WordItem key={w.id} word={w} type="mastered" />)}
            </div>
          </div>
        )}

        {noVistas.length > 0 && (
          <div className="animate-in fade-in slide-in-from-bottom-4">
            <SectionHeader title="Por Descubrir" count={noVistas.length} />
            <div className="space-y-2">
              {noVistas.map(w => (
                <div key={w.id} className="p-4 bg-white rounded-2xl border border-dashed border-slate-100 flex justify-between items-center opacity-40">
                  <span className="font-semibold text-slate-400 capitalize">{w.original}</span>
                  <span className="text-[10px] font-bold text-slate-200">NUEVA</span>
                </div>
              ))}
            </div>
          </div>
        )}

        <div className="mt-12 mb-6 px-1">
           <button onClick={() => handleResetProgress(viewingReportId!)} 
             className="w-full py-4 rounded-2xl border-2 border-dashed border-slate-200 text-slate-400 font-bold text-xs uppercase tracking-widest hover:bg-slate-50 active:scale-95 transition-all">
             Reiniciar Todo el Progreso
           </button>
        </div>
      </div>
    );
  };

  return (
    <div className="w-full max-w-md mx-auto p-4 md:p-6 pb-48">
      {/* HEADER CON BOTÓN DE AJUSTES */}
      <header className="flex items-center justify-between mb-10 mt-6 relative">
        <div className="w-10"></div> {/* Spacer */}
        <div className="flex flex-col items-center">
            <h1 className="text-3xl sm:text-4xl font-elegant tracking-[0.3em] font-light text-slate-800 mb-1 text-center">ECHOFY</h1>
            <div className="h-1 w-12 bg-slate-200 rounded-full"></div>
        </div>
        {role === 'parent' ? (
             <button onClick={() => setIsSettingsOpen(true)} className="w-10 h-10 rounded-full bg-slate-50 text-slate-400 flex items-center justify-center active:bg-slate-200 transition-colors">
                ⚙️
             </button>
        ) : <div className="w-10"></div>}
      </header>

      {/* INPUT FILE GLOBAL Y OCULTO - Accesible por Settings y por Banner de Recuperación */}
      <input 
          type="file" 
          accept=".json" 
          ref={fileInputRef}
          onChange={handleFileChange}
          className="hidden" 
      />

      {role === 'parent' && (
          <div className="mb-8">
            <button onClick={() => setIsVoiceStudioOpen(true)} className="w-full flex items-center justify-between px-4 py-3 bg-white rounded-2xl shadow-sm border border-slate-100 text-slate-500 active:scale-95 transition-all">
                <div className="flex items-center gap-3">
                <span className="text-lg">🔊</span>
                <div className="flex flex-col items-start min-w-0">
                    <span className="text-[10px] uppercase font-bold tracking-widest text-slate-300 text-left">Voz actual</span>
                    <span className="text-sm font-semibold font-elegant truncate max-w-[180px]">{getVoiceDisplayName()}</span>
                </div>
                </div>
            </button>
          </div>
      )}


      {role === 'child' ? renderChildView() : renderParentView()}

      {/* MODAL ESTUDIO DE VOZ */}
      {isVoiceStudioOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/20 backdrop-blur-sm" onClick={() => setIsVoiceStudioOpen(false)}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-6 shadow-2xl relative z-20 animate-in zoom-in-95 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold mb-6">Estudio de Voz</h2>
            <div className="flex-1 overflow-y-auto space-y-6 custom-scrollbar pr-1">
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Ritmo</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.rate} 
                       onChange={e => { const s={...voiceSettings, rate:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('rate')} onTouchEnd={() => triggerVoiceFeedback('rate')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-indigo-600" />
              </div>
              <div className="space-y-4">
                <label className="text-sm font-bold text-slate-600">Tono</label>
                <input type="range" min="0.5" max="1.5" step="0.1" value={voiceSettings.pitch} 
                       onChange={e => { const s={...voiceSettings, pitch:parseFloat(e.target.value)}; setVoiceSettings(s); saveVoiceSettings(s); }}
                       onMouseUp={() => triggerVoiceFeedback('pitch')} onTouchEnd={() => triggerVoiceFeedback('pitch')}
                       className="w-full h-2 bg-slate-100 rounded-full appearance-none accent-fuchsia-600" />
              </div>
              <div className="space-y-2">
                <p className="text-[10px] font-bold text-slate-300 uppercase tracking-widest">Voces en el dispositivo</p>
                {categorizedVoices.elite.concat(categorizedVoices.backup).map(v => (
                  <button key={v.voiceURI} onClick={() => handleVoiceSelect(v)} 
                          className={`w-full p-4 rounded-xl text-left border-2 transition-all ${voiceSettings.voiceURI === v.voiceURI ? 'bg-indigo-600 border-indigo-600 text-white' : 'bg-slate-50 border-transparent text-slate-600'}`}>
                    <span className="font-bold text-sm">{v.name.replace(/Google|Microsoft|English|en-US/gi, '').trim()}</span>
                  </button>
                ))}
              </div>
            </div>
            <button onClick={() => setIsVoiceStudioOpen(false)} className="mt-6 w-full bg-slate-900 text-white py-4 rounded-2xl font-bold">Cerrar</button>
          </div>
        </div>
      )}

      {/* MODAL CONFIGURACIÓN / RESPALDO */}
      {isSettingsOpen && (
        <div className="fixed inset-0 z-[200] flex items-center justify-center p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setIsSettingsOpen(false)}></div>
          <div className="bg-white w-full max-w-sm rounded-[2.5rem] p-8 shadow-2xl relative z-20 animate-in zoom-in-95 flex flex-col items-center text-center">
            <div className="w-16 h-16 bg-slate-100 rounded-3xl flex items-center justify-center text-3xl mb-4">🛡️</div>
            <h2 className="text-2xl font-elegant font-bold text-slate-800 mb-2">Seguridad de Datos</h2>
            <p className="text-sm text-slate-400 font-medium mb-8 leading-relaxed">
               Guarda una copia de seguridad para no perder el progreso de tu hija si cambias de dispositivo.
            </p>

            <div className="w-full space-y-4">
                <button onClick={handleExportBackup} className="w-full py-4 bg-indigo-50 text-indigo-600 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all border border-indigo-100">
                    <span>💾</span> Guardar Copia de Seguridad
                </button>

                <div className="relative">
                    {/* El input file está ahora fuera de este modal, pero el botón lo llama igual */}
                    <button onClick={handleImportClick} className="w-full py-4 bg-white text-slate-500 rounded-2xl font-bold flex items-center justify-center gap-3 active:scale-95 transition-all border-2 border-dashed border-slate-200 hover:border-slate-300">
                        <span>📂</span> Restaurar Datos
                    </button>
                </div>
            </div>

            <button onClick={() => setIsSettingsOpen(false)} className="mt-8 text-slate-400 font-bold text-sm uppercase tracking-widest p-2">
                Cerrar
            </button>
          </div>
        </div>
      )}

      {/* MODAL REPORTE */}
      {viewingReportId && (
        <div className="fixed inset-0 z-[150] flex items-end sm:items-center justify-center p-0 sm:p-6">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingReportId(null)}></div>
          <div className="bg-white w-full max-w-lg rounded-t-[3rem] sm:rounded-[3rem] p-8 shadow-2xl relative z-20 animate-in slide-in-from-bottom-20 max-h-[85vh] flex flex-col">
            <h2 className="text-2xl font-elegant font-bold text-slate-800 mb-1">Estado de Aprendizaje</h2>
            <p className="text-[10px] text-slate-300 font-bold uppercase tracking-widest mb-4">Progreso de la aventura</p>
            {renderReportList()}
            <button onClick={() => setViewingReportId(null)} className="w-full bg-slate-900 text-white py-5 rounded-2xl font-bold active:scale-95 transition-transform">Volver</button>
          </div>
        </div>
      )}

      {/* TOAST NOTIFICATION */}
      {toast && (
          <div className={`fixed bottom-24 left-1/2 -translate-x-1/2 z-[300] px-6 py-3 rounded-full shadow-xl flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4 ${toast.type === 'success' ? 'bg-emerald-500 text-white' : 'bg-indigo-600 text-white'}`}>
              <span className="font-bold text-lg">{toast.type === 'success' ? '✓' : 'ℹ︎'}</span>
              <span className="font-bold text-sm">{toast.msg}</span>
          </div>
      )}
    </div>
  );
};

export default ParentDashboard;

import React, { useState, useEffect } from 'react';
import ParentDashboard from './components/ParentDashboard';
import GameScreen from './components/GameScreen';
import { loadLists, prepareSession } from './store';
import { Word, GameSession } from './types';
import { triggerHaptic } from './geminiService';

const App: React.FC = () => {
  const [role, setRole] = useState<'parent' | 'child'>('parent');
  const [activeSession, setActiveSession] = useState<GameSession | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);

  useEffect(() => {
    // Configuración para que se sienta como App Nativa
    document.body.style.overflow = 'hidden';
    document.body.style.position = 'fixed';
    document.body.style.width = '100%';
    document.body.style.height = '100%';
    document.body.style.overscrollBehaviorY = 'none';

    const handleContextMenu = (e: MouseEvent) => e.preventDefault();
    document.addEventListener('contextmenu', handleContextMenu);

    // Bloquear pinch-zoom
    const handleTouchStart = (e: TouchEvent) => {
      if (e.touches.length > 1) e.preventDefault();
    };
    document.addEventListener('touchstart', handleTouchStart, { passive: false });

    return () => { 
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('touchstart', handleTouchStart);
    };
  }, []);

  const handleStartGame = (listId: string, mode: 'normal' | 'repaso') => {
    const list = loadLists().find(l => l.id === listId);
    if (list) {
      triggerHaptic('success');
      setActiveSession({
        listId,
        words: prepareSession(list, mode),
        mode
      });
      setRole('child');
    }
  };

  const toggleRole = () => {
    triggerHaptic('click');
    setRole(role === 'parent' ? 'child' : 'parent');
  };

  const activeList = activeSession ? loadLists().find(l => l.id === activeSession.listId) : null;

  if (role === 'child' && activeSession && activeList) {
    return (
      <GameScreen 
        listId={activeSession.listId}
        words={activeSession.words}
        themeIndex={activeList.themeIndex}
        mode={activeSession.mode}
        onExit={() => { setActiveSession(null); setRole('child'); }} 
      />
    );
  }

  return (
    <div className="h-[100dvh] w-full bg-[#fdfdfe] text-slate-900 font-sans overflow-y-auto overflow-x-hidden safe-padding-top overscroll-y-contain scroll-smooth">
      <ParentDashboard 
        role={role} 
        onStartGame={handleStartGame} 
        onModalStateChange={setIsModalOpen}
      />

      {!isModalOpen && (
        <div className="fixed bottom-[calc(2.5rem+env(safe-area-inset-bottom))] left-1/2 -translate-x-1/2 z-[100] flex items-center gap-5 bg-white/80 backdrop-blur-xl px-6 py-3 rounded-full shadow-lg border border-slate-100 animate-in fade-in slide-in-from-bottom-4">
          <span className={`text-[10px] font-bold tracking-[0.2em] transition-colors ${role === 'parent' ? 'text-slate-900' : 'text-slate-300'}`}>PADRE</span>
          <button onClick={toggleRole}
            className={`w-12 h-6 rounded-full relative transition-colors duration-300 ${role === 'child' ? 'bg-emerald-500' : 'bg-slate-300'}`}>
            <div className={`absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow-md transform transition-transform duration-300 ${role === 'child' ? 'translate-x-6' : 'translate-x-0'}`} />
          </button>
          <span className={`text-[10px] font-bold tracking-[0.2em] transition-colors ${role === 'child' ? 'text-emerald-600' : 'text-slate-300'}`}>NIÑO</span>
        </div>
      )}
    </div>
  );
};

